import { useState, useEffect, useRef } from "react";
import { Plus, Trash2, Edit2, Shield, X, Camera } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { AnalistaService } from "@/entities/Analista";
import type { Analista, AccessLevel } from "@/entities/Analista";
import { LabService } from "@/entities/Lab";
import type { Lab } from "@/entities/Lab";
import { Dialog, DialogContent } from "@/components/ui/dialog";
import { useAuth } from "@/contexts/AuthContext";


export default function AnalystsTab() {
    const { user: currentUser, refreshUser, currentLab } = useAuth();
    const [analistas, setAnalistas] = useState<Analista[]>([]);
    const [labs, setLabs] = useState<Lab[]>([]);
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [editingAnalista, setEditingAnalista] = useState<Analista | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Form
    const [nome, setNome] = useState("");
    const [email, setEmail] = useState("");
    const [senha, setSenha] = useState("");
    const [cargo, setCargo] = useState("");
    const [acesso, setAcesso] = useState<AccessLevel>("user");
    const [labId, setLabId] = useState("");
    const [foto, setFoto] = useState<string | undefined>(undefined);

    useEffect(() => {
        loadData();
    }, [currentUser, currentLab]);

    const loadData = async () => {
        // Prepare promises
        const promises: Promise<any>[] = [LabService.list()];

        // Check scope
        const isGlobalAdmin = currentUser?.acesso === 'admin_global';
        const targetLabId = currentLab?.id || (currentUser?.acesso === 'admin_lab' ? currentUser.lab_id : null);

        // Global admin sees EVERYTHING, lab admin sees only their lab
        if (targetLabId && !isGlobalAdmin) {
            promises.push(AnalistaService.listByLab(targetLabId));
        } else {
            promises.push(AnalistaService.list());
        }

        const [lData, aData] = await Promise.all(promises);
        setLabs(lData);
        setAnalistas(aData);
    };

    const handleOpenDialog = (a?: Analista) => {
        // Default labId for new analyst
        const defaultLabId = currentLab?.id || (currentUser?.acesso === 'admin_lab' ? (currentUser.lab_id || "") : "") || "";

        if (a) {
            setEditingAnalista(a);
            setNome(a.nome);
            setEmail(a.email);
            setSenha(""); // Limpa campo de senha na edi├º├úo por seguran├ºa
            setCargo(a.cargo);
            setAcesso(a.acesso);
            setLabId(a.lab_id || "");
            setFoto(a.foto || undefined);
        } else {
            setEditingAnalista(null);
            setNome("");
            setEmail("");
            setSenha("");
            setCargo("");
            setAcesso("user");
            setLabId(defaultLabId);
            setFoto(undefined);
        }
        setIsDialogOpen(true);
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = () => {
                setFoto(reader.result as string);
            };
            reader.readAsDataURL(file);
        }
    };

    const handleSave = async () => {
        // Validate required fields
        if (!nome || !email || (!editingAnalista && !senha) || !cargo) {
            alert("Por favor, preencha todos os campos obrigat├│rios.");
            return;
        }

        // If not global admin, labId validation logic might vary, but usually required unless admin_global creating global admin
        // But here we enforce labId if we are in a lab context
        if (!labId && acesso !== 'admin_global') {
            alert("V├¡nculo com laborat├│rio ├® obrigat├│rio para este n├¡vel de acesso.");
            return;
        }

        try {
            let senhaAEnviar = senha;

            // Se uma senha foi informada, ela precisa ser hasheada para n├úo quebrar o login
            if (senha) {
                const encoder = new TextEncoder();
                const data = encoder.encode(senha);
                const hashBuffer = await crypto.subtle.digest('SHA-256', data);
                const hashArray = Array.from(new Uint8Array(hashBuffer));
                senhaAEnviar = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
            }

            const payload = {
                nome, email, cargo, acesso, foto,
                ...(senha ? { senha: senhaAEnviar } : {}),
                lab_id: labId
            };

            if (editingAnalista) {
                await AnalistaService.update(editingAnalista.id, payload);
                // Se o analista editado for o usu├írio logado, atualiza o contexto
                if (editingAnalista.id === currentUser?.id) {
                    await refreshUser();
                }
            } else {
                await AnalistaService.create(payload as any);
            }
            setIsDialogOpen(false);
            loadData();
        } catch (error) {
            console.error(error);
            alert("Erro ao salvar analista: " + (error instanceof Error ? error.message : "Erro desconhecido"));
        }
    };



    const handleDelete = async (id: string) => {
        if (confirm("Tem certeza que deseja excluir este analista?")) {
            await AnalistaService.delete(id);
            loadData();
        }
    };

    const getLabName = (id?: string) => {
        if (!id) return "Global / N/A";
        return labs.find(l => l.id === id)?.nome || "Lab Desconhecido";
    };

    const getInitials = (name: string) => {
        return name.split(" ").map(n => n[0]).join("").substring(0, 2).toUpperCase();
    };

    const targetLabId = currentLab?.id || (currentUser?.acesso === 'admin_lab' ? currentUser.lab_id : null);

    return (
        <div className="animate-fade-in space-y-8">
            <div className="flex justify-between items-end border-b border-black pb-4">
                <div className="space-y-1">
                    <h2 className="text-xl font-serif text-black uppercase tracking-wide">Analyst Registry</h2>
                    <p className="text-[10px] font-mono text-neutral-500 uppercase tracking-widest">Manage access credentials & roles</p>
                </div>
                <Button
                    onClick={() => handleOpenDialog()}
                    className="rounded-none bg-black text-white hover:bg-neutral-800 text-[10px] font-bold uppercase tracking-widest px-6 h-10 transition-all"
                >
                    <Plus className="mr-2 h-3 w-3" /> New Analyst
                </Button>
            </div>

            <div className="overflow-x-auto">
                <table className="w-full text-left border-collapse">
                    <thead>
                        <tr className="border-b-2 border-black">
                            <th className="py-4 text-[10px] font-bold text-black uppercase tracking-widest pl-4">Profile</th>
                            <th className="py-4 text-[10px] font-bold text-black uppercase tracking-widest">Name / Role</th>
                            <th className="py-4 text-[10px] font-bold text-black uppercase tracking-widest">Credentials</th>
                            <th className="py-4 text-[10px] font-bold text-black uppercase tracking-widest">Unit Access</th>
                            <th className="py-4 text-[10px] font-bold text-black uppercase tracking-widest text-right pr-4">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-neutral-200">
                        {analistas.map(a => (
                            <tr key={a.id} className="group hover:bg-neutral-50 transition-colors">
                                <td className="py-4 pl-4">
                                    {a.foto ? (
                                        <div className="h-10 w-10 overflow-hidden border border-black grayscale">
                                            <img src={a.foto} alt={a.nome} className="h-full w-full object-cover" />
                                        </div>
                                    ) : (
                                        <div className="h-10 w-10 flex items-center justify-center border border-black bg-neutral-100 font-bold text-xs">
                                            {getInitials(a.nome)}
                                        </div>
                                    )}
                                </td>
                                <td className="py-4">
                                    <div className="font-bold text-sm text-black">{a.nome}</div>
                                    <div className="text-[10px] font-mono text-neutral-500 uppercase mt-1">{a.cargo}</div>
                                </td>
                                <td className="py-4">
                                    <div className="font-mono text-xs text-black">{a.email}</div>
                                    <div className="flex items-center gap-2 mt-1">
                                        <Shield className="h-3 w-3 text-neutral-400" />
                                        <span className="text-[9px] font-bold uppercase tracking-widest text-neutral-500">{a.acesso.replace('_', ' ')}</span>
                                    </div>
                                </td>
                                <td className="py-4">
                                    <span className="text-xs font-mono border-b border-neutral-300 pb-0.5">{getLabName(a.lab_id)}</span>
                                </td>
                                <td className="py-4 text-right pr-4 space-x-2">
                                    <Button variant="ghost" size="icon" onClick={() => handleOpenDialog(a)} className="rounded-none h-8 w-8 hover:bg-black hover:text-white border border-transparent hover:border-black transition-all">
                                        <Edit2 className="h-3 w-3" />
                                    </Button>
                                    <Button variant="ghost" size="icon" onClick={() => handleDelete(a.id)} className="rounded-none h-8 w-8 hover:bg-red-600 hover:text-white border border-transparent hover:border-red-600 transition-all">
                                        <Trash2 className="h-3 w-3" />
                                    </Button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
                <DialogContent className="max-w-lg p-0 overflow-hidden border border-black shadow-2xl bg-white rounded-none">
                    <div className="border-b border-black p-6 bg-neutral-50 flex items-center justify-between">
                        <div>
                            <h3 className="text-lg font-serif font-bold text-black uppercase">
                                {editingAnalista ? "EDITAR PERFIL" : "CADASTRAR ANALISTA"}
                            </h3>
                            <p className="text-[10px] font-mono font-bold text-neutral-400 uppercase tracking-widest mt-1">
                                GEST├âO DE CREDENCIAIS
                            </p>
                        </div>
                        <button
                            onClick={() => setIsDialogOpen(false)}
                            className="p-2 hover:bg-black hover:text-white transition-colors"
                            title="Fechar janela"
                            aria-label="Fechar janela"
                        >
                            <X className="h-4 w-4" />
                        </button>
                    </div>

                    <div className="p-8 space-y-6">
                        {/* Imagem de Perfil */}
                        <div className="flex flex-col items-center gap-4 py-2 border-b border-neutral-100 pb-6">
                            <div
                                className="h-24 w-24 border border-black flex items-center justify-center relative group cursor-pointer overflow-hidden bg-neutral-50 hover:bg-neutral-100 transition-colors"
                                onClick={() => fileInputRef.current?.click()}
                            >
                                {foto ? (
                                    <img src={foto} alt="Preview" className="h-full w-full object-cover grayscale" />
                                ) : (
                                    <Camera className="h-6 w-6 text-neutral-400 group-hover:text-black transition-colors" />
                                )}
                                <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                                    <span className="text-[9px] font-bold text-white uppercase tracking-widest">ALTERAR</span>
                                </div>
                            </div>
                            <input
                                type="file"
                                ref={fileInputRef}
                                className="hidden"
                                accept="image/*"
                                onChange={handleFileChange}
                                title="Upload de foto de perfil"
                                aria-label="Upload de foto de perfil"
                            />
                            <p className="text-[9px] font-bold uppercase text-neutral-400 tracking-widest">AVATAR DO USU├üRIO</p>
                        </div>

                        <div className="grid grid-cols-2 gap-6">
                            <div className="space-y-2">
                                <Label className="text-[9px] font-bold uppercase text-neutral-500 tracking-widest">NOME COMPLETO</Label>
                                <Input value={nome} onChange={e => setNome(e.target.value)} className="h-10 rounded-none border-neutral-300 focus:border-black font-mono text-sm" />
                            </div>
                            <div className="space-y-2">
                                <Label className="text-[9px] font-bold uppercase text-neutral-500 tracking-widest">FUN├ç├âO / CARGO</Label>
                                <Input value={cargo} onChange={e => setCargo(e.target.value)} className="h-10 rounded-none border-neutral-300 focus:border-black font-mono text-sm" />
                            </div>
                        </div>

                        <div className="space-y-2">
                            <Label className="text-[9px] font-bold uppercase text-neutral-500 tracking-widest">ENDERE├çO DE E-MAIL</Label>
                            <Input value={email} onChange={e => setEmail(e.target.value)} className="h-10 rounded-none border-neutral-300 focus:border-black font-mono text-sm" />
                        </div>

                        <div className="space-y-2">
                            <Label className="text-[9px] font-bold uppercase text-neutral-500 tracking-widest">SENHA</Label>
                            <Input value={senha} onChange={e => setSenha(e.target.value)} type="password" placeholder={editingAnalista ? "ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó" : "min. 6 caracteres"} className="h-10 rounded-none border-neutral-300 focus:border-black font-mono text-sm placeholder:text-neutral-300" />
                        </div>

                        <div className="grid grid-cols-2 gap-6">
                            <div className="space-y-2">
                                <Label className="text-[9px] font-bold uppercase text-neutral-500 tracking-widest min-h-[24px] flex items-center">N├ìVEL DE ACESSO</Label>
                                <select
                                    className="w-full h-10 rounded-none border border-neutral-300 px-3 text-xs font-mono uppercase focus:ring-0 focus:border-black focus:outline-none transition-all"
                                    value={acesso}
                                    onChange={(e) => setAcesso(e.target.value as AccessLevel)}
                                    title="Selecione o n├¡vel de acesso"
                                    aria-label="Selecione o n├¡vel de acesso"
                                >
                                    <option value="user">ANALISTA</option>
                                    <option value="quality_admin">QUALIDADE (ADM)</option>
                                    <option value="admin_lab">ADMIN LAB</option>
                                    {/* SUPER ADMIN option only visible to current super admins */}
                                    {currentUser?.acesso === 'admin_global' && (
                                        <option value="admin_global">SUPER ADMIN</option>
                                    )}
                                </select>
                            </div>
                            <div className="space-y-2">
                                <Label className="text-[9px] font-bold uppercase text-neutral-500 tracking-widest min-h-[24px] flex items-center">
                                    UNIDADE DE LABORAT├ôRIO
                                    {labs.length > 0 && (
                                        <span className="ml-2 text-neutral-400">({labs.length} DISPON├ìVEIS)</span>
                                    )}
                                </Label>
                                {labs.length === 0 ? (
                                    <div className="w-full h-10 rounded-none border border-dashed border-amber-400 bg-amber-50 px-3 flex items-center text-xs font-mono text-amber-700">
                                        ÔÜá NENHUM LAB
                                    </div>
                                ) : (
                                    <select
                                        className="w-full h-10 rounded-none border border-neutral-300 px-3 text-xs font-mono uppercase focus:ring-0 focus:border-black focus:outline-none transition-all disabled:opacity-50 disabled:bg-neutral-100"
                                        value={labId}
                                        onChange={(e) => setLabId(e.target.value)}
                                        disabled={!!targetLabId && currentUser?.acesso !== 'admin_global'}
                                        title="Selecione a unidade do laborat├│rio"
                                        aria-label="Selecione a unidade do laborat├│rio"
                                    >
                                        <option value="">SELECIONE A UNIDADE...</option>
                                        {labs.map(l => (
                                            <option key={l.id} value={l.id}>{l.nome} ({l.codigo})</option>
                                        ))}
                                    </select>
                                )}
                            </div>
                        </div>

                        <div className="flex gap-4 pt-4 border-t border-neutral-100 mt-4">
                            <Button
                                onClick={() => setIsDialogOpen(false)}
                                variant="ghost"
                                className="flex-1 h-12 rounded-none border border-black hover:bg-neutral-100 text-[10px] font-bold uppercase tracking-widest"
                            >
                                CANCELAR
                            </Button>
                            <Button
                                onClick={handleSave}
                                className="flex-1 h-12 rounded-none bg-black text-white hover:bg-neutral-800 text-[10px] font-bold uppercase tracking-widest shadow-lg"
                            >
                                SALVAR CREDENCIAIS
                            </Button>
                        </div>
                    </div>
                </DialogContent>
            </Dialog>
        </div>
    );
}

import { useState, useEffect } from "react";
import { Plus, Trash2, Edit2, Landmark, X, AlertTriangle, Loader2, CheckCircle } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { LabService } from "@/entities/Lab";
import type { Lab } from "@/entities/Lab";
import { MachineService } from "@/entities/Machine";
import { AnalistaService } from "@/entities/Analista";
import { Dialog, DialogContent } from "@/components/ui/dialog";
import { useToast } from "@/contexts/ToastContext";

export default function LabsTab() {
    const { addToast } = useToast();
    const [labs, setLabs] = useState<Lab[]>([]);
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [editingLab, setEditingLab] = useState<Lab | null>(null);
    const [deletingLab, setDeletingLab] = useState<Lab | null>(null);
    const [isDeleting, setIsDeleting] = useState(false);
    const [deleteSuccess, setDeleteSuccess] = useState<string | null>(null);

    // Form States
    const [nome, setNome] = useState("");
    const [codigo, setCodigo] = useState("");
    const [cidade, setCidade] = useState("");
    const [estado, setEstado] = useState("");

    useEffect(() => {
        loadLabs();
        // Sincroniza├º├úo Realtime ÔÇö atualiza automaticamente sem F5
        // quando qualquer usu├írio altera labs no banco de dados
        const unsubscribe = LabService.subscribe(() => loadLabs());
        return unsubscribe;
    }, []);

    const loadLabs = async () => {
        const data = await LabService.list();
        setLabs(data);
    };

    const handleOpenDialog = (lab?: Lab) => {
        if (lab) {
            setEditingLab(lab);
            setNome(lab.nome);
            setCodigo(lab.codigo);
            setCidade(lab.cidade || "");
            setEstado(lab.estado || "");
        } else {
            setEditingLab(null);
            setNome("");
            setCodigo("");
            setCidade("");
            setEstado("");
        }
        setIsDialogOpen(true);
    };

    const handleSave = async () => {
        try {
            if (editingLab) {
                await LabService.update(editingLab.id, { nome, codigo, cidade, estado });
                addToast({ title: "Laborat├│rio Atualizado", type: "success" });
            } else {
                await LabService.create({ nome, codigo, cidade, estado });
                addToast({ title: "Laborat├│rio Criado", type: "success" });
            }
            setIsDialogOpen(false);
            loadLabs();
        } catch (error) {
            console.error(error);
            addToast({ title: "Erro ao Salvar", description: "Verifique os dados e tente novamente.", type: "error" });
        }
    };

    // Exclus├úo em cascata ÔÇö sem portal, sem modal overlay
    // Usa painel inline para evitar o erro de DOM "insertBefore"
    const handleDelete = (lab: Lab) => {
        setDeleteSuccess(null);
        setDeletingLab(lab);
    };

    const cancelDelete = () => {
        setDeletingLab(null);
        setDeleteSuccess(null);
    };

    const confirmDelete = async () => {
        if (!deletingLab || isDeleting) return;
        setIsDeleting(true);

        const labId = deletingLab.id;
        const labNome = deletingLab.nome;

        try {
            // Passo 1: Apagar m├íquinas vinculadas
            const machines = await MachineService.listByLab(labId);
            for (const m of machines) {
                await MachineService.delete(m.id);
            }

            // Passo 2: Desvincular analistas (null, n├úo undefined ÔÇö para Supabase)
            const analistas = await AnalistaService.listByLab(labId);
            for (const a of analistas) {
                await AnalistaService.update(a.id, { lab_id: null } as any);
            }

            // Passo 3: Excluir o laborat├│rio
            await LabService.delete(labId);

            // Fecha o painel de confirma├º├úo e mostra sucesso inline
            setDeletingLab(null);
            setDeleteSuccess(`Laborat├│rio "${labNome}" removido com sucesso.`);

            // Recarrega lista
            await loadLabs();

            // Toast ap├│s tudo estabilizar
            setTimeout(() => {
                addToast({
                    title: `${labNome} removido`,
                    description: `${machines.length} m├íquina(s) e ${analistas.length} analista(s) desvinculados.`,
                    type: "success"
                });
                setDeleteSuccess(null);
            }, 2500);

        } catch (err: any) {
            console.error("Erro ao excluir laborat├│rio:", err);
            setDeletingLab(null);
            addToast({
                title: "Erro ao Excluir",
                description: err?.message || "Falha ao remover o laborat├│rio.",
                type: "error"
            });
        } finally {
            setIsDeleting(false);
        }
    };

    return (
        <div className="animate-fade-in space-y-8">
            <div className="flex justify-between items-end border-b border-black pb-4">
                <div className="space-y-1">
                    <h2 className="text-xl font-serif text-black uppercase tracking-wide">Lab Network</h2>
                    <p className="text-[10px] font-mono text-neutral-500 uppercase tracking-widest">Management of physical laboratory units</p>
                </div>
                <Button
                    onClick={() => handleOpenDialog()}
                    className="h-9 px-5 rounded-none bg-black text-white hover:bg-neutral-800 text-[10px] font-black uppercase tracking-widest flex items-center gap-2"
                >
                    <Plus className="h-3 w-3" /> Add Unit
                </Button>
            </div>

            {/* Banner de sucesso inline */}
            {deleteSuccess && (
                <div className="flex items-center gap-3 bg-emerald-50 border border-emerald-200 rounded-xl px-5 py-3 text-sm text-emerald-800"
                    style={{ animation: 'fadeSlideDown 0.3s ease' }}>
                    <CheckCircle className="h-4 w-4 text-emerald-500 shrink-0" />
                    <span className="font-medium">{deleteSuccess}</span>
                </div>
            )}

            {/* Painel de confirma├º├úo inline ÔÇö SEM portal/modal para evitar erro insertBefore */}
            {deletingLab && (
                <div
                    className="border border-red-200 bg-red-50/80 rounded-xl p-4 space-y-3 overflow-hidden"
                    style={{ animation: 'fadeSlideDown 0.25s ease' }}
                >
                    <div className="flex items-start gap-3">
                        <AlertTriangle className="h-5 w-5 text-red-500 mt-0.5 shrink-0" />
                        <div className="flex-1">
                            <p className="font-bold text-red-900 text-sm">
                                Excluir laborat├│rio: <span className="font-black">{deletingLab.nome}</span>?
                            </p>
                            <p className="text-xs text-red-600 mt-1">
                                Todas as m├íquinas HVI vinculadas ser├úo removidas. Analistas ser├úo desvinculados (n├úo exclu├¡dos). Os dados de O.S. n├úo ser├úo apagados.
                            </p>
                        </div>
                    </div>
                    <div className="flex gap-3">
                        <Button
                            onClick={cancelDelete}
                            disabled={isDeleting}
                            variant="ghost"
                            className="h-9 px-5 rounded-none border border-neutral-300 hover:bg-white text-[10px] font-bold uppercase tracking-widest"
                        >
                            Cancelar
                        </Button>
                        <Button
                            onClick={confirmDelete}
                            disabled={isDeleting}
                            className="h-9 px-5 rounded-none bg-red-600 hover:bg-red-700 text-white text-[10px] font-bold uppercase tracking-widest flex items-center gap-2"
                        >
                            {isDeleting ? (
                                <><Loader2 className="h-3 w-3 animate-spin" /> Removendo...</>
                            ) : (
                                <><Trash2 className="h-3 w-3" /> Sim, Excluir</>
                            )}
                        </Button>
                    </div>
                </div>
            )}

            <div className="overflow-x-auto">
                <table className="w-full text-sm">
                    <thead>
                        <tr className="border-b border-black">
                            <th className="py-3 pl-4 text-left text-[9px] font-black uppercase tracking-widest text-neutral-500 w-12"></th>
                            <th className="py-3 text-left text-[9px] font-black uppercase tracking-widest text-neutral-500">Laboratory</th>
                            <th className="py-3 text-left text-[9px] font-black uppercase tracking-widest text-neutral-500">Code</th>
                            <th className="py-3 text-left text-[9px] font-black uppercase tracking-widest text-neutral-500">Location</th>
                            <th className="py-3 pr-4 text-right text-[9px] font-black uppercase tracking-widest text-neutral-500">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-neutral-200">
                        {labs.map(lab => (
                            <tr
                                key={lab.id}
                                className={`group hover:bg-neutral-50 transition-colors ${deletingLab?.id === lab.id ? 'bg-red-50/50' : ''}`}
                            >
                                <td className="py-4 pl-4 text-center">
                                    <div className="h-8 w-8 mx-auto flex items-center justify-center border border-black bg-white rounded-none">
                                        <Landmark className="h-3 w-3 text-black" />
                                    </div>
                                </td>
                                <td className="py-4 font-bold text-sm text-black">{lab.nome}</td>
                                <td className="py-4">
                                    <span className="font-mono text-xs bg-neutral-100 px-2 py-1">{lab.codigo}</span>
                                </td>
                                <td className="py-4 font-mono text-xs text-neutral-500 uppercase">
                                    {lab.cidade}, {lab.estado}
                                </td>
                                <td className="py-4 text-right pr-4 space-x-2">
                                    <Button
                                        title="Editar laborat├│rio"
                                        variant="ghost"
                                        size="icon"
                                        onClick={() => handleOpenDialog(lab)}
                                        className="rounded-none h-8 w-8 hover:bg-black hover:text-white border border-transparent hover:border-black transition-all"
                                    >
                                        <Edit2 className="h-3 w-3" />
                                    </Button>
                                    <Button
                                        title="Excluir laborat├│rio"
                                        variant="ghost"
                                        size="icon"
                                        onClick={() => handleDelete(lab)}
                                        disabled={isDeleting}
                                        className="rounded-none h-8 w-8 hover:bg-red-600 hover:text-white border border-transparent hover:border-red-600 transition-all"
                                    >
                                        <Trash2 className="h-3 w-3" />
                                    </Button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {/* Modal Criar/Editar Laborat├│rio */}
            <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
                <DialogContent className="max-w-md p-0 overflow-hidden border border-black shadow-2xl bg-white rounded-none">
                    <div className="border-b border-black p-6 bg-neutral-50 flex items-center justify-between">
                        <h3 className="text-lg font-serif font-bold text-black uppercase">
                            {editingLab ? "Editar Laborat├│rio" : "Novo Laborat├│rio"}
                        </h3>
                        <button
                            onClick={() => setIsDialogOpen(false)}
                            title="Fechar modal"
                            className="p-2 hover:bg-black hover:text-white transition-colors"
                        >
                            <X className="h-4 w-4" />
                        </button>
                    </div>

                    <div className="p-8 space-y-6">
                        <div className="space-y-2">
                            <Label className="text-[9px] font-bold uppercase text-neutral-500 tracking-widest">Nome do Laborat├│rio</Label>
                            <Input value={nome} onChange={e => setNome(e.target.value)} placeholder="ex: Sorriso" className="h-10 rounded-none border-neutral-300 focus:border-black font-mono text-sm" />
                        </div>
                        <div className="space-y-2">
                            <Label className="text-[9px] font-bold uppercase text-neutral-500 tracking-widest">C├│digo</Label>
                            <Input value={codigo} onChange={e => setCodigo(e.target.value)} placeholder="ex: LAB-01" className="h-10 rounded-none border-neutral-300 focus:border-black font-mono text-sm uppercase" />
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <Label className="text-[9px] font-bold uppercase text-neutral-500 tracking-widest">Cidade</Label>
                                <Input value={cidade} onChange={e => setCidade(e.target.value)} className="h-10 rounded-none border-neutral-300 focus:border-black font-mono text-sm" />
                            </div>
                            <div className="space-y-2">
                                <Label className="text-[9px] font-bold uppercase text-neutral-500 tracking-widest">Estado (UF)</Label>
                                <Input value={estado} onChange={e => setEstado(e.target.value)} maxLength={2} className="h-10 rounded-none border-neutral-300 focus:border-black font-mono text-sm uppercase" />
                            </div>
                        </div>

                        <div className="flex gap-4 pt-4 border-t border-neutral-100 mt-4">
                            <Button
                                onClick={() => setIsDialogOpen(false)}
                                variant="ghost"
                                className="flex-1 h-12 rounded-none border border-black hover:bg-neutral-100 text-[10px] font-bold uppercase tracking-widest"
                            >
                                Cancelar
                            </Button>
                            <Button
                                onClick={handleSave}
                                className="flex-[2] h-12 rounded-none bg-black text-white hover:bg-neutral-800 text-[10px] font-bold uppercase tracking-widest shadow-lg"
                            >
                                Salvar
                            </Button>
                        </div>
                    </div>
                </DialogContent>
            </Dialog>
        </div>
    );
}

import { useState } from "react";
import type { Sample } from "@/entities/Sample";
import { cn } from "@/lib/utils";
import { calculateStatistics } from "@/lib/stats";
import { AlertTriangle, Palette, Box, Tag, Cpu, ArrowUpDown, ArrowUp, ArrowDown, Trash2, Calendar, Hash, FileDown, Lock } from "lucide-react";
import { formatDecimalBR } from "@/services/ocrExtraction";
import { HVIFileGeneratorService, type HVIPreviewData } from "@/services/HVIFileGeneratorService";
import HVIPreviewModal from "@/components/HVIPreviewModal";
import { useLanguage } from "@/contexts/LanguageContext";

interface AnalysisTableProps {
    samples: Sample[];
    onUpdateSample: (id: string, field: string, value: any) => void;
    onColorChange: (id: string, color: string) => void;
    onDeleteSample: (id: string) => void;
    isProcessing: boolean;
    highlightedSampleId?: string | null;
}

const COLORS = [
    { value: "#ef4444", label: "Vermelho", name: "red" },
    { value: "#3b82f6", label: "Azul", name: "blue" },
    { value: "#10b981", label: "Verde", name: "green" },
    { value: "#f59e0b", label: "Amarelo", name: "yellow" },
];

export default function AnalysisTable({ samples, onUpdateSample, onColorChange, onDeleteSample, isProcessing, highlightedSampleId }: AnalysisTableProps) {
    const { t } = useLanguage();
    const fields = ['mic', 'len', 'unf', 'str', 'rd', 'b'] as const;
    const [sortConfig, setSortConfig] = useState<{ key: string; direction: 'asc' | 'desc' } | null>(null);
    const [previewModal, setPreviewModal] = useState<{ isOpen: boolean; data: HVIPreviewData | null; sample: Sample | null }>({ isOpen: false, data: null, sample: null });

    const statsByField = fields.reduce((acc, field) => {
        const values = samples
            .map(s => ({ id: s.id, val: (s as any)[field] }))
            .filter(v => typeof v.val === 'number');
        acc[field] = calculateStatistics(values);
        return acc;
    }, {} as Record<string, ReturnType<typeof calculateStatistics>>);

    const handleSort = (key: string) => {
        let direction: 'asc' | 'desc' = 'asc';
        if (sortConfig && sortConfig.key === key && sortConfig.direction === 'asc') {
            direction = 'desc';
        }
        setSortConfig({ key, direction });
    };

    const sortedSamples = [...samples].sort((a, b) => {
        if (!sortConfig) return 0;
        const valA = (a as any)[sortConfig.key];
        const valB = (b as any)[sortConfig.key];

        if (valA < valB) return sortConfig.direction === 'asc' ? -1 : 1;
        if (valA > valB) return sortConfig.direction === 'asc' ? 1 : -1;
        return 0;
    });

    // Highlight visual only - no scroll

    return (
        <div className="relative w-full bg-white">
            <table className="w-full text-left border-collapse table-fixed">
                <thead className="bg-slate-50 border-b border-slate-200 sticky top-0 z-10">
                    <tr className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-[3.5rem]">
                        <th
                            className="px-2 w-[50px] cursor-pointer hover:text-blue-600 transition-colors"
                            onClick={() => handleSort('amostra_id')}
                        >
                            <div className="flex items-center gap-1">
                                <Hash className="h-3.5 w-3.5 hidden lg:inline" /> ID
                                {sortConfig?.key === 'amostra_id' ? (
                                    sortConfig.direction === 'asc' ? <ArrowUp className="h-3 w-3" /> : <ArrowDown className="h-3 w-3" />
                                ) : (
                                    <ArrowUpDown className="h-3 w-3 opacity-20" />
                                )}
                            </div>
                        </th>
                        <th className="px-2 w-[8%]">
                            <div className="flex items-center gap-1">
                                <Box className="h-3.5 w-3.5 hidden lg:inline" /> MALA
                            </div>
                        </th>
                        <th className="px-2 w-[12%]">
                            <div className="flex items-center gap-1">
                                <Tag className="h-3.5 w-3.5 hidden lg:inline" /> LABEL
                            </div>
                        </th>
                        <th className="px-2 w-[8%]">
                            <div className="flex items-center gap-1">
                                <Calendar className="h-3.5 w-3.5 hidden lg:inline" /> DATA
                            </div>
                        </th>
                        <th
                            className="px-1 text-center w-[35px] cursor-pointer hover:text-blue-600 transition-colors"
                            onClick={() => handleSort('hvi')}
                        >
                            <div className="flex items-center justify-center gap-1">
                                <Cpu className="h-3.5 w-3.5 inline" />
                                {sortConfig?.key === 'hvi' ? (
                                    sortConfig.direction === 'asc' ? <ArrowUp className="h-3 w-3" /> : <ArrowDown className="h-3 w-3" />
                                ) : null}
                            </div>
                        </th>
                        <th
                            className="px-1 text-center w-[70px] cursor-pointer hover:text-blue-600 transition-colors"
                            onClick={() => handleSort('cor')}
                        >
                            <div className="flex items-center justify-center gap-1">
                                <Palette className="h-3.5 w-3.5 inline" />
                                {sortConfig?.key === 'cor' ? (
                                    sortConfig.direction === 'asc' ? <ArrowUp className="h-3 w-3" /> : <ArrowDown className="h-3 w-3" />
                                ) : null}
                            </div>
                        </th>
                        {fields.map(f => (
                            <th
                                key={f}
                                onClick={() => handleSort(f)}
                                className="px-4 text-right italic font-black text-slate-500 cursor-pointer hover:text-blue-600 transition-colors"
                            >
                                <div className="flex items-center justify-end gap-1">
                                    {f === 'b' ? '+b' : f.toUpperCase()}
                                    {sortConfig?.key === f ? (
                                        sortConfig.direction === 'asc' ?
                                            <ArrowUp className="h-3 w-3 text-blue-600" /> :
                                            <ArrowDown className="h-3 w-3 text-blue-600" />
                                    ) : (
                                        <ArrowUpDown className="h-3 w-3 opacity-20" />
                                    )}
                                </div>
                            </th>
                        ))}
                        <th className="px-2 w-[70px]"></th>
                    </tr>
                </thead>

                <tbody className="divide-y divide-slate-100">
                    {sortedSamples.map((sample) => {
                        // Define cor de fundo baseada na classifica├º├úo
                        let rowBgClass = "hover:bg-slate-50";
                        if (sample.cor === "#ef4444") rowBgClass = "bg-red-50/5 hover:bg-red-100/10";
                        else if (sample.cor === "#3b82f6") rowBgClass = "bg-blue-50/5 hover:bg-blue-100/10";
                        else if (sample.cor === "#10b981") rowBgClass = "bg-emerald-50/5 hover:bg-emerald-100/10";
                        else if (sample.cor === "#f59e0b") rowBgClass = "bg-amber-50/5 hover:bg-amber-100/10";

                        const isHighlighted = highlightedSampleId === sample.id;

                        return (
                            <tr
                                key={sample.id}
                                id={`sample-row-${sample.id}`}
                                className={cn(
                                    "transition-all text-xs border-b",
                                    rowBgClass,
                                    isHighlighted ? "bg-black text-white !border-black scale-[1.01] shadow-xl z-20 relative" : "border-slate-100"
                                )}
                            >
                                <td className="px-2 py-4 font-mono font-black text-black text-center border-r border-slate-100/50">
                                    <span className={cn(
                                        "text-sm",
                                        isHighlighted && "text-white"
                                    )}>
                                        #{sample.amostra_id}
                                    </span>
                                </td>
                                <td className="px-2 py-4 font-bold truncate border-r border-slate-100/50">
                                    <div className={cn(
                                        "inline-flex items-center px-2 py-1 rounded-lg text-[10px] font-black uppercase tracking-tight shadow-sm",
                                        sample.cor === "#ef4444" ? "bg-red-100 text-red-700" :
                                            sample.cor === "#3b82f6" ? "bg-blue-100 text-blue-700" :
                                                sample.cor === "#10b981" ? "bg-emerald-100 text-emerald-700" :
                                                    sample.cor === "#f59e0b" ? "bg-amber-100 text-amber-700" :
                                                        "bg-slate-50 text-slate-400"
                                    )}>
                                        {sample.mala || "-"}
                                    </div>
                                </td>
                                <td className="px-2 py-4 font-bold text-slate-400 text-[10px] truncate border-r border-slate-100/50">{sample.etiqueta || "-"}</td>
                                <td className="px-2 py-4 font-mono font-bold text-slate-500 text-[9px] border-r border-slate-100/50">
                                    <div className="flex flex-col leading-tight">
                                        <span>{sample.data_analise || "--/--/--"}</span>
                                        <span className="text-[8px] opacity-70">{sample.hora_analise || "--:--"}</span>
                                    </div>
                                </td>
                                <td className="px-1 py-4 font-black text-blue-600 text-center border-r border-slate-100/50">{sample.hvi || "-"}</td>
                                <td className="px-2 py-4 border-r border-slate-100/50">
                                    <div className="flex gap-1 justify-center items-center min-w-fit px-1">
                                        {COLORS.map((c) => (
                                            <button
                                                key={c.value}
                                                disabled={sample.locked}
                                                onClick={() => {
                                                    // Se clicar na cor j├í selecionada, REMOVE a cor
                                                    if (sample.cor === c.value) {
                                                        onColorChange(sample.id, ""); // Remove a cor
                                                    } else {
                                                        onColorChange(sample.id, c.value); // Aplica a cor
                                                    }
                                                }}
                                                className={cn(
                                                    "w-5 h-5 rounded-full border-2 border-white shadow-md transition-all focus:outline-none",
                                                    sample.locked ? "cursor-not-allowed opacity-50" : "hover:scale-110",
                                                    sample.cor === c.value
                                                        ? "scale-110 ring-2 ring-slate-900 ring-offset-1 opacity-100"
                                                        : "opacity-30 hover:opacity-100 hover:ring-2 hover:ring-slate-300 hover:ring-offset-1",
                                                    c.value === "#ef4444" && "bg-red-500",
                                                    c.value === "#3b82f6" && "bg-blue-500",
                                                    c.value === "#10b981" && "bg-emerald-500",
                                                    c.value === "#f59e0b" && "bg-amber-500"
                                                )}
                                                title={sample.locked ? "Amostra bloqueada" : (sample.cor === c.value ? `Remover cor ${c.label}` : `Aplicar ${c.label}`)}
                                            />
                                        ))}
                                    </div>
                                </td>
                                {fields.map((field) => {
                                    const value = (sample as any)[field];
                                    const isOutlier = statsByField[field].outliers.includes(sample.id);
                                    const decimals = field === 'mic' || field === 'len' ? 2 : 1;

                                    return (
                                        <td key={field} className="px-4 py-4 text-right border-r border-slate-100/50 last:border-none">
                                            <div className="relative flex items-center justify-end">
                                                {isOutlier && (
                                                    <AlertTriangle className="h-3 w-3 text-amber-500 absolute -left-2 animate-pulse" />
                                                )}
                                                <input
                                                    aria-label={`Valor de ${field}`}
                                                    className={cn(
                                                        "w-full text-right bg-transparent border-none focus:ring-0 p-0 font-mono font-black transition-all",
                                                        "text-lg tracking-tight",
                                                        isOutlier ? "text-amber-600" : (isHighlighted ? "text-white" : "text-slate-900"),
                                                        (isProcessing || sample.locked) && "opacity-50 cursor-not-allowed"
                                                    )}
                                                    defaultValue={formatDecimalBR(value ?? 0, decimals)}
                                                    onBlur={(e) => {
                                                        if (sample.locked) {
                                                            e.target.value = formatDecimalBR(value ?? 0, decimals);
                                                            return;
                                                        }
                                                        const inputValue = e.target.value.replace(',', '.');
                                                        const val = parseFloat(inputValue);
                                                        if (!isNaN(val) && val !== value) {
                                                            onUpdateSample(sample.id, field, val);
                                                        }
                                                        e.target.value = formatDecimalBR(isNaN(val) ? (value ?? 0) : val, decimals);
                                                    }}
                                                    disabled={isProcessing || sample.locked}
                                                />
                                            </div>
                                        </td>
                                    );
                                })}
                                <td className="px-1 py-3 text-center">
                                    <div className="flex items-center justify-center gap-0.5">
                                        {sample.locked ? (
                                            <button
                                                onClick={() => {
                                                    if (confirm("Deseja desbloquear esta amostra para edi├º├úo?")) {
                                                        onUpdateSample(sample.id, 'locked', false);
                                                    }
                                                }}
                                                className="p-1 text-amber-500 hover:text-amber-600 hover:bg-amber-50 rounded transition-all"
                                                title="Amostra Bloqueada (Clique para Desbloquear)"
                                            >
                                                <Lock className="h-3.5 w-3.5" />
                                            </button>
                                        ) : (
                                            <button
                                                onClick={async () => {
                                                    const result = await HVIFileGeneratorService.generatePreviewForSample(sample, samples);
                                                    if (!result.success) {
                                                        alert(result.message);
                                                    } else if (result.data) {
                                                        setPreviewModal({ isOpen: true, data: result.data, sample });
                                                    }
                                                }}
                                                className="p-1 text-slate-300 hover:text-blue-600 hover:bg-blue-50 rounded transition-all"
                                                title="Gerar arquivo HVI"
                                            >
                                                <FileDown className="h-3.5 w-3.5" />
                                            </button>
                                        )}

                                        {!sample.locked && (
                                            <button
                                                onClick={() => onDeleteSample(sample.id)}
                                                className="p-1 text-slate-300 hover:text-rose-600 hover:bg-rose-50 rounded transition-all"
                                                title={t('analysis.delete_sample')}
                                            >
                                                <Trash2 className="h-3.5 w-3.5" />
                                            </button>
                                        )}
                                    </div>
                                </td>
                            </tr>
                        );
                    })}
                </tbody>
            </table>
            {samples.length === 0 && (
                <div className="p-24 text-center text-slate-200 font-bold uppercase tracking-[0.4em] italic text-[10px]">
                    {t('analysis.no_records')}
                </div>
            )}

            {/* HVI Preview Modal */}
            {previewModal.data && previewModal.sample && (
                <HVIPreviewModal
                    isOpen={previewModal.isOpen}
                    onClose={() => setPreviewModal({ isOpen: false, data: null, sample: null })}
                    onConfirm={() => {
                        if (previewModal.data) {
                            HVIFileGeneratorService.downloadHVIFile(previewModal.data.content, previewModal.data.filename);
                            if (previewModal.sample) {
                                onUpdateSample(previewModal.sample.id, 'locked', true);
                            }
                            setPreviewModal({ isOpen: false, data: null, sample: null });
                        }
                    }}
                    content={previewModal.data.content}
                    filename={previewModal.data.filename}
                    machineModel={previewModal.data.machineModel}
                    originalSample={previewModal.sample}
                    generatedValues={previewModal.data.generatedValues}
                />
            )}
        </div>
    );
}

import React, { useState, useMemo } from "react";
import { Line, LineChart, CartesianGrid, ResponsiveContainer, Tooltip, XAxis, YAxis } from "recharts";
import { cn } from "@/lib/utils";

import { CalendarDays, RotateCcw } from "lucide-react";

interface GlobalProductionChartProps {
    data: any[]; // Array of { date: string, [labId]: number }
    labs: any[]; // Array of { id: string, nome: string, ... }
}

const CHART_CONFIG = [
    { hex: "#000000", bg: "bg-black", text: "text-black" }, // Lab 1
    { hex: "#ef4444", bg: "bg-red-500", text: "text-red-500" }, // Lab 2
    { hex: "#22c55e", bg: "bg-green-500", text: "text-green-500" }, // Lab 3
    { hex: "#3b82f6", bg: "bg-blue-500", text: "text-blue-500" }, // Lab 4
    { hex: "#f59e0b", bg: "bg-amber-500", text: "text-amber-500" }, // Lab 5
    { hex: "#8b5cf6", bg: "bg-violet-500", text: "text-violet-500" }, // Lab 6
    { hex: "#ec4899", bg: "bg-pink-500", text: "text-pink-500" }, // Lab 7
    { hex: "#64748b", bg: "bg-slate-500", text: "text-slate-500" }, // Lab 8
];

const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
        return (
            <div className="bg-white p-4 border border-neutral-200 shadow-xl rounded-lg">
                <p className="font-bold text-sm mb-2 font-mono flex items-center gap-2">
                    <CalendarDays className="h-4 w-4 text-neutral-500" />
                    {new Date(label).toLocaleDateString('pt-BR')}
                </p>
                <div className="space-y-1">
                    {payload.map((entry: any, index: number) => {
                        const config = CHART_CONFIG.find(c => c.hex === entry.color) || CHART_CONFIG[0];
                        return (
                            <div key={index} className="flex items-center gap-2 justify-between min-w-[150px]">
                                <div className="flex items-center gap-2">
                                    <div
                                        className={cn("w-2 h-2 rounded-full", config.bg)}
                                    />
                                    <span className="text-xs text-neutral-500 uppercase tracking-widest truncate max-w-[100px]">
                                        {entry.name}
                                    </span>
                                </div>
                                <span
                                    className={cn("font-mono font-bold", config.text)}
                                >
                                    {entry.value.toLocaleString('pt-BR')}
                                </span>
                            </div>
                        );
                    })}
                </div>
            </div>
        );
    }
    return null;
};

export default function GlobalProductionChart({ data, labs }: GlobalProductionChartProps) {
    if (!data || data.length === 0) return null;

    const [startDate, setStartDate] = useState<string>('');
    const [endDate, setEndDate] = useState<string>('');
    const [granularity, setGranularity] = useState<'day' | 'week' | 'month'>('day');
    const [selectedLabs, setSelectedLabs] = useState<string[]>([]);

    // Initialize selected labs
    useMemo(() => {
        if (labs && labs.length > 0 && selectedLabs.length === 0) {
            setSelectedLabs(labs.map(l => l.id));
        }
    }, [labs]);

    const toggleLab = (labId: string, e: React.MouseEvent) => {
        if (e.ctrlKey || e.metaKey || e.shiftKey) {
            // Multi-select mode (Toggle specific lab)
            setSelectedLabs(prev =>
                prev.includes(labId)
                    ? prev.filter(id => id !== labId)
                    : [...prev, labId]
            );
        } else {
            // Single-select mode (Isolate or Reset)
            if (selectedLabs.length === 1 && selectedLabs[0] === labId) {
                // Already isolated, so reset to show all
                if (labs) setSelectedLabs(labs.map(l => l.id));
            } else {
                // Isolate this lab
                setSelectedLabs([labId]);
            }
        }
    };

    const resetFilters = () => {
        setStartDate('');
        setEndDate('');
        setGranularity('day');
        if (labs) setSelectedLabs(labs.map(l => l.id));
    };

    // Filter Data by Date Range
    const filteredData = useMemo(() => {
        if (!startDate && !endDate) {
            // Default: Last 30 days
            const sortedData = [...data].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
            return sortedData.slice(-30);
        }

        let filtered = data;
        if (startDate) {
            filtered = filtered.filter(d => d.date >= startDate);
        }
        if (endDate) {
            filtered = filtered.filter(d => d.date <= endDate);
        }
        return filtered.sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
    }, [data, startDate, endDate]);

    return (
        <div className="w-full bg-white border border-neutral-200 rounded-2xl p-6 shadow-sm mb-12">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
                <div>
                    <h3 className="text-lg font-bold uppercase tracking-tight">Vis├úo Global de Produ├º├úo</h3>
                    <p className="text-xs text-neutral-500 font-mono mt-1">TOTAL DE AMOSTRAS POR LABORAT├ôRIO (DI├üRIO)</p>
                </div>

                <div className="flex items-center gap-4 bg-neutral-50 p-2 rounded-lg border border-neutral-100">
                    <div className="flex items-center gap-2 text-xs font-mono">
                        <span className="text-neutral-400">DE:</span>
                        <input
                            type="date"
                            className="bg-transparent border-none p-1 font-bold text-black focus:ring-0 cursor-pointer"
                            onChange={(e) => setStartDate(e.target.value)}
                            value={startDate}
                            aria-label="Data Inicial"
                        />
                    </div>
                    <div className="w-px h-4 bg-neutral-300" />
                    <div className="flex items-center gap-2 text-xs font-mono">
                        <span className="text-neutral-400">AT├ë:</span>
                        <input
                            type="date"
                            className="bg-transparent border-none p-1 font-bold text-black focus:ring-0 cursor-pointer"
                            onChange={(e) => setEndDate(e.target.value)}
                            value={endDate}
                            aria-label="Data Final"
                        />
                    </div>
                </div>

                <div className="flex bg-neutral-100 p-1 rounded-lg">
                    {['day', 'week', 'month'].map((g) => (
                        <button
                            key={g}
                            onClick={() => setGranularity(g as any)}
                            className={cn(
                                "px-3 py-1 text-[10px] font-bold uppercase tracking-wider rounded-md transition-all",
                                granularity === g ? "bg-white text-black shadow-sm" : "text-neutral-400 hover:text-neutral-600"
                            )}
                        >
                            {g === 'day' ? 'Dia' : g === 'week' ? 'Sem' : 'M├¬s'}
                        </button>
                    ))}
                </div>

                <button
                    onClick={resetFilters}
                    className="flex items-center gap-2 px-3 py-2 bg-neutral-100 hover:bg-neutral-200 text-neutral-600 rounded-lg transition-colors text-xs font-bold uppercase tracking-wider"
                    title="Limpar Filtros"
                >
                    <RotateCcw className="h-3 w-3" />
                    Limpar
                </button>
            </div>

            {/* Custom Legend / Filter */}
            <div className="flex flex-wrap gap-3 mb-8 justify-center">
                {labs.map((lab, index) => {
                    const config = CHART_CONFIG[index % CHART_CONFIG.length];
                    const isSelected = selectedLabs.includes(lab.id);

                    return (
                        <button
                            key={lab.id}
                            onClick={(e) => toggleLab(lab.id, e)}
                            className={cn(
                                "flex items-center gap-2 px-4 py-2 rounded-full border transition-all duration-300 transform hover:scale-105",
                                isSelected
                                    ? "bg-white border-neutral-200 shadow-md ring-1 ring-black/5"
                                    : "bg-neutral-50 border-transparent opacity-60 grayscale hover:grayscale-0 hover:opacity-100"
                            )}
                            title="Clique para isolar, Ctrl+Clique para selecionar m├║ltiplos"
                        >
                            <div
                                className={cn(
                                    "w-3 h-3 rounded-full shadow-sm transition-all duration-300",
                                    isSelected ? "scale-110" : "scale-90",
                                    config.bg
                                )}
                            />
                            <span className={cn(
                                "text-[10px] font-bold uppercase tracking-widest transition-colors",
                                isSelected ? "text-black" : "text-neutral-500"
                            )}>
                                {lab.nome}
                            </span>
                        </button>
                    );
                })}
            </div>

            <div className="h-[400px] w-full">
                <ResponsiveContainer width="100%" height="100%">
                    <LineChart
                        data={filteredData}
                        margin={{
                            top: 5,
                            right: 30,
                            left: 20,
                            bottom: 5,
                        }}
                    >
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f5f5f5" />
                        <XAxis
                            dataKey="date"
                            axisLine={false}
                            tickLine={false}
                            tick={{ fontSize: 10, fill: '#737373' }}
                            tickFormatter={(value) => new Date(value).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' })}
                            minTickGap={30}
                        />
                        <YAxis
                            axisLine={false}
                            tickLine={false}
                            tick={{ fontSize: 10, fill: '#737373' }}
                            tickFormatter={(value) => value >= 1000 ? `${(value / 1000).toFixed(1)}k` : value}
                        />
                        <Tooltip content={<CustomTooltip />} cursor={{ stroke: '#e5e5e5', strokeWidth: 1 }} />

                        {labs.map((lab, idx) => {
                            if (!selectedLabs.includes(lab.id)) return null;
                            return (
                                <Line
                                    key={lab.id}
                                    type="monotone"
                                    dataKey={lab.id}
                                    name={lab.nome}
                                    stroke={CHART_CONFIG[idx % CHART_CONFIG.length].hex}
                                    strokeWidth={2}
                                    dot={{ r: 3, strokeWidth: 0, fill: CHART_CONFIG[idx % CHART_CONFIG.length].hex }}
                                    activeDot={{ r: 6, strokeWidth: 0 }}
                                    connectNulls
                                />
                            );
                        })}
                    </LineChart>
                </ResponsiveContainer>
            </div>
        </div>
    );
}

import { useState, useEffect, useRef } from "react";
import { X, Activity, ChevronRight, Binary, ShieldCheck } from "lucide-react";
import { HVIAnalysisService, type HVIAnalysisReport, type ParameterAnalysis } from "@/services/HVIAnalysisService";
import { type Sample } from "@/entities/Sample";
import { cn } from "@/lib/utils";
import { createPortal } from "react-dom";

// HVI Statistical Report Modal Component
interface HVIStatisticalReportModalProps {
    isOpen: boolean;
    onClose: () => void;
    samples: Sample[];
}

export default function HVIStatisticalReportModal({ isOpen, onClose, samples }: HVIStatisticalReportModalProps) {
    const [reports, setReports] = useState<HVIAnalysisReport[]>([]);
    const [loading, setLoading] = useState(false);
    const [activeTab, setActiveTab] = useState(0);
    const reportRef = useRef<HTMLDivElement>(null);
    const scrollContainerRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (isOpen && samples.length > 0) {
            const fetchReport = async () => {
                setLoading(true);
                try {
                    const reportData = await HVIAnalysisService.analyze(samples);
                    setReports(reportData);
                    if (activeTab >= reportData.length) setActiveTab(0);
                } catch (error) {
                    console.error("Erro ao gerar relat├│rio:", error);
                } finally {
                    setLoading(false);
                }
            };
            fetchReport();
        }
    }, [isOpen, samples]);

    useEffect(() => {
        if (scrollContainerRef.current) scrollContainerRef.current.scrollTop = 0;
    }, [activeTab]);

    const currentReport = reports[activeTab];

    const getInterpretation = (analysis: ParameterAnalysis, count: number) => {
        if (count === 1) return { label: "INDIVIDUAL", color: "text-neutral-600", bg: "bg-neutral-50", desc: "Amostra ├║nica. Medi├º├úo pontual sem base estat├¡stica." };
        const cv = analysis.stats.cv;
        const prob = analysis.prediction.probabilityWithinRange;
        if (cv <= 2.5 && prob > 85) return { label: "EXCELENTE", color: "text-green-600", bg: "bg-green-50", desc: "Uniformidade excepcional. Ideal para fia├º├úo de alta performance." };
        if (cv <= 5.0 && prob > 65) return { label: "EST├üVEL", color: "text-blue-600", bg: "bg-blue-50", desc: "Varia├º├úo controlada dentro dos padr├Áes t├®cnicos." };
        if (cv <= 8.0) return { label: "ALERTA", color: "text-amber-600", bg: "bg-amber-50", desc: "Dispers├úo moderada. Requer aten├º├úo no processo." };
        return { label: "CR├ìTICO", color: "text-red-600", bg: "bg-red-50", desc: "Alta heterogeneidade. Risco elevado de irregularidades." };
    };

    const getParamMeaning = (param: string) => {
        const meanings: Record<string, string> = {
            'MIC': 'Micronaire (Finura e Maturidade)',
            'LEN': 'Comprimento UHML (Polegadas)',
            'STR': 'Resist├¬ncia (G/Tex)',
            'UNF': 'Uniformidade de Comprimento (%)',
            'RD': 'Reflet├óncia da Cor (Rd)',
            'B': 'Grau de Amarelamento (+b)'
        };
        return meanings[param.toUpperCase()] || param;
    };

    const getCleanLabel = (label: string, type: 'CONSOLIDATED' | 'MACHINE' | 'COLOR') => {
        if (type === 'CONSOLIDATED') return 'PANORAMA GLOBAL DO LOTE';
        if (type === 'MACHINE') return 'UNIDADE HVI ' + label.replace('M├üQUINA: ', '').replace('HVI ', '');
        if (type === 'COLOR') {
            const raw = label.replace('QUALIDADE: ', '');
            if (raw === '#3b82f6') return 'CLASSE AZUL (PREMIUM)';
            if (raw === '#10b981') return 'CLASSE VERDE (PADR├âO)';
            if (raw === '#f59e0b') return 'CLASSE AMARELA (M├ëDIO)';
            if (raw === '#ef4444') return 'CLASSE VERMELHA (REJEITO)';
            return 'CLASSE: ' + raw;
        }
        return label;
    };

    if (!isOpen) return null;

    const activeColor = currentReport?.groupType === 'COLOR' ? currentReport.machine.replace('QUALIDADE: ', '') : null;

    return createPortal(
        <div className="fixed inset-0 z-[999] flex items-center justify-center bg-black/60 backdrop-blur-md p-0 md:p-8 overflow-hidden">
            <div className="bg-white w-full max-w-[1600px] h-full md:h-auto md:max-h-[95vh] flex flex-col border-2 border-black overflow-hidden relative shadow-[20px_20px_0px_rgba(0,0,0,0.15)] animate-in zoom-in-95 duration-300">

                {/* HEADER */}
                <div className="shrink-0 flex items-center justify-between px-8 py-4 border-b-2 border-black bg-white">
                    <div className="flex items-center gap-6">
                        <div className="h-10 w-10 bg-black flex items-center justify-center rotate-3 shadow-lg">
                            <ShieldCheck className="text-white h-6 w-6" />
                        </div>
                        <div className="flex flex-col">
                            <h2 className="text-2xl font-serif font-black tracking-tighter text-black uppercase italic leading-none">ORIGO INTELLIGENCE</h2>
                            <p className="text-[9px] font-mono font-black text-black/40 uppercase tracking-[0.4em] mt-0.5">Fiber Quality Audit System</p>
                        </div>
                    </div>
                    <button onClick={onClose} className="p-2.5 hover:bg-black hover:text-white transition-all border-2 border-black rounded-full shadow-[3px_3px_0px_#ddd] active:shadow-none active:translate-x-[2px] active:translate-y-[2px]" title="Fechar Relat├│rio">
                        <X className="h-5 w-5" />
                    </button>
                </div>

                <div className="flex-1 overflow-hidden flex flex-col md:flex-row bg-white">

                    {/* SIDEBAR */}
                    <div className="w-full md:w-[320px] border-b-2 md:border-b-0 md:border-r-2 border-black bg-[#fafafa] flex flex-col shrink-0">
                        <div className="p-6 space-y-8 overflow-y-auto">
                            <div className="space-y-3">
                                <p className="text-[10px] font-mono text-black font-black uppercase tracking-[0.3em] border-b border-black/20 pb-2">
                                    Segmentos Auditados
                                </p>
                                <div className="space-y-1.5">
                                    {reports.map((r, idx) => (
                                        <button
                                            key={`${r.machine}-${idx}`}
                                            onClick={() => setActiveTab(idx)}
                                            className={cn(
                                                "w-full text-left px-4 py-3 text-[10px] font-mono uppercase tracking-wide font-black transition-all border-2 flex items-center justify-between group",
                                                activeTab === idx ? "bg-black text-white border-black shadow-[4px_4px_0px_rgba(0,0,0,0.1)]" : "bg-white text-black border-black/10 hover:border-black"
                                            )}
                                        >
                                            <div className="flex items-center gap-3">
                                                {r.groupType === 'COLOR' && (
                                                    <div className="h-3 w-3 rounded-full border border-black/30 shadow-sm bg-dynamic" style={{ '--bg-color': r.machine.replace('QUALIDADE: ', '') } as React.CSSProperties} />
                                                )}
                                                <span className="truncate max-w-[180px]">{getCleanLabel(r.machine, r.groupType)}</span>
                                            </div>
                                            <div className="flex items-center gap-2">
                                                <span className="text-[8px] opacity-50 font-bold">{r.cleanedCount}</span>
                                                <ChevronRight className={cn("h-3.5 w-3.5 transition-transform", activeTab === idx ? "translate-x-0.5" : "opacity-0 group-hover:opacity-30")} />
                                            </div>
                                        </button>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* CONTENT */}
                    <div className="flex-1 overflow-y-auto bg-white" ref={scrollContainerRef}>
                        {loading ? (
                            <div className="h-full flex flex-col items-center justify-center gap-6">
                                <Activity className="h-10 w-10 animate-spin text-black" />
                                <p className="font-mono text-[10px] uppercase font-black tracking-widest text-black/60">Processando An├ílise Estat├¡stica...</p>
                            </div>
                        ) : !currentReport ? (
                            <div className="h-full flex items-center justify-center opacity-5"><Binary className="h-32 w-32" /></div>
                        ) : (
                            <div key={activeTab} ref={reportRef} className="p-8 md:p-16 space-y-20 max-w-[1200px] mx-auto">

                                {/* BANNER */}
                                <div className="space-y-8">
                                    <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 border-b-4 border-black pb-8">
                                        <div className="space-y-3">
                                            <div className="flex items-center gap-5">
                                                {activeColor && <div className="h-16 w-4 rounded-sm shadow-lg bg-dynamic" style={{ '--bg-color': activeColor } as React.CSSProperties} />}
                                                <h3 className="text-4xl md:text-6xl font-serif font-black tracking-tighter text-black uppercase italic leading-none">
                                                    {getCleanLabel(currentReport.machine, currentReport.groupType)}
                                                </h3>
                                            </div>
                                            <div className="flex items-center gap-3 ml-1">
                                                <div className="text-[11px] font-mono text-black/50 font-black uppercase tracking-[0.3em]">
                                                    Lote: {samples[0]?.lote_id || 'N/A'} ÔÇó {currentReport.cleanedCount} Amostras V├ílidas
                                                </div>
                                            </div>
                                        </div>
                                        <div className="bg-black text-white p-6 shadow-[8px_8px_0px_rgba(0,0,0,0.08)] border-2 border-black">
                                            <p className="text-[9px] font-mono uppercase tracking-widest opacity-60 mb-1">Confiabilidade Global</p>
                                            <p className="text-4xl font-serif font-black italic leading-none">{Math.round(currentReport.consolidated.globalProbability)}%</p>
                                            <p className="text-[8px] font-mono uppercase opacity-40 mt-1">
                                                {currentReport.consolidated.status === 'OK' ? 'Aprovado' : currentReport.consolidated.status === 'ALERTA' ? 'Aten├º├úo' : 'Cr├¡tico'}
                                            </p>
                                        </div>
                                    </div>

                                    {/* RESUMO EXECUTIVO */}
                                    <div className="border-2 border-black p-6 bg-gradient-to-br from-white to-neutral-50">
                                        <h4 className="text-base font-serif font-black italic uppercase mb-3 flex items-center gap-2">
                                            <div className="h-1 w-8 bg-black" />
                                            Resumo Executivo
                                        </h4>
                                        <p className="text-sm font-mono font-bold leading-relaxed">
                                            {currentReport.cleanedCount > 1
                                                ? `Este segmento foi auditado com base em ${currentReport.cleanedCount} amostras v├ílidas. A an├ílise estat├¡stica indica uma confiabilidade global de ${currentReport.consolidated.globalProbability.toFixed(1)}%, caracterizando o lote como ${currentReport.consolidated.globalProbability > 85 ? 'EXCELENTE para processamento industrial' : currentReport.consolidated.globalProbability > 70 ? 'ADEQUADO com ressalvas t├®cnicas' : 'REQUER ATEN├ç├âO ESPECIAL'}. Os par├ómetros cr├¡ticos apresentam varia├º├úo m├®dia controlada.`
                                                : "An├ílise baseada em amostra ├║nica. Os valores apresentados s├úo medi├º├Áes pontuais e n├úo permitem infer├¬ncia estat├¡stica sobre a variabilidade do lote completo. Recomenda-se an├ílise de amostras adicionais para valida├º├úo."
                                            }
                                        </p>
                                    </div>
                                </div>

                                {/* TABELA T├ëCNICA CONSOLIDADA */}
                                <div className="space-y-4">
                                    <h4 className="text-lg font-serif font-black italic uppercase flex items-center gap-3">
                                        <div className="h-1 w-10 bg-black" />
                                        Par├ómetros T├®cnicos Consolidados
                                    </h4>
                                    <div className="border-2 border-black overflow-hidden shadow-lg">
                                        <table className="w-full">
                                            <thead className="bg-black text-white">
                                                <tr className="text-[10px] font-mono uppercase tracking-wider">
                                                    <th className="p-3 text-left border-r border-white/20">Par├ómetro</th>
                                                    <th className="p-3 text-center border-r border-white/20">M├®dia</th>
                                                    <th className="p-3 text-center border-r border-white/20">Desvio</th>
                                                    <th className="p-3 text-center border-r border-white/20">CV%</th>
                                                    <th className="p-3 text-center border-r border-white/20">Min</th>
                                                    <th className="p-3 text-center">Max</th>
                                                </tr>
                                            </thead>
                                            <tbody className="bg-white">
                                                {currentReport?.parameterAnalyses?.map((analysis: ParameterAnalysis, idx: number) => (
                                                    <tr key={analysis.param} className={cn("border-b border-black/10 hover:bg-neutral-50 transition-colors", idx % 2 === 0 ? "bg-white" : "bg-neutral-50/30")}>
                                                        <td className="p-3 font-serif font-black italic text-base border-r border-black/10">
                                                            {analysis.displayName}
                                                            <div className="text-[9px] font-mono font-normal opacity-50 mt-0.5">{getParamMeaning(analysis.param)}</div>
                                                        </td>
                                                        <td className="p-3 text-center font-mono font-black text-lg border-r border-black/10">{analysis.stats.mean.toFixed(2)}</td>
                                                        <td className="p-3 text-center font-mono text-sm text-neutral-500 border-r border-black/10">{analysis.stats.stdDev.toFixed(3)}</td>
                                                        <td className={cn("p-3 text-center font-mono font-black border-r border-black/10", analysis.stats.cv > 5 ? "text-red-600" : "text-blue-600")}>
                                                            {currentReport.cleanedCount > 1 ? analysis.stats.cv.toFixed(2) + '%' : 'ÔÇö'}
                                                        </td>
                                                        <td className="p-3 text-center font-mono text-sm opacity-60 border-r border-black/10">{analysis.stats.min.toFixed(2)}</td>
                                                        <td className="p-3 text-center font-mono text-sm opacity-60">{analysis.stats.max.toFixed(2)}</td>
                                                    </tr>
                                                )) || []}
                                            </tbody>
                                        </table>
                                    </div>
                                </div>

                                {/* AN├üLISE VISUAL POR PAR├éMETRO */}
                                <div className="space-y-16">
                                    <h4 className="text-lg font-serif font-black italic uppercase flex items-center gap-3">
                                        <div className="h-1 w-10 bg-black" />
                                        An├ílise Visual de Distribui├º├úo
                                    </h4>

                                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                                        {currentReport?.parameterAnalyses?.map((analysis: ParameterAnalysis) => {
                                            const interpretation = getInterpretation(analysis, currentReport.cleanedCount);
                                            return (
                                                <div key={analysis.param} className="border-2 border-black p-6 bg-white shadow-md hover:shadow-xl transition-shadow">
                                                    <div className="flex items-center justify-between mb-4 pb-3 border-b border-black/10">
                                                        <div className="flex items-center gap-3">
                                                            <h5 className="text-xl font-serif font-black italic">{analysis.displayName}</h5>
                                                            <span className={cn("px-2 py-0.5 text-[8px] font-mono font-black uppercase border border-black", interpretation.bg, interpretation.color)}>
                                                                {interpretation.label}
                                                            </span>
                                                        </div>
                                                        <span className="text-2xl font-serif font-black italic">{analysis.stats.mean.toFixed(2)}</span>
                                                    </div>

                                                    <div className="h-32 border border-black/20 bg-neutral-50/50 p-3 flex items-end gap-1 relative mb-3">
                                                        <div className="absolute top-1 left-1 text-[7px] font-mono opacity-20 uppercase font-black">Distribui├º├úo</div>
                                                        {(analysis.distribution || []).map((d: { label: string; value: number; percent: number }, i: number) => (
                                                            <div
                                                                key={i}
                                                                className="flex-1 bg-black/90 hover:bg-black transition-all cursor-pointer relative group h-dynamic"
                                                                style={{ '--dynamic-height': `${d.percent}%` } as React.CSSProperties}
                                                                title={`${d.label}: ${d.percent.toFixed(1)}%`}
                                                            >
                                                                <div className="absolute -top-6 left-1/2 -translate-x-1/2 bg-black text-white text-[7px] px-1 py-0.5 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
                                                                    {d.percent.toFixed(1)}%
                                                                </div>
                                                            </div>
                                                        ))}
                                                    </div>

                                                    <div className="grid grid-cols-3 gap-3 text-center text-[10px] font-mono">
                                                        <div>
                                                            <div className="opacity-40 uppercase mb-0.5">Min</div>
                                                            <div className="font-black">{analysis.stats.min.toFixed(2)}</div>
                                                        </div>
                                                        <div>
                                                            <div className="opacity-40 uppercase mb-0.5">CV%</div>
                                                            <div className={cn("font-black", analysis.stats.cv > 5 ? "text-red-600" : "text-blue-600")}>
                                                                {currentReport.cleanedCount > 1 ? analysis.stats.cv.toFixed(2) + '%' : 'ÔÇö'}
                                                            </div>
                                                        </div>
                                                        <div>
                                                            <div className="opacity-40 uppercase mb-0.5">Max</div>
                                                            <div className="font-black">{analysis.stats.max.toFixed(2)}</div>
                                                        </div>
                                                    </div>
                                                </div>
                                            );
                                        }) || []}
                                    </div>
                                </div>

                                {/* RODAP├ë */}
                                <div className="border-t-4 border-black pt-10 flex flex-col md:flex-row justify-between items-center gap-6 opacity-40">
                                    <div className="flex items-center gap-4">
                                        <div className="h-10 w-10 border-2 border-black flex items-center justify-center font-black text-sm italic bg-black text-white">OR</div>
                                        <div className="flex flex-col">
                                            <span className="text-[10px] font-serif font-black italic uppercase">Laudo T├®cnico Certificado</span>
                                            <span className="text-[8px] font-mono font-black uppercase">Emitido em: {new Date().toLocaleString('pt-BR')}</span>
                                        </div>
                                    </div>
                                    <div className="text-[8px] font-mono font-black uppercase text-right">
                                        ORIGO Intelligence ÔÇó Fiberscan Analytics Engine v4.3
                                    </div>
                                </div>

                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>,
        document.body
    );
}

import { useMemo, useState } from "react";
import type { Sample } from "@/entities/Sample";
import { cn } from "@/lib/utils";
import { formatDecimalBR } from "@/services/ocrExtraction";
import { TrendingUp, Activity, BarChart3, LineChart, AreaChart, CircleDot } from "lucide-react";

interface MovingAverageChartProps {
    samples: Sample[];
    windowSize?: number;
    onSampleHover?: (sampleId: string | null) => void;
}

// Todos os par├ómetros HVI incluindo UNF
const FIELDS = [
    { key: 'mic', label: 'MIC' },
    { key: 'len', label: 'LEN' },
    { key: 'unf', label: 'UNF' },
    { key: 'str', label: 'STR' },
    { key: 'rd', label: 'RD' },
    { key: 'b', label: '+b' },
] as const;

// Tipos de gr├ífico dispon├¡veis
const CHART_TYPES = [
    { key: 'line', label: 'Linhas', icon: LineChart },
    { key: 'area', label: '├ürea', icon: AreaChart },
    { key: 'scatter', label: 'Dispers├úo', icon: CircleDot },
] as const;

// Labels em portugu├¬s sem termos normativos
const COLORS_MAP: Record<string, string> = {
    "#3b82f6": "GRUPO 1",
    "#10b981": "GRUPO 2",
    "#f59e0b": "GRUPO 3",
    "#ef4444": "GRUPO 4",
};

interface ChartSample extends Sample {
    parsedVal: number;
    globalIndex?: number;
}

export default function MovingAverageChart({ samples, windowSize = 3, onSampleHover }: MovingAverageChartProps) {
    const [selectedField, setSelectedField] = useState<typeof FIELDS[number]['key']>('mic');
    const [hoveredSample, setHoveredSample] = useState<ChartSample | null>(null);
    const [chartType, setChartType] = useState<typeof CHART_TYPES[number]['key']>('line');


    // Ordenar amostras por ID para ordem cronol├│gica
    const sortedSamples = useMemo(() =>
        [...samples].sort((a, b) => {
            const idA = parseInt(a.amostra_id.replace(/\D/g, '')) || 0;
            const idB = parseInt(b.amostra_id.replace(/\D/g, '')) || 0;
            return idA - idB;
        }),
        [samples]);

    const chartData = useMemo(() => {
        const fieldKey = selectedField;

        // Parse robusto de dados
        const validSamples = sortedSamples.filter(s => {
            const rawVal = (s as any)[fieldKey];
            let val = rawVal;
            if (typeof rawVal === 'string') {
                val = parseFloat(rawVal.replace(',', '.'));
            }
            return typeof val === 'number' && !isNaN(val) && val > 0;
        }).map(s => ({
            ...s,
            parsedVal: typeof (s as any)[fieldKey] === 'number'
                ? (s as any)[fieldKey]
                : parseFloat(((s as any)[fieldKey] as string).replace(',', '.'))
        })) as ChartSample[];


        if (validSamples.length === 0) return null;

        const values = validSamples.map(s => s.parsedVal);
        const minVal = Math.min(...values);
        const maxVal = Math.max(...values);
        const globalAvg = values.reduce((a, b) => a + b, 0) / values.length;

        // Calcular desvio padr├úo
        const variance = values.reduce((acc, val) => acc + Math.pow(val - globalAvg, 2), 0) / values.length;
        const stdDev = Math.sqrt(variance);

        const margin = (maxVal - minVal) * 0.2 || (maxVal * 0.1) || 1;
        const yMin = Math.max(0, minVal - margin);
        const yMax = maxVal + margin;
        const yRange = yMax - yMin;

        // Dimens├Áes
        const width = 1200;
        const height = 400;
        const padding = { left: 60, right: 40, top: 40, bottom: 60 };

        const chartWidth = width - padding.left - padding.right;
        const chartHeight = height - padding.top - padding.bottom;

        const totalPoints = validSamples.length;
        const stepX = chartWidth / (Math.max(totalPoints - 1, 1));

        // Agrupar dados por cor (S├®ries)
        const series = Object.keys(COLORS_MAP).map(color => {
            const groupSamples = validSamples
                .map((s, i) => ({ ...s, globalIndex: i }))
                .filter(s => s.cor === color);

            if (groupSamples.length === 0) return null;

            // Estat├¡sticas do GRUPO
            const groupValues = groupSamples.map(s => s.parsedVal);
            const groupAvg = groupValues.reduce((a, b) => a + b, 0) / groupValues.length;
            const groupVariance = groupValues.reduce((acc, val) => acc + Math.pow(val - groupAvg, 2), 0) / groupValues.length;
            const groupStdDev = Math.sqrt(groupVariance);

            // Coordenadas baseadas no ├¡ndice GLOBAL
            const points = groupSamples.map((s) => {
                const x = padding.left + (s.globalIndex * stepX);
                const y = padding.top + chartHeight - ((s.parsedVal - yMin) / yRange) * chartHeight;
                // Detectar outliers (>1.5¤â DO GRUPO)
                const isOutlier = Math.abs(s.parsedVal - groupAvg) > 1.5 * groupStdDev;
                return { x, y, val: s.parsedVal, original: s, color, isOutlier };
            });

            // Path conectando APENAS estes pontos
            const path = points.length > 1
                ? `M ${points[0].x},${points[0].y} ` + points.slice(1).map(p => `L ${p.x},${p.y}`).join(" ")
                : null;

            return { color, points, path };
        }).filter(s => s !== null);

        // Linhas de grade baseadas nos valores reais
        const gridValues = [
            minVal,
            minVal + (maxVal - minVal) * 0.25,
            minVal + (maxVal - minVal) * 0.5,
            minVal + (maxVal - minVal) * 0.75,
            maxVal
        ];

        const gridLines = gridValues.map((val) => {
            const y = padding.top + chartHeight - ((val - yMin) / yRange) * chartHeight;
            return { y, val };
        });

        // Labels do eixo X
        // Labels do eixo X - Mostrar todos se tiver poucas amostras, sen├úo pular alguns
        const labelInterval = totalPoints <= 30 ? 1 : Math.ceil(totalPoints / 15);
        const xLabels = validSamples
            .map((s, i) => ({ s, i }))
            .filter(({ i }) => i % labelInterval === 0)
            .map(({ s, i }) => ({
                x: padding.left + (i * stepX),
                label: s.amostra_id.length > 2 ? s.amostra_id : `#${s.amostra_id}`
            }));

        const globalAvgY = padding.top + chartHeight - ((globalAvg - yMin) / yRange) * chartHeight;

        // Banda de desvio padr├úo
        const stdDevUpperY = padding.top + chartHeight - ((globalAvg + stdDev - yMin) / yRange) * chartHeight;
        const stdDevLowerY = padding.top + chartHeight - ((globalAvg - stdDev - yMin) / yRange) * chartHeight;

        return {
            series,
            gridLines,
            xLabels,
            globalAvg,
            globalAvgY,
            width,
            height,
            yMin,
            yMax,
            padding,
            stdDev,
            stdDevUpperY,
            stdDevLowerY
        };

    }, [sortedSamples, selectedField, windowSize]);

    if (!chartData || chartData.series.length === 0) return (
        <div className="w-full h-64 flex flex-col items-center justify-center bg-neutral-50 rounded-none border border-neutral-200">
            <BarChart3 className="h-8 w-8 text-neutral-300 mb-2" />
            <span className="text-xs font-bold uppercase tracking-widest text-neutral-400">Aguardando Dados...</span>
        </div>
    );

    return (
        <div className="w-full bg-white border border-black p-8 animate-fade-in relative flex flex-col gap-8 shadow-[8px_8px_0px_rgba(0,0,0,1)]">

            {/* Cabe├ºalho Unificado */}
            <div className="space-y-6">
                {/* Linha 1: T├¡tulo e Status */}
                <div className="flex flex-col md:flex-row md:items-end justify-between gap-4 border-b border-black pb-4">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-black text-white">
                            <TrendingUp className="h-5 w-5" />
                        </div>
                        <div>
                            <h3 className="text-sm font-black text-black uppercase tracking-widest leading-none mb-1">
                                An├ílise de Tend├¬ncia
                            </h3>
                            <p className="text-[10px] text-neutral-500 font-medium">
                                Visualiza├º├úo temporal de indicadores de qualidade
                            </p>
                        </div>
                    </div>

                    <div className="flex items-center gap-6 text-[10px] bg-neutral-50 px-4 py-2 rounded-lg border border-neutral-100">
                        <div className="flex flex-col items-end">
                            <span className="text-neutral-400 uppercase tracking-widest text-[9px]">M├®dia Global</span>
                            <strong className="text-black text-sm font-mono">{formatDecimalBR(chartData.globalAvg, 2)}</strong>
                        </div>
                        <div className="w-px h-8 bg-neutral-200"></div>
                        <div className="flex flex-col items-end">
                            <span className="text-neutral-400 uppercase tracking-widest text-[9px]">Desvio Padr├úo</span>
                            <strong className="text-black text-sm font-mono">{formatDecimalBR(chartData.stdDev, 2)}</strong>
                        </div>
                    </div>
                </div>

                {/* Linha 2: Barra de Controle (Par├ómetros + Tipo de Gr├ífico + Legenda) */}
                <div className="flex flex-col xl:flex-row items-center justify-between gap-4 bg-neutral-50 p-2 rounded-xl border border-neutral-200">

                    {/* Grupo Esquerda: Par├ómetros */}
                    <div className="flex items-center gap-1 overflow-x-auto w-full xl:w-auto p-1">
                        {FIELDS.map(f => (
                            <button
                                key={f.key}
                                onClick={() => setSelectedField(f.key as any)}
                                className={cn(
                                    "px-4 py-2 text-[10px] font-bold uppercase tracking-widest transition-all rounded-lg whitespace-nowrap flex-1 md:flex-none text-center",
                                    selectedField === f.key
                                        ? "bg-black text-white shadow-md"
                                        : "text-neutral-500 hover:bg-white hover:text-black hover:shadow-sm"
                                )}
                            >
                                {f.label}
                            </button>
                        ))}
                    </div>

                    {/* Divisor Responsivo */}
                    <div className="hidden xl:block w-px h-8 bg-neutral-300"></div>

                    {/* Grupo Direita: Legenda e Tipos */}
                    <div className="flex flex-wrap items-center justify-center gap-4 w-full xl:w-auto">

                        {/* Legenda Compacta */}
                        <div className="flex items-center gap-2 pr-4 border-r border-neutral-300">
                            <div className="flex -space-x-1">
                                <div className="w-3 h-3 rounded-full bg-[#10b981] border border-white"></div>
                                <div className="w-3 h-3 rounded-full bg-[#3b82f6] border border-white"></div>
                                <div className="w-3 h-3 rounded-full bg-[#f59e0b] border border-white"></div>
                                <div className="w-3 h-3 rounded-full bg-[#ef4444] border border-white"></div>
                            </div>
                            <span className="text-[9px] font-bold uppercase text-neutral-400 tracking-wider">Grupos 1-4</span>
                        </div>

                        {/* Seletor de Tipo */}
                        <div className="flex items-center bg-white rounded-lg p-1 border border-neutral-200 shadow-sm">
                            {CHART_TYPES.map(type => {
                                const Icon = type.icon;
                                return (
                                    <button
                                        key={type.key}
                                        onClick={() => setChartType(type.key)}
                                        title={type.label}
                                        className={cn(
                                            "p-2 rounded-md transition-all",
                                            chartType === type.key
                                                ? "bg-neutral-100 text-black mx-1"
                                                : "text-neutral-400 hover:text-black"
                                        )}
                                    >
                                        <Icon className="h-4 w-4" />
                                    </button>
                                );
                            })}
                        </div>
                    </div>
                </div>
            </div>


            <div className="flex flex-col lg:flex-row gap-8">
                {/* ├ürea do Gr├ífico */}
                <div className="relative flex-1 min-h-[350px] bg-neutral-50/30 border border-neutral-100 group rounded-xl">
                    <svg id="trend-chart-svg" viewBox={`0 0 ${chartData.width} ${chartData.height}`} className="w-full h-full overflow-visible">

                        {/* Banda de Desvio Padr├úo */}
                        <rect
                            x={chartData.padding.left}
                            y={chartData.stdDevUpperY}
                            width={chartData.width - chartData.padding.left - chartData.padding.right}
                            height={chartData.stdDevLowerY - chartData.stdDevUpperY}
                            fill="#f0f0f0"
                            opacity="0.5"
                        />

                        {/* Grade e Eixo Y */}
                        {chartData.gridLines.map((line, i) => (
                            <g key={i}>
                                <line
                                    x1={chartData.padding.left}
                                    y1={line.y}
                                    x2={chartData.width - chartData.padding.right}
                                    y2={line.y}
                                    stroke="#e5e5e5"
                                    strokeWidth="1"
                                    strokeDasharray="4 4"
                                />
                                <text
                                    x={chartData.padding.left - 12}
                                    y={line.y + 6}
                                    textAnchor="end"
                                    className="fill-neutral-900 font-mono font-black"
                                    style={{ fontSize: '16px' }}
                                >
                                    {formatDecimalBR(line.val, 1)}
                                </text>
                            </g>
                        ))}

                        {/* Linha de M├®dia Global */}
                        <line
                            x1={chartData.padding.left}
                            y1={chartData.globalAvgY}
                            x2={chartData.width - chartData.padding.right}
                            y2={chartData.globalAvgY}
                            stroke="black"
                            strokeWidth="1"
                            strokeDasharray="2 2"
                            opacity="0.3"
                        />
                        <text x={chartData.width - chartData.padding.right + 5} y={chartData.globalAvgY + 4} className="text-[9px] fill-black font-mono font-bold opacity-50">M├ëDIA</text>

                        {/* Paths e Pontos das S├®ries - RENDERIZA├ç├âO CONDICIONAL */}
                        {chartData.series.map((s, i) => (
                            <g key={s.color}>

                                {/* GR├üFICO DE ├üREA */}
                                {chartType === 'area' && s.path && (
                                    <>
                                        <path
                                            d={`${s.path} L ${s.points[s.points.length - 1].x},${chartData.height - chartData.padding.bottom} L ${s.points[0].x},${chartData.height - chartData.padding.bottom} Z`}
                                            fill={s.color}
                                            opacity="0.2"
                                        />
                                        <path
                                            d={s.path}
                                            fill="none"
                                            stroke={s.color}
                                            strokeWidth="2"
                                            strokeLinecap="round"
                                            strokeLinejoin="round"
                                            opacity="0.8"
                                        />
                                    </>
                                )}

                                {/* GR├üFICO DE LINHAS */}
                                {chartType === 'line' && s.path && (
                                    <path
                                        d={s.path}
                                        fill="none"
                                        stroke={s.color}
                                        strokeWidth="2.5"
                                        strokeLinecap="round"
                                        strokeLinejoin="round"
                                        className="opacity-90"
                                    />
                                )}

                                {/* GR├üFICO DE DISPERS├âO */}
                                {chartType === 'scatter' && s.points.map((p, idx) => (
                                    <circle
                                        key={`scatter-${i}-${idx}`}
                                        cx={p.x}
                                        cy={p.y}
                                        r="5"
                                        fill={p.isOutlier ? "#ef4444" : s.color}
                                        opacity="0.7"
                                        className="pointer-events-none"
                                    />
                                ))}

                                {/* PONTOS DE DADOS - Comum a ambos */}
                                {s.points.map((p, idx) => (
                                    <g key={`${i}-${idx}`}>
                                        <circle
                                            cx={p.x}
                                            cy={p.y}
                                            r="8"
                                            fill="transparent"
                                            className="hover:cursor-pointer z-10"
                                            onMouseEnter={() => {
                                                setHoveredSample(p.original);
                                                if (onSampleHover) onSampleHover(p.original.id);
                                            }}
                                            onClick={() => {
                                                if (hoveredSample?.id === p.original.id) {
                                                    setHoveredSample(null);
                                                    if (onSampleHover) onSampleHover(null);
                                                } else {
                                                    setHoveredSample(p.original);
                                                    if (onSampleHover) onSampleHover(p.original.id);
                                                }
                                            }}
                                        />
                                        {/* Destaque de Outlier */}
                                        {p.isOutlier && (
                                            <circle
                                                cx={p.x}
                                                cy={p.y}
                                                r="10"
                                                fill="none"
                                                stroke="#ef4444"
                                                strokeWidth="2"
                                                strokeDasharray="2 2"
                                                className="animate-pulse"
                                            />
                                        )}
                                        <circle
                                            cx={p.x}
                                            cy={p.y}
                                            r="4"
                                            fill={p.isOutlier ? "#ef4444" : (chartType === 'area' ? s.color : "white")}
                                            stroke={chartType === 'area' ? "white" : s.color}
                                            strokeWidth="2.5"
                                            className="pointer-events-none transition-all"
                                        />
                                    </g>
                                ))}
                            </g>
                        ))}


                        {/* Anel de Destaque ao Hover - Est├ítico e Discreto */}
                        {hoveredSample && (
                            <circle
                                cx={(chartData.series.flatMap(s => s.points).find(p => p.original.id === hoveredSample.id))?.x || 0}
                                cy={(chartData.series.flatMap(s => s.points).find(p => p.original.id === hoveredSample.id))?.y || 0}
                                r="6"
                                fill="white"
                                stroke="black"
                                strokeWidth="2"
                                className="z-20 shadow-sm"
                            />
                        )}


                        {/* Labels do Eixo X */}
                        {chartData.xLabels.map((lbl, i) => (
                            <text
                                key={i}
                                x={lbl.x}
                                y={chartData.height - 10}
                                textAnchor="middle"
                                className="fill-neutral-900 font-mono font-bold"
                                style={{ fontSize: '12px' }}
                            >
                                {lbl.label}
                            </text>
                        ))}
                    </svg>

                    {/* Legenda */}
                    <div className="absolute bottom-2 left-16 flex items-center gap-4 text-[9px]">
                        <div className="flex items-center gap-1">
                            <div className="w-3 h-3 bg-neutral-200 opacity-50"></div>
                            <span className="text-neutral-500">Banda ┬▒1¤â</span>
                        </div>
                        <div className="flex items-center gap-1">
                            <div className="w-3 h-3 rounded-full border-2 border-red-500 border-dashed"></div>
                            <span className="text-red-500">Outlier (&gt;2¤â)</span>
                        </div>
                    </div>
                </div>

                {/* Painel de Detalhes */}
                <div className="w-full lg:w-64 min-h-[200px] border-l border-neutral-100 pl-0 lg:pl-10 flex flex-col gap-6">
                    <div className="flex items-center gap-2 border-b border-black pb-2 justify-between">
                        <div className="flex items-center gap-2">
                            <Activity className="h-4 w-4 text-black" />
                            <h4 className="text-xs font-bold uppercase tracking-widest">Inspetor</h4>
                        </div>
                        {hoveredSample && (
                            <button
                                onClick={() => setHoveredSample(null)}
                                className="text-[9px] font-bold text-neutral-400 hover:text-black uppercase tracking-tighter"
                            >
                                [ Desselecionar ]
                            </button>
                        )}
                    </div>

                    {hoveredSample ? (
                        <div className="space-y-6 animate-slide-up">
                            <div className="space-y-1">
                                <span className="text-[9px] text-neutral-400 uppercase tracking-widest block">Amostra Selecionada</span>
                                <div className="flex items-baseline gap-2">
                                    <span className="text-4xl font-mono font-black tracking-tighter">#{hoveredSample.amostra_id}</span>
                                    <span className="text-[10px] uppercase font-bold text-neutral-400 max-w-[100px] truncate">{hoveredSample.mala || 'Sem Mala'}</span>
                                </div>
                            </div>

                            <div className="space-y-2">
                                <span className="text-[9px] text-neutral-400 uppercase tracking-widest block">M├®trica Principal ({selectedField.toUpperCase()})</span>
                                <div className="flex items-center gap-3">
                                    <span className="text-3xl font-mono font-bold border-b-2 border-black">
                                        {formatDecimalBR(hoveredSample.parsedVal || 0, 2)}
                                    </span>
                                    <div className={`px-2 py-1 rounded text-[10px] font-bold uppercase text-white`} style={{ backgroundColor: hoveredSample.cor || '#000' }}>
                                        {COLORS_MAP[hoveredSample.cor || ''] || 'S/COR'}
                                    </div>
                                </div>
                            </div>

                            <div className="p-4 bg-neutral-50 border border-neutral-200 space-y-3">
                                <span className="text-[9px] text-neutral-400 uppercase tracking-widest block border-b border-neutral-200 pb-1">Dados Contextuais</span>
                                <div className="grid grid-cols-2 gap-y-2 gap-x-4 text-[10px] font-mono">
                                    <div className="flex justify-between items-center text-neutral-600">
                                        <span>MIC</span>
                                        <span className={selectedField === 'mic' ? 'font-bold text-black' : ''}>{formatDecimalBR(hoveredSample.mic || 0, 2)}</span>
                                    </div>
                                    <div className="flex justify-between items-center text-neutral-600">
                                        <span>LEN</span>
                                        <span className={selectedField === 'len' ? 'font-bold text-black' : ''}>{formatDecimalBR(hoveredSample.len || 0, 2)}</span>
                                    </div>
                                    <div className="flex justify-between items-center text-neutral-600">
                                        <span>UNF</span>
                                        <span className={selectedField === 'unf' ? 'font-bold text-black' : ''}>{formatDecimalBR(hoveredSample.unf || 0, 1)}</span>
                                    </div>
                                    <div className="flex justify-between items-center text-neutral-600">
                                        <span>STR</span>
                                        <span className={selectedField === 'str' ? 'font-bold text-black' : ''}>{formatDecimalBR(hoveredSample.str || 0, 1)}</span>
                                    </div>
                                    <div className="flex justify-between items-center text-neutral-600">
                                        <span>RD</span>
                                        <span className={selectedField === 'rd' ? 'font-bold text-black' : ''}>{formatDecimalBR(hoveredSample.rd || 0, 1)}</span>
                                    </div>
                                    <div className="flex justify-between items-center text-neutral-600">
                                        <span>+b</span>
                                        <span className={selectedField === 'b' ? 'font-bold text-black' : ''}>{formatDecimalBR(hoveredSample.b || 0, 1)}</span>
                                    </div>
                                </div>
                            </div>
                        </div>
                    ) : (
                        <div className="flex-1 flex flex-col items-center justify-center text-center opacity-40 space-y-4">
                            <div className="w-16 h-16 bg-neutral-100 rounded-full flex items-center justify-center">
                                <Activity className="h-6 w-6 text-neutral-400" />
                            </div>
                            <p className="text-[10px] uppercase font-bold text-neutral-500 max-w-[150px] leading-relaxed">
                                Passe o mouse sobre qualquer ponto para ver os dados HVI
                            </p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

import { useState } from "react";
import { createPortal } from "react-dom";
import { type Sample } from "@/entities/Sample";
import { X, Bot, Loader2, BarChart3, TrendingUp } from "lucide-react";
import { Button } from "@/components/ui/button";
import { DeepSeekService } from "@/services/DeepSeekService";

interface PatternAnalysisModalProps {
    isOpen: boolean;
    onClose: () => void;
    samples: Sample[];
    onApplyColors: (updates: Record<string, string>) => void;
}

interface Group {
    id: string;
    label?: string;
    micAvg: number;
    lenAvg: number;
    unfAvg: number;
    strAvg: number;
    rdAvg: number;
    bAvg: number;
    count: number;
    sampleIds: string[];
    color: string | null;
    patternFeatures?: string[];
}

export default function PatternAnalysisModal({ isOpen, onClose, samples, onApplyColors }: PatternAnalysisModalProps) {
    const [groups, setGroups] = useState<Group[]>([]);
    const [scanned, setScanned] = useState(false);

    // AI Report State
    const [aiAnalysis, setAiAnalysis] = useState("");
    const [isAiLoading, setIsAiLoading] = useState(false);
    const [isScanning, setIsScanning] = useState(false);

    // An├ílise de Padr├Áes Estat├¡sticos
    const runAnalysis = () => {
        setScanned(false);
        setIsScanning(true);

        setTimeout(() => {
            try {
                const result = DeepSeekService.classifySamplesSmart(samples);
                setGroups(result);
            } catch (error) {
                console.error("Erro na identifica├º├úo de padr├Áes:", error);
            }
            setScanned(true);
            setIsScanning(false);
        }, 1000);
    };

    const handleGenerateReport = async () => {
        setIsAiLoading(true);
        try {
            const analysis = await DeepSeekService.analyzeSamples(samples);
            setAiAnalysis(analysis);
        } catch (error) {
            setAiAnalysis("Erro ao gerar relat├│rio descritivo.");
        } finally {
            setIsAiLoading(false);
        }
    };

    const handleApply = () => {
        const updates: Record<string, string> = {};

        // Aplicar cores de todos os grupos
        groups.forEach(group => {
            if (group.color) {
                group.sampleIds.forEach(id => {
                    updates[id] = group.color as string;
                });
            }
        });

        onApplyColors(updates);
        onClose();
    };

    if (!isOpen) return null;

    return createPortal(
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={onClose} />

            <div className="relative w-full max-w-5xl max-h-[90vh] bg-white text-black flex flex-col shadow-2xl animate-fade-in border border-black">
                {/* Header */}
                <div className="flex items-center justify-between p-8 border-b border-black">
                    <div className="space-y-1">
                        <h2 className="text-2xl font-serif leading-none flex items-center gap-3">
                            Analista Inteligente
                            <span className="text-sm bg-neutral-100 text-neutral-800 px-2 py-0.5 rounded font-mono font-bold">PADR├òES</span>
                        </h2>
                        <p className="text-[10px] font-bold uppercase tracking-widest text-neutral-400">
                            Identifica├º├úo Estat├¡stica de Padr├Áes Laboratoriais HVI
                        </p>
                    </div>
                    <div className="flex items-center gap-2">
                        <button onClick={onClose} className="p-2 hover:bg-neutral-100 rounded-full" title="Fechar" aria-label="Fechar">
                            <X className="h-5 w-5" />
                        </button>
                    </div>
                </div>

                {/* Content */}
                <div className="flex-1 overflow-y-auto p-8 bg-neutral-50/50">

                    {!scanned ? (
                        <div className="h-full flex flex-col items-center justify-center space-y-6 py-12">
                            <div className={`w-20 h-20 bg-neutral-100 border border-neutral-200 flex items-center justify-center rounded-full ${isScanning ? 'animate-spin' : 'animate-pulse'}`}>
                                {isScanning ? (
                                    <Loader2 className="h-8 w-8 text-black" />
                                ) : (
                                    <BarChart3 className="h-8 w-8 text-black" />
                                )}
                            </div>
                            <div className="text-center space-y-2">
                                <h3 className="text-lg font-bold">Iniciar Identifica├º├úo de Padr├Áes</h3>
                                <p className="text-sm text-neutral-500 max-w-lg mx-auto">
                                    O Analista Inteligente identificar├í padr├Áes estat├¡sticos e agrupar├í
                                    <strong> todas as {samples.length} amostras</strong> por comportamento semelhante.
                                    <br /><br />
                                    <span className="text-xs text-neutral-400">
                                        An├ílise puramente descritiva ÔÇö Sem aplica├º├úo de normas ou toler├óncias.
                                    </span>
                                </p>
                            </div>
                            <Button
                                onClick={runAnalysis}
                                disabled={isScanning}
                                className="px-8 h-12 bg-black text-white hover:bg-neutral-800 uppercase tracking-widest text-xs font-bold rounded-none shadow-lg"
                            >
                                {isScanning ? "Analisando..." : "Identificar Padr├Áes"}
                            </Button>
                        </div>
                    ) : (
                        <div className="space-y-8">
                            {/* Header dos Resultados */}
                            <div className="flex items-center justify-between">
                                <h3 className="text-sm font-bold uppercase tracking-widest flex items-center gap-2">
                                    <div className="w-2 h-2 bg-blue-500 rounded-full animate-pulse" />
                                    Agrupamentos Identificados
                                    <span className="text-neutral-400 font-normal ml-2">
                                        ({groups.reduce((acc, g) => acc + g.count, 0)} amostras = 100%)
                                    </span>
                                </h3>
                                <Button
                                    variant="outline"
                                    size="sm"
                                    onClick={runAnalysis}
                                    className="h-8 text-[10px] uppercase font-bold border-black hover:bg-neutral-50 rounded-none bg-white"
                                >
                                    Reanalisar
                                </Button>
                            </div>

                            {groups.length === 0 ? (
                                <div className="text-center py-12 border-2 border-dashed border-neutral-300 bg-white">
                                    <p className="text-neutral-400 text-xs font-bold uppercase tracking-widest">
                                        Nenhum padr├úo estat├¡stico identificado nos dados dispon├¡veis
                                    </p>
                                </div>
                            ) : (
                                <div className="grid gap-4">
                                    {groups.map((group) => {
                                        const features = group.patternFeatures || [];

                                        return (
                                            <div key={group.id}
                                                className="bg-white border-l-4 p-5 flex flex-col md:flex-row items-start md:items-center justify-between gap-6 shadow-sm hover:shadow-md transition-all"
                                                ref={(el) => {
                                                    if (el) {
                                                        const c = group.color || '#000';
                                                        el.style.borderLeftColor = c;
                                                        el.style.setProperty('--group-color', c);
                                                    }
                                                }}
                                            >
                                                {/* Estat├¡sticas do Grupo */}
                                                <div className="flex items-center gap-6 flex-1">
                                                    <div
                                                        className="h-14 w-14 flex-shrink-0 text-white flex flex-col items-center justify-center font-mono font-bold leading-none rounded-lg shadow-sm bg-[var(--group-color)]"
                                                    >
                                                        <span className="text-xl">{group.count}</span>
                                                        <span className="text-[8px] opacity-80 uppercase">Obs.</span>
                                                    </div>
                                                    <div className="space-y-3 flex-1">
                                                        <div className="flex flex-col md:flex-row md:items-center gap-3">
                                                            <span className="text-xs uppercase font-bold tracking-widest text-black flex items-center gap-2 min-w-fit">
                                                                <TrendingUp className="h-3 w-3" />
                                                                {group.label || group.id}
                                                            </span>

                                                            {/* Tags de Caracter├¡sticas do Padr├úo */}
                                                            <div className="flex flex-wrap gap-2">
                                                                {features.map((feature, i) => (
                                                                    <span key={i} className="px-2 py-1 rounded text-[10px] font-bold uppercase tracking-wider bg-neutral-100 text-neutral-700 ring-1 ring-neutral-200">
                                                                        {feature}
                                                                    </span>
                                                                ))}
                                                            </div>
                                                        </div>

                                                        {/* Grid de Estat├¡sticas */}
                                                        <div className="grid grid-cols-6 gap-4 text-xs font-mono border-t border-neutral-100 pt-2 text-neutral-600">
                                                            <div className="text-center">
                                                                <span className="text-[8px] text-neutral-400 block mb-0.5">MIC</span>
                                                                <b>{(group.micAvg || 0).toFixed(2)}</b>
                                                            </div>
                                                            <div className="text-center">
                                                                <span className="text-[8px] text-neutral-400 block mb-0.5">LEN</span>
                                                                <b>{(group.lenAvg || 0).toFixed(2)}</b>
                                                            </div>
                                                            <div className="text-center">
                                                                <span className="text-[8px] text-neutral-400 block mb-0.5">STR</span>
                                                                <b>{(group.strAvg || 0).toFixed(1)}</b>
                                                            </div>
                                                            <div className="text-center">
                                                                <span className="text-[8px] text-neutral-400 block mb-0.5">RD</span>
                                                                <b>{(group.rdAvg || 0).toFixed(1)}</b>
                                                            </div>
                                                            <div className="text-center">
                                                                <span className="text-[8px] text-neutral-400 block mb-0.5">+B</span>
                                                                <b>{(group.bAvg || 0).toFixed(1)}</b>
                                                            </div>
                                                            <div className="text-center">
                                                                <span className="text-[8px] text-neutral-400 block mb-0.5">UNF</span>
                                                                <b>{(group.unfAvg || 0).toFixed(1)}</b>
                                                            </div>
                                                        </div>
                                                    </div>
                                                </div>

                                                {/* Badge de Identifica├º├úo */}
                                                <div className="hidden md:flex flex-col items-end gap-1">
                                                    <span className="text-[9px] uppercase font-bold text-neutral-400 tracking-widest">Padr├úo</span>
                                                    <div
                                                        className="px-3 py-1 rounded bg-neutral-100 text-xs font-bold uppercase tracking-wider text-right shadow-sm border border-neutral-200"
                                                        ref={(el) => { if (el) el.style.color = group.color || '#000'; }}
                                                    >
                                                        {group.id}
                                                    </div>
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                            )}

                            {/* Se├º├úo de Relat├│rio Descritivo */}
                            <div className="pt-8 border-t border-neutral-200 mt-8">
                                <div className="flex items-center justify-between mb-6">
                                    <div>
                                        <h3 className="font-bold text-lg">Relat├│rio Descritivo Completo</h3>
                                        <p className="text-[10px] uppercase tracking-widest text-neutral-400">
                                            An├ílise estat├¡stica detalhada ÔÇö Sem crit├®rios normativos
                                        </p>
                                    </div>
                                    {!aiAnalysis && (
                                        <Button
                                            onClick={handleGenerateReport}
                                            disabled={isAiLoading}
                                            variant="outline"
                                            className="h-10 px-6 uppercase text-xs font-bold tracking-widest border-black text-black hover:bg-black hover:text-white transition-colors"
                                        >
                                            {isAiLoading ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <Bot className="w-4 h-4 mr-2" />}
                                            <span>{isAiLoading ? "Gerando..." : "Gerar Relat├│rio"}</span>
                                        </Button>
                                    )}
                                </div>
                                {aiAnalysis && (
                                    <div className="bg-white p-8 border border-neutral-200 shadow-sm font-mono text-xs leading-relaxed border-l-4 border-l-black animate-in fade-in slide-in-from-bottom-2 duration-500 max-h-96 overflow-y-auto">
                                        <pre className="whitespace-pre-wrap">{aiAnalysis}</pre>
                                    </div>
                                )}
                            </div>
                        </div>
                    )}
                </div>

                {/* Footer */}
                {scanned && (
                    <div className="p-8 border-t border-black bg-white flex justify-between items-center">
                        <p className="text-[10px] font-mono font-bold text-neutral-400 uppercase tracking-widest">
                            {groups.reduce((acc, g) => acc + g.count, 0)} Observa├º├Áes em {groups.length} Grupos
                        </p>
                        <div className="flex gap-4">
                            <Button
                                variant="ghost"
                                onClick={onClose}
                                className="h-12 px-6 rounded-none uppercase text-xs font-bold tracking-widest hover:bg-neutral-100"
                            >
                                Cancelar
                            </Button>
                            <Button
                                onClick={handleApply}
                                disabled={groups.length === 0}
                                className="h-12 px-8 bg-black text-white hover:bg-neutral-800 rounded-none uppercase text-xs font-bold tracking-widest disabled:opacity-50 shadow-xl"
                            >
                                Aprovar e Aplicar Cores
                            </Button>
                        </div>
                    </div>
                )}
            </div>
        </div>,
        document.body
    );
}

import { useEffect, useMemo, useState } from "react";
import * as Lucide from "lucide-react";
import { cn } from "@/lib/utils";
import { supabase } from "@/lib/supabase";
import { useAuth } from "@/contexts/AuthContext";
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip as RechartsTooltip, ResponsiveContainer, ReferenceLine } from 'recharts';

export const formatName = (name: string) => {
    return name.replace(/Linha\/Mq/gi, "MAQ").replace(/LINHA\/MQ/gi, "MAQ");
};

const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
        return (
            <div className="bg-white/95 backdrop-blur-sm border border-neutral-200 p-4 shadow-2xl rounded-xl animate-in fade-in zoom-in duration-200">
                <p className="text-[10px] font-bold uppercase tracking-widest text-neutral-400 mb-2 border-b border-neutral-100 pb-1">{label}</p>
                <div className="space-y-1.5">
                    {payload.map((entry: any, index: number) => (
                        <div key={`${entry.name}-${index}`} className="flex items-center justify-between gap-8">
                            <div className="flex items-center gap-2">
                                <div className="h-2 w-2 rounded-full shadow-sm bg-dynamic" style={{ '--bg-color': entry.stroke || entry.color } as React.CSSProperties} />
                                <span className="text-[11px] font-medium text-neutral-600 uppercase pt-0.5">{entry.name}</span>
                            </div>
                            <span className="text-[11px] font-mono font-bold text-black">{Number(entry.value).toLocaleString('pt-BR')}</span>
                        </div>
                    ))}
                </div>
            </div>
        );
    }
    return null;
};

interface ProductionData {
    id?: string;
    data_producao: string;
    turno: string;
    peso: number;
    produto?: string;
    offset_peso?: number;
}

interface ProductionTrendChartProps {
    data: ProductionData[];
}

interface SHIFT_CONFIG {
    hex: string;
    bg: string;
    text: string;
}

const SHIFT_COLORS_CONFIG: Record<string, SHIFT_CONFIG> = {
    "TURNO 1": { hex: "#1d4ed8", bg: "bg-blue-700", text: "text-blue-700" },
    "TURNO 2": { hex: "#047857", bg: "bg-emerald-700", text: "text-emerald-700" },
    "TURNO 3": { hex: "#b45309", bg: "bg-amber-700", text: "text-amber-700" },
    "GERAL": { hex: "#4b5563", bg: "bg-gray-600", text: "text-gray-600" },
    "TOTAL DIA": { hex: "#000000", bg: "bg-black", text: "text-black" }
};

const MACHINE_COLORS_CONFIG: SHIFT_CONFIG[] = [
    { hex: "#dc2626", bg: "bg-red-600", text: "text-red-600" },
    { hex: "#ea580c", bg: "bg-orange-600", text: "text-orange-600" },
    { hex: "#ca8a04", bg: "bg-yellow-600", text: "text-yellow-600" },
    { hex: "#65a30d", bg: "bg-lime-600", text: "text-lime-600" },
    { hex: "#0d9488", bg: "bg-teal-600", text: "text-teal-600" },
    { hex: "#0891b2", bg: "bg-cyan-600", text: "text-cyan-600" },
    { hex: "#4f46e5", bg: "bg-indigo-600", text: "text-indigo-600" },
    { hex: "#c026d3", bg: "bg-fuchsia-600", text: "text-fuchsia-600" },
    { hex: "#e11d48", bg: "bg-rose-600", text: "text-rose-600" },
    { hex: "#7c3aed", bg: "bg-violet-600", text: "text-violet-600" }
];

interface ChartPoint {
    date: string;
    val: number;
    id: string;
    type: string;
}

export default function ProductionTrendChart({ data }: ProductionTrendChartProps) {
    const { currentLab, user } = useAuth();
    const labId = currentLab?.id || user?.lab_id;

    type ViewMode = 'general' | 'detailed' | 'machine_comparison' | 'compare_machines_total';
    const [viewMode, setViewMode] = useState<ViewMode>('general');
    const [selectedShift, setSelectedShift] = useState<string>("TURNO 1");
    const [selectedMachine, setSelectedMachine] = useState<string>("");

    const [dateStart, setDateStart] = useState<string>('');
    const [dateEnd, setDateEnd] = useState<string>('');

    const [targetValue, setTargetValue] = useState<number | null>(null);
    const [isSavingTarget, setIsSavingTarget] = useState(false);
    const [showTargetLine, setShowTargetLine] = useState(false);
    const [showMovingAverage, setShowMovingAverage] = useState(false);
    const [granularity, setGranularity] = useState<'day' | 'week' | 'month'>('day');

    useEffect(() => {
        const loadTarget = async () => {
            if (!labId || labId === 'all') return;
            try {
                const { data: config, error } = await supabase
                    .from('operacao_producao_config')
                    .select('meta_producao')
                    .eq('lab_id', labId)
                    .maybeSingle();

                if (!error && config?.meta_producao) {
                    setTargetValue(config.meta_producao);
                    setShowTargetLine(true);
                }
            } catch (e) {
                // Ignore silent errors if table doesn't exist yet
            }
        };
        loadTarget();
    }, [labId]);

    const saveTargetToDB = async (val: number) => {
        if (!labId) return;
        setIsSavingTarget(true);
        try {
            await supabase
                .from('operacao_producao_config')
                .upsert({
                    lab_id: labId,
                    meta_producao: val,
                    updated_at: new Date().toISOString()
                }, { onConflict: 'lab_id' });
        } catch (e) {
            console.error("Erro ao salvar meta:", e);
        } finally {
            setIsSavingTarget(false);
        }
    };



    const availableShifts = useMemo(() => Array.from(new Set(data.map(d => d.turno))).sort(), [data]);
    const availableMachines = useMemo(() => {
        const productSums: Record<string, number> = {};
        data.forEach(d => {
            const name = d.produto || "Desconhecido";
            productSums[name] = (productSums[name] || 0) + (d.peso || 0);
        });
        return Array.from(new Set(data.map(d => d.produto || "Desconhecido")))
            .filter(m => productSums[m] > 0)
            .sort();
    }, [data]);

    useEffect(() => {
        if (!selectedMachine && availableMachines.length > 0) {
            setSelectedMachine(availableMachines[0]);
        }
    }, [availableMachines, selectedMachine]);

    const filteredData = useMemo(() => {
        if (data.length === 0) return [];
        if (!dateStart || !dateEnd) return data;

        const start = new Date(dateStart).setHours(0, 0, 0, 0);
        const end = new Date(dateEnd).setHours(23, 59, 59, 999);

        return data.filter(d => {
            const dTime = new Date(d.data_producao).getTime();
            return dTime >= start && dTime <= end;
        }).sort((a, b) => new Date(a.data_producao).getTime() - new Date(b.data_producao).getTime());
    }, [data, dateStart, dateEnd]);

    const kpis = useMemo(() => {
        if (filteredData.length === 0) return { total: 0, avg: 0, peak: 0, peakDate: '-' };
        const dayMap = new Map<string, number>();
        filteredData.forEach(d => {
            const current = dayMap.get(d.data_producao) || 0;
            dayMap.set(d.data_producao, current + d.peso);
        });
        const dailyValues = Array.from(dayMap.values());
        const total = dailyValues.reduce((a, b) => a + b, 0);
        const avg = total / (dailyValues.length || 1);
        const peak = Math.max(...dailyValues);
        const peakEntry = Array.from(dayMap.entries()).find(([, val]) => val === peak);
        const peakDate = peakEntry ? peakEntry[0].split('-').reverse().slice(0, 2).join('/') : '-';
        return { total, avg, peak, peakDate };
    }, [filteredData]);

    const sortedDataResult = useMemo(() => {
        const seriesMap = new Map<string, ChartPoint[]>();
        if (viewMode === 'general') {
            availableShifts.forEach(t => seriesMap.set(t, []));
            seriesMap.set("TOTAL DIA", []);
            const aggregatedMap = new Map<string, Record<string, number>>();
            filteredData.forEach(d => {
                const date = new Date(d.data_producao);
                let key = d.data_producao;
                if (granularity === 'week') {
                    const day = date.getDay() || 7;
                    if (day !== 1) date.setHours(-24 * (day - 1));
                    key = date.toISOString().split('T')[0];
                } else if (granularity === 'month') {
                    key = d.data_producao.substring(0, 7) + '-01';
                }
                if (!aggregatedMap.has(key)) aggregatedMap.set(key, {});
                const periodData = aggregatedMap.get(key)!;
                periodData[d.turno] = (periodData[d.turno] || 0) + d.peso;
                periodData['TOTAL DIA'] = (periodData['TOTAL DIA'] || 0) + d.peso;
            });
            const sortedKeys = Array.from(aggregatedMap.keys()).sort();
            sortedKeys.forEach(dateKey => {
                const values = aggregatedMap.get(dateKey)!;
                availableShifts.forEach(turno => {
                    if (values[turno] > 0) {
                        seriesMap.get(turno)?.push({ date: dateKey, val: values[turno], id: `${dateKey}-${turno}`, type: turno });
                    }
                });
                if (values['TOTAL DIA'] > 0) {
                    seriesMap.get("TOTAL DIA")?.push({ date: dateKey, val: values['TOTAL DIA'], id: `${dateKey}-TOTAL`, type: "TOTAL DIA" });
                }
            });
            return { uniqueDates: sortedKeys, series: seriesMap };
        } else if (viewMode === 'detailed') {
            const shiftData = filteredData.filter(d => d.turno === selectedShift);
            availableMachines.forEach(m => seriesMap.set(m, []));
            const aggregatedMap = new Map<string, Record<string, number>>();
            shiftData.forEach(d => {
                const date = new Date(d.data_producao);
                let key = d.data_producao;
                if (granularity === 'week') {
                    const day = date.getDay() || 7;
                    if (day !== 1) date.setHours(-24 * (day - 1));
                    key = date.toISOString().split('T')[0];
                } else if (granularity === 'month') {
                    key = d.data_producao.substring(0, 7) + '-01';
                }
                if (!aggregatedMap.has(key)) aggregatedMap.set(key, {});
                const periodData = aggregatedMap.get(key)!;
                if (d.produto) periodData[d.produto] = (periodData[d.produto] || 0) + (d.offset_peso ?? d.peso);
                else periodData['???'] = (periodData['???'] || 0) + d.peso;
            });
            const sortedKeys = Array.from(aggregatedMap.keys()).sort();
            sortedKeys.forEach(dateKey => {
                const values = aggregatedMap.get(dateKey)!;
                availableMachines.forEach(mq => {
                    if (values[mq] > 0) seriesMap.get(mq)?.push({ date: dateKey, val: values[mq], id: `${dateKey}-${mq}`, type: mq });
                });
            });
            return { uniqueDates: sortedKeys, series: seriesMap };
        } else if (viewMode === 'machine_comparison') {
            const machineData = filteredData.filter(d => d.produto === selectedMachine);
            availableShifts.forEach(t => seriesMap.set(t, []));
            const aggregatedMap = new Map<string, Record<string, number>>();
            machineData.forEach(d => {
                const date = new Date(d.data_producao);
                let key = d.data_producao;
                if (granularity === 'week') {
                    const day = date.getDay() || 7;
                    if (day !== 1) date.setHours(-24 * (day - 1));
                    key = date.toISOString().split('T')[0];
                } else if (granularity === 'month') {
                    key = d.data_producao.substring(0, 7) + '-01';
                }
                if (!aggregatedMap.has(key)) aggregatedMap.set(key, {});
                const periodData = aggregatedMap.get(key)!;
                periodData[d.turno] = (periodData[d.turno] || 0) + d.peso;
            });
            const sortedKeys = Array.from(aggregatedMap.keys()).sort();
            sortedKeys.forEach(dateKey => {
                const values = aggregatedMap.get(dateKey)!;
                availableShifts.forEach(turno => {
                    const val = values[turno] || 0;
                    if (val > 0) seriesMap.get(turno)?.push({ date: dateKey, val, id: `${dateKey}-${turno}-${selectedMachine}`, type: turno });
                });
            });
            return { uniqueDates: sortedKeys, series: seriesMap };
        } else {
            availableMachines.forEach(m => seriesMap.set(m, []));
            const aggregatedMap = new Map<string, Record<string, number>>();
            filteredData.forEach(d => {
                const date = new Date(d.data_producao);
                let key = d.data_producao;
                if (granularity === 'week') {
                    const day = date.getDay() || 7;
                    if (day !== 1) date.setHours(-24 * (day - 1));
                    key = date.toISOString().split('T')[0];
                } else if (granularity === 'month') {
                    key = d.data_producao.substring(0, 7) + '-01';
                }
                if (!aggregatedMap.has(key)) aggregatedMap.set(key, {});
                const periodData = aggregatedMap.get(key)!;
                if (d.produto) periodData[d.produto] = (periodData[d.produto] || 0) + d.peso;
            });
            const sortedKeys = Array.from(aggregatedMap.keys()).sort();
            sortedKeys.forEach(dateKey => {
                const values = aggregatedMap.get(dateKey)!;
                availableMachines.forEach(mq => {
                    if (values[mq] > 0) seriesMap.get(mq)?.push({ date: dateKey, val: values[mq], id: `${dateKey}-${mq}-TOTAL`, type: mq });
                });
            });
            return { uniqueDates: sortedKeys, series: seriesMap };
        }
    }, [filteredData, viewMode, selectedShift, selectedMachine, availableShifts, availableMachines, granularity]);

    const rechartsData = useMemo(() => {
        if (!sortedDataResult || sortedDataResult.uniqueDates.length === 0) return [];
        return sortedDataResult.uniqueDates.map(date => {
            const point: any = { date, displayDate: date.split('-').reverse().slice(0, 2).join('/') };
            Array.from(sortedDataResult.series.entries()).forEach(([name, points]) => {
                const found = points.find(p => p.date === date);
                if (found) point[name] = found.val;
            });
            return point;
        });
    }, [sortedDataResult]);

    const seriesConfig = useMemo(() => {
        if (!sortedDataResult) return [];
        return Array.from(sortedDataResult.series.keys()).map(name => {
            let color = "#000000";
            if (name === "TOTAL DIA") {
                color = SHIFT_COLORS_CONFIG["TOTAL DIA"].hex;
            } else if (SHIFT_COLORS_CONFIG[name]) {
                color = SHIFT_COLORS_CONFIG[name].hex;
            } else {
                const machIndex = availableMachines.indexOf(name);
                if (machIndex !== -1) {
                    color = MACHINE_COLORS_CONFIG[machIndex % MACHINE_COLORS_CONFIG.length].hex;
                } else {
                    let hash = 0;
                    for (let i = 0; i < name.length; i++) hash = name.charCodeAt(i) + ((hash << 5) - hash);
                    const c = (hash & 0x00FFFFFF).toString(16).toUpperCase();
                    color = "#" + "00000".substring(0, 6 - c.length) + c;
                }
            }
            return { name, color, isTotal: name === "TOTAL DIA" };
        });
    }, [sortedDataResult, availableMachines]);

    if (!rechartsData || rechartsData.length === 0) return (
        <div className="w-full h-64 flex flex-col items-center justify-center bg-neutral-50 border border-neutral-200 rounded-xl">
            <Lucide.BarChart3 className="h-8 w-8 text-neutral-300 mb-2" />
            <span className="text-[10px] font-bold uppercase tracking-widest text-neutral-400">Dados insuficiente para o per├¡odo</span>
        </div>
    );

    return (
        <div className="w-full bg-white border border-black p-6 animate-fade-in relative flex flex-col gap-6 shadow-[8px_8px_0px_rgba(0,0,0,1)] rounded-xl">
            <div className="flex flex-col md:flex-row items-start md:items-end justify-between gap-6 border-b border-black pb-6">
                <div className="flex items-center gap-4"><div className="p-3 bg-black text-white rounded shrink-0 shadow-lg"><Lucide.TrendingUp className="h-6 w-6" /></div><div><h3 className="text-xl font-serif text-black leading-none mb-1">An├ílise de Produ├º├úo</h3><p className="text-[10px] text-neutral-500 font-bold uppercase tracking-widest">{viewMode === 'general' ? 'Vis├úo Geral da F├íbrica' : viewMode === 'detailed' ? 'Performance por M├íquina' : 'Detalhamento'}</p></div></div>
                <div className="flex items-center gap-2 overflow-x-auto pb-1 md:pb-0 w-full md:w-auto">
                    <div className="px-4 py-2 bg-neutral-50 border border-neutral-100 rounded-lg text-center min-w-[100px]"><span className="text-[9px] font-bold text-neutral-400 uppercase block">Total</span><span className="text-lg font-mono font-black text-black leading-none">{kpis.total.toLocaleString('pt-BR')}</span></div>
                    <div className="w-px h-8 bg-neutral-200 hidden md:block" /><div className="px-4 py-2 bg-neutral-50 border border-neutral-100 rounded-lg text-center min-w-[100px]"><span className="text-[9px] font-bold text-neutral-400 uppercase block">M├®dia</span><span className="text-lg font-mono font-black text-emerald-600 leading-none">{Math.round(kpis.avg).toLocaleString('pt-BR')}</span></div>
                    <div className="w-px h-8 bg-neutral-200 hidden md:block" /><div className="px-4 py-2 bg-neutral-50 border border-neutral-100 rounded-lg text-center min-w-[100px]"><span className="text-[9px] font-bold text-neutral-400 uppercase block">Pico ({kpis.peakDate})</span><span className="text-lg font-mono font-black text-blue-600 leading-none">{kpis.peak.toLocaleString('pt-BR')}</span></div>
                </div>
            </div>
            <div className="bg-neutral-50/50 p-2 rounded-lg border border-neutral-100 flex flex-col lg:flex-row items-center justify-between gap-4">
                <div className="flex flex-col sm:flex-row items-center gap-4 w-full lg:w-auto overflow-x-auto">
                    <div className="flex items-center gap-2 bg-white border border-neutral-200 rounded p-1.5 shadow-sm"><span className="text-[10px] font-bold text-neutral-500 uppercase">De:</span><input type="date" aria-label="In├¡cio" value={dateStart} onChange={(e) => setDateStart(e.target.value)} className="bg-transparent border-none p-0 text-[10px] font-bold uppercase" /><span className="text-neutral-300 mx-1">|</span><span className="text-[10px] font-bold text-neutral-500 uppercase">At├®:</span><input type="date" aria-label="Fim" value={dateEnd} onChange={(e) => setDateEnd(e.target.value)} className="bg-transparent border-none p-0 text-[10px] font-bold uppercase" /></div>
                    <div className="h-6 w-px bg-neutral-300 hidden sm:block" />
                    <div className="flex items-center bg-white border border-neutral-200 rounded p-1 shadow-sm">{(['day', 'week', 'month'] as const).map(opt => (<button key={opt} onClick={() => setGranularity(opt)} className={cn("px-3 py-1.5 text-[10px] font-bold uppercase rounded transition-all", granularity === opt ? "bg-neutral-800 text-white shadow" : "text-neutral-400 hover:text-black hover:bg-neutral-50")}>{opt === 'day' ? 'Dia' : opt === 'week' ? 'Sem' : 'M├¬s'}</button>))}</div>
                </div>
                <div className="flex flex-wrap items-center gap-3 justify-end w-full lg:w-auto">
                    <button onClick={() => setShowMovingAverage(!showMovingAverage)} className={cn("flex items-center gap-2 px-3 h-9 rounded border transition-all text-[10px] font-bold uppercase tracking-wide", showMovingAverage ? "bg-orange-50 border-orange-200 text-orange-600 shadow-sm" : "bg-white border-neutral-200 text-neutral-400 hover:border-neutral-300 hover:text-neutral-600")}><Lucide.Activity className="h-3.5 w-3.5" /><span className="hidden sm:inline">Tend├¬ncia</span></button>
                    <div className={cn("flex items-center gap-2 px-3 h-9 bg-white border rounded transition-all focus-within:ring-1 focus-within:ring-red-500", showTargetLine ? "border-red-200 shadow-sm" : "border-neutral-200")}><Lucide.Target className={cn("h-3.5 w-3.5", showTargetLine ? "text-red-500" : "text-neutral-300")} /><input type="number" placeholder="Meta" className="w-20 text-[10px] border-none p-0 font-mono focus:ring-0" value={targetValue || ''} onChange={(e) => { const v = Number(e.target.value); setTargetValue(v); setShowTargetLine(true); }} onBlur={() => targetValue && saveTargetToDB(targetValue)} />{isSavingTarget && <span className="text-[10px]">...</span>}</div>
                    <select title="Modo de Exibi├º├úo" value={viewMode} onChange={(e) => setViewMode(e.target.value as ViewMode)} className="h-9 px-3 text-[10px] font-bold uppercase bg-white border border-neutral-200 rounded shadow-sm focus:outline-none focus:ring-1 focus:ring-black cursor-pointer"><option value="general">Geral</option><option value="detailed">Por M├íquina (Turno)</option><option value="compare_machines_total">M├íquinas (Total)</option><option value="machine_comparison">Detalhamento</option></select>
                    {viewMode === 'detailed' && <select title="Turno" value={selectedShift} onChange={(e) => setSelectedShift(e.target.value)} className="h-9 px-3 text-[10px] font-bold uppercase bg-white border border-neutral-200 rounded shadow-sm">{availableShifts.map(s => <option key={s} value={s}>{s}</option>)}</select>}
                    {viewMode === 'machine_comparison' && <select title="M├íquina" value={selectedMachine} onChange={(e) => setSelectedMachine(e.target.value)} className="h-9 px-3 text-[10px] font-bold uppercase bg-white border border-neutral-200 rounded shadow-sm">{availableMachines.map(m => <option key={m} value={m}>{formatName(m)}</option>)}</select>}
                </div>
            </div>

            <div className="bg-neutral-50/50 border border-neutral-100 rounded-[1.5rem] p-4 h-[420px] w-full mt-2 shadow-inner">
                <ResponsiveContainer width="100%" height="100%">
                    <LineChart data={rechartsData} margin={{ top: 20, right: 30, left: 10, bottom: 5 }}>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e5e5e5" />
                        <XAxis dataKey="displayDate" axisLine={false} tickLine={false} tick={{ fill: '#9ca3af', fontSize: 10, fontWeight: 700 }} dy={10} />
                        <YAxis axisLine={false} tickLine={false} tick={{ fill: '#9ca3af', fontSize: 10, fontWeight: 700 }} tickFormatter={(val) => Math.round(val).toLocaleString('pt-BR')} />
                        <RechartsTooltip content={<CustomTooltip />} cursor={{ stroke: '#e5e5e5', strokeWidth: 2 }} />
                        {showTargetLine && targetValue && (
                            <ReferenceLine y={targetValue} stroke="#ef4444" strokeWidth={2} strokeDasharray="6 4" label={{ position: 'insideTopLeft', value: 'META', fill: '#ef4444', fontSize: 10, fontWeight: 900 }} />
                        )}
                        {seriesConfig.map((s) => (
                            <Line key={s.name} type="monotone" dataKey={s.name} name={formatName(s.name)} stroke={s.color} strokeWidth={s.isTotal ? 4 : 2.5} dot={{ r: s.isTotal ? 6 : 4, stroke: s.color, strokeWidth: 2, fill: '#fff' }} activeDot={{ r: s.isTotal ? 8 : 6, stroke: '#fff', strokeWidth: 2, fill: s.color }} />
                        ))}
                    </LineChart>
                </ResponsiveContainer>
            </div>

            <div className="flex flex-wrap items-center justify-center gap-x-6 gap-y-3 pt-6 pb-2 border-t border-neutral-100">
                {seriesConfig.map((s) => (
                    <div key={s.name} className="flex items-center gap-2">
                        <div className="w-3 h-3 rounded-full shadow-sm bg-dynamic" style={{ '--bg-color': s.color } as React.CSSProperties} />
                        <span className="text-[10px] font-bold text-neutral-500 uppercase tracking-widest">{formatName(s.name)}</span>
                    </div>
                ))}
            </div>
        </div>
    );
}

import { Card, CardContent } from "@/components/ui/card";
import type { Sample } from "@/entities/Sample";
import { calculateStatistics } from "@/lib/stats";
import { AlertTriangle, Zap, Info, Pencil, X } from "lucide-react";
import { cn } from "@/lib/utils";
import { formatDecimalBR } from "@/services/ocrExtraction";
import { useState } from "react";

interface StatisticsPanelProps {
    samples: Sample[];
    selectedColor?: string | null;
}

const COLORS: Record<string, string> = {
    "#ef4444": "VERMELHO",
    "#3b82f6": "AZUL",
    "#10b981": "VERDE",
    "#f59e0b": "AMARELO",
};

const CUSTOM_AVERAGES_KEY = 'custom_color_averages';

export default function StatisticsPanel({ samples, selectedColor }: StatisticsPanelProps) {
    const [editingField, setEditingField] = useState<{ color: string; field: string } | null>(null);
    const [editValue, setEditValue] = useState<string>('');

    const [customAverages, setCustomAverages] = useState<Record<string, Record<string, number>>>(() => {
        try {
            const stored = localStorage.getItem(CUSTOM_AVERAGES_KEY);
            return stored ? JSON.parse(stored) : {};
        } catch {
            return {};
        }
    });

    const fields = [
        { key: 'mic', label: 'MIC', decimals: 2 },
        { key: 'len', label: 'LEN', decimals: 2 },
        { key: 'str', label: 'STR', decimals: 1 },
        { key: 'rd', label: 'RD', decimals: 1 },
        { key: 'b', label: '+b', decimals: 1 },
    ] as const;

    const groups = samples.reduce((acc, s) => {
        if (s.cor) {
            if (!acc[s.cor]) acc[s.cor] = [];
            acc[s.cor].push(s);
        }
        return acc;
    }, {} as Record<string, Sample[]>);

    const colorsToShow = selectedColor ? [selectedColor] : Object.keys(groups);

    const generateAutomatedInsight = (groupSamples: Sample[]) => {
        const micStats = calculateStatistics(groupSamples.map(s => ({ id: s.id, val: s.mic || 0 })));
        if (micStats.stdDev > 0.4) return { message: "Alta Variabilidade", type: "warning" };
        if (micStats.mean < 3.5 || micStats.mean > 5.0) return { message: "Aten├º├úo: M├®dia At├¡pica", type: "warning" };
        return { message: "M├®tricas Est├íveis", type: "success" };
    };

    const getValue = (color: string, field: string, calculatedValue: number) => {
        return customAverages[color]?.[field] ?? calculatedValue;
    };

    const isCustomValue = (color: string, field: string) => {
        return customAverages[color]?.[field] !== undefined;
    };

    const startEditing = (color: string, field: string, currentValue: number, decimals: number) => {
        setEditingField({ color, field });
        // Format value to remove floating point artifacts
        setEditValue(currentValue.toFixed(decimals));
    };

    const saveEdit = () => {
        if (!editingField) return;
        const numValue = parseFloat(editValue);
        if (isNaN(numValue)) {
            cancelEdit();
            return;
        }

        const newCustomAverages = {
            ...customAverages,
            [editingField.color]: {
                ...customAverages[editingField.color],
                [editingField.field]: numValue
            }
        };

        setCustomAverages(newCustomAverages);
        localStorage.setItem(CUSTOM_AVERAGES_KEY, JSON.stringify(newCustomAverages));
        setEditingField(null);
        setEditValue('');
    };

    const cancelEdit = () => {
        setEditingField(null);
        setEditValue('');
    };

    const resetToCalculated = (color: string, field: string) => {
        const newCustomAverages = { ...customAverages };
        if (newCustomAverages[color]) {
            delete newCustomAverages[color][field];
            if (Object.keys(newCustomAverages[color]).length === 0) {
                delete newCustomAverages[color];
            }
        }
        setCustomAverages(newCustomAverages);
        localStorage.setItem(CUSTOM_AVERAGES_KEY, JSON.stringify(newCustomAverages));
    };

    if (colorsToShow.length === 0) {
        return (
            <div className="bg-neutral-50 rounded-xl p-12 text-center border border-neutral-200 border-dashed">
                <div className="bg-white h-12 w-12 rounded-full border border-neutral-100 flex items-center justify-center mx-auto mb-3 shadow-sm">
                    <Info className="h-5 w-5 text-neutral-400" />
                </div>
                <p className="text-neutral-900 font-bold uppercase tracking-widest text-xs">Sem Dados Classificados</p>
                <p className="text-[10px] text-neutral-500 mt-1 max-w-xs mx-auto">Classifique as amostras para visualizar as estat├¡sticas por grupo.</p>
            </div>
        );
    }

    return (
        <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-4">
            {colorsToShow.map(color => {
                const groupSamples = groups[color] || [];
                if (groupSamples.length === 0) return null;

                const colorName = COLORS[color] || "GRUPO";
                const insight = generateAutomatedInsight(groupSamples);

                return (
                    <Card key={color} className="overflow-hidden border border-neutral-200 bg-white shadow-sm hover:shadow-lg transition-all duration-200">
                        {/* Thin color indicator */}
                        <div className="h-0.5 w-full" style={{ backgroundColor: color }} />

                        <CardContent className="p-6">
                            {/* Header */}
                            <div className="flex justify-between items-center mb-6">
                                <h4 className="text-sm font-bold uppercase tracking-wider text-neutral-700">
                                    {colorName}
                                </h4>
                                <span className="text-[10px] font-semibold text-neutral-400 bg-neutral-50 px-2 py-1 rounded">
                                    {groupSamples.length} amostras
                                </span>
                            </div>

                            {/* Metrics */}
                            <div className="space-y-4">
                                {fields.map(field => {
                                    const values = groupSamples.map(s => ({ id: s.id, val: (s as any)[field.key] })).filter(v => typeof v.val === 'number');
                                    const stats = calculateStatistics(values);
                                    const displayValue = getValue(color, field.key, stats.mean);
                                    const isCustom = isCustomValue(color, field.key);
                                    const isEditing = editingField?.color === color && editingField?.field === field.key;

                                    return (
                                        <div key={field.key}>
                                            {isEditing ? (
                                                <div className="flex items-center gap-2">
                                                    <span className="text-xs font-semibold text-neutral-400 uppercase w-12 shrink-0">
                                                        {field.label}
                                                    </span>
                                                    <input
                                                        type="number"
                                                        step={field.decimals === 2 ? "0.01" : "0.1"}
                                                        value={editValue}
                                                        onChange={(e) => setEditValue(e.target.value)}
                                                        onKeyDown={(e) => {
                                                            if (e.key === 'Enter') saveEdit();
                                                            if (e.key === 'Escape') cancelEdit();
                                                        }}
                                                        onBlur={saveEdit}
                                                        className="flex-1 min-w-0 px-3 py-2 text-xl font-mono font-bold border-2 border-blue-500 rounded-lg text-center focus:outline-none focus:ring-2 focus:ring-blue-300 bg-blue-50"
                                                        autoFocus
                                                    />
                                                </div>
                                            ) : (
                                                <div
                                                    className="flex items-center justify-between group/metric cursor-pointer py-2 px-3 -mx-3 rounded-lg hover:bg-neutral-50 transition-colors"
                                                    onClick={() => startEditing(color, field.key, displayValue, field.decimals)}
                                                >
                                                    <span className="text-xs font-semibold text-neutral-400 uppercase">
                                                        {field.label}
                                                    </span>
                                                    <div className="flex items-center gap-2">
                                                        <span
                                                            className={cn(
                                                                "text-2xl font-mono font-bold tabular-nums transition-colors",
                                                                isCustom ? "text-blue-600" : "text-neutral-900"
                                                            )}
                                                        >
                                                            {formatDecimalBR(displayValue, field.decimals)}
                                                        </span>
                                                        {isCustom ? (
                                                            <button
                                                                onClick={(e) => {
                                                                    e.stopPropagation();
                                                                    resetToCalculated(color, field.key);
                                                                }}
                                                                className="h-6 w-6 flex items-center justify-center rounded-md hover:bg-orange-100 text-orange-600 transition-colors shrink-0"
                                                                title="Restaurar valor calculado"
                                                            >
                                                                <X className="h-4 w-4" />
                                                            </button>
                                                        ) : (
                                                            <Pencil className="h-4 w-4 text-neutral-300 opacity-0 group-hover/metric:opacity-100 transition-opacity" />
                                                        )}
                                                    </div>
                                                </div>
                                            )}
                                        </div>
                                    )
                                })}
                            </div>

                            {/* Footer insight */}
                            <div className={cn(
                                "mt-6 pt-4 border-t flex items-center justify-center gap-2 text-[10px] font-bold uppercase tracking-wider",
                                insight.type === 'success' ? "border-emerald-100 text-emerald-600" : "border-amber-100 text-amber-600"
                            )}>
                                {insight.type === 'success' ? <Zap className="h-3.5 w-3.5" /> : <AlertTriangle className="h-3.5 w-3.5" />}
                                {insight.message}
                            </div>
                        </CardContent>
                    </Card>
                )
            })}
        </div>
    );
}

