                                                            {cell.maxDelay >= 48 && !pin && (
                                                                <div className="absolute top-1 right-1">
                                                                    <div className="h-1.5 w-1.5 rounded-full bg-red-400 animate-pulse" />
                                                                </div>
                                                            )}
                                                        </div>
                                                    ) : ""}
                                                </td>
                                            );
                                        })}
