import React, { createContext, useContext, useState, useCallback } from "react";

type ToastType = "success" | "error" | "info" | "destructive" | "warning";

interface Toast {
    id: string;
    title: string;
    description?: string;
    type: ToastType;
}

interface AddToastProps {
    title: string;
    description?: string;
    type?: ToastType;
    variant?: ToastType;
}

interface ToastContextValue {
    addToast: (props: AddToastProps) => void;
    toast: (props: AddToastProps) => void;
    toasts: Toast[];
}

const ToastContext = createContext<ToastContextValue | undefined>(undefined);

export function useToast() {
    const context = useContext(ToastContext);
    if (!context) {
        throw new Error("useToast must be used within a ToastProvider");
    }
    return context;
}

export function ToastProvider({ children }: { children: React.ReactNode }) {
    const [toasts, setToasts] = useState<Toast[]>([]);

    const addToast = useCallback(({ title, description, type, variant }: AddToastProps) => {
        const id = Math.random().toString(36).substring(2, 9);
        const finalType = type || variant || "info";

        setToasts((prev) => [...prev, { id, title, description, type: finalType }]);

        setTimeout(() => {
            removeToast(id);
        }, 5000);
    }, []);

    const removeToast = useCallback((id: string) => {
        setToasts((prev) => prev.filter((t) => t.id !== id));
    }, []);

    return (
        <ToastContext.Provider value={{ addToast, toast: addToast, toasts }}>
            {children}
            {/* Default toaster removed - Layout handles it now */}
        </ToastContext.Provider>
    );
}

import { supabase } from "@/lib/supabase";

export type AccessLevel = 'admin_global' | 'admin_lab' | 'user' | 'quality_admin';

export interface Analista {
    id: string;
    nome: string;
    email: string;
    foto?: string; // URL da foto ou Base64
    senha?: string; // Em produ├º├úo, nunca salvar senha em plain text
    lab_id?: string; // Pode ser null se for admin global
    cargo: string;
    acesso: AccessLevel;
    created_at: string;
    updated_at: string;
    last_active?: string;
    current_lote_id?: string | null;
}

const STORAGE_KEY = 'fibertech_analistas';

const isSupabaseEnabled = () => {
    const url = import.meta.env.VITE_SUPABASE_URL;
    const key = import.meta.env.VITE_SUPABASE_ANON_KEY;
    return !!url && url !== 'YOUR_SUPABASE_URL' && !!key && key !== 'YOUR_SUPABASE_ANON_KEY';
};

const getStoredAnalistas = (): Analista[] => {
    try {
        const data = localStorage.getItem(STORAGE_KEY);
        if (!data) return [];
        return JSON.parse(data);
    } catch {
        return [];
    }
};

const saveStoredAnalistas = (analistas: Analista[]) => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(analistas));
};

export const AnalistaService = {
    async list(): Promise<Analista[]> {
        if (isSupabaseEnabled()) {
            try {
                const { data, error } = await supabase.from('analistas').select('*');
                if (error) throw error;
                if (data && data.length > 0) return data;
            } catch (err) {
                console.warn("Supabase list failed, falling back to local:", err);
            }

            const localData = getStoredAnalistas();
            return localData || [];
        }
        return getStoredAnalistas();
    },

    async listByLab(labId: string): Promise<Analista[]> {
        if (isSupabaseEnabled()) {
            try {
                const { data, error } = await supabase.from('analistas').select('*').eq('lab_id', labId);
                if (error) throw error;
                return data || [];
            } catch (err) {
                console.warn("Supabase listByLab failed, falling back to local:", err);
            }
        }
        return getStoredAnalistas().filter(a => a.lab_id === labId);
    },

    async get(id: string): Promise<Analista | undefined> {
        if (isSupabaseEnabled()) {
            try {
                const { data, error } = await supabase.from('analistas').select('*').eq('id', id).single();
                if (!error && data) return data;
            } catch (err) {
                console.warn("Supabase get failed, falling back to local:", err);
            }
        }
        return getStoredAnalistas().find(a => a.id === id);
    },

    async create(data: Omit<Analista, 'id' | 'created_at' | 'updated_at'>): Promise<Analista> {
        if (isSupabaseEnabled()) {
            const { data: newAnalista, error } = await supabase.from('analistas').insert([data]).select().single();
            if (error) throw error;
            return newAnalista;
        }

        const analistas = getStoredAnalistas();
        if (analistas.some(a => a.email === data.email)) {
            throw new Error("Email j├í cadastrado");
        }

        const newAnalista: Analista = {
            ...data,
            id: Math.random().toString(36).substr(2, 9),
            created_at: new Date().toISOString(),
            updated_at: new Date().toISOString(),
        };
        analistas.push(newAnalista);
        saveStoredAnalistas(analistas);
        return newAnalista;
    },

    async update(id: string, data: Partial<Analista>): Promise<Analista | undefined> {
        if (isSupabaseEnabled()) {
            try {
                // Remove undefined fields which cause 400 Bad Request
                const cleanData = { ...data };
                Object.keys(cleanData).forEach(key => (cleanData as any)[key] === undefined && delete (cleanData as any)[key]);

                if (Object.keys(cleanData).length === 0) return undefined;

                const { data: updated, error } = await supabase.from('analistas').update(cleanData).eq('id', id).select().single();

                if (error) {
                    console.warn(`Supabase update warning for analista ${id}:`, error);
                    return undefined;
                }
                return updated;
            } catch (err) {
                console.warn(`Unexpected error updating analista ${id}:`, err);
                return undefined;
            }
        }

        const analistas = getStoredAnalistas();
        const index = analistas.findIndex(a => a.id === id);
        if (index === -1) throw new Error("Analista not found");

        const updatedAnalista = { ...analistas[index], ...data, updated_at: new Date().toISOString() };
        analistas[index] = updatedAnalista;
        saveStoredAnalistas(analistas);
        return updatedAnalista;
    },

    async delete(id: string): Promise<void> {
        if (isSupabaseEnabled()) {
            const { error } = await supabase.from('analistas').delete().eq('id', id);
            if (error) throw error;
            return;
        }

        const analistas = getStoredAnalistas();
        const filtered = analistas.filter(a => a.id !== id);
        saveStoredAnalistas(filtered);
    },

    async updateLastActive(id: string, loteId?: string | null): Promise<void> {
        try {
            const updateData: any = { last_active: new Date().toISOString() };

            // Treat empty string as null for UUID columns
            if (loteId !== undefined) {
                updateData.current_lote_id = loteId === "" ? null : loteId;
            }

            if (isSupabaseEnabled()) {
                await supabase.from('analistas').update(updateData).eq('id', id);
                return;
            }

            const analistas = getStoredAnalistas();
            const index = analistas.findIndex(a => a.id === id);
            if (index !== -1) {
                analistas[index].last_active = new Date().toISOString();
                if (loteId !== undefined) analistas[index].current_lote_id = loteId;
                saveStoredAnalistas(analistas);
            }
        } catch (error) {
            // Suppress heartburn errors, just log warning
            console.warn("Failed to update user presence", error);
        }
    }
};

import { supabase } from "@/lib/supabase";

export interface AuditCategory {
    id: string;
    name: string;
    description: string;
    labId?: string;
}

export interface AuditDocument {
    id: string;
    name: string;
    fileName: string;
    fileSize: number;
    fileType: string;
    data?: string; // Optional (loaded on demand)
    uploadDate: string;
    category: string;
    analystName: string;
    status: 'pending' | 'verified' | 'completed';
    labId?: string;
    // Novos campos para formato de "Tarefa/Afazer"
    isTask?: boolean;
    deadline?: string;
    assignedTo?: string;
    observation?: string;
}

const DOCS_KEY = 'fibertech_audit_docs';
const CATS_KEY = 'fibertech_audit_categories';

const isSupabaseEnabled = () => !!import.meta.env.VITE_SUPABASE_URL && !!import.meta.env.VITE_SUPABASE_ANON_KEY;

let detectedDbColumns: string[] = [];
// Helper removed as it was unused

const DEFAULT_CATEGORIES: AuditCategory[] = [
    { id: "calib", name: "Certificados de Calibra├º├úo", description: "Certificados HVI, balan├ºas e equipamentos auxiliares." },
    { id: "pops", name: "POPs (Procedimentos)", description: "Instru├º├Áes de trabalho e procedimentos operacionais padr├úo." },
    { id: "maint", name: "Registros de Manuten├º├úo", description: "Hist├│rico de manuten├º├Áes preventivas e corretivas." },
    { id: "train", name: "Treinamentos de Equipe", description: "Evid├¬ncias de capacita├º├úo e treinamentos t├®cnicos." },
    { id: "interlab", name: "Relat├│rios de Interlaboratorial", description: "Resultados e an├ílises de participa├º├úo em ensaios externos." }
];

export const AuditService = {
    // --- CATEGORIES ---
    async listCategories(): Promise<AuditCategory[]> {
        if (isSupabaseEnabled()) {
            try {
                const { data, error } = await supabase
                    .from('auditoria_categorias')
                    .select('*');

                if (error) throw error;

                return (data || []).map((d: any) => ({
                    ...d,
                    labId: d.lab_id
                }));
            } catch (error) {
                console.warn("Supabase (Categorias) unavailable, falling back to local storage:", error);
                // Fallback to local storage
            }
        }
        const data = localStorage.getItem(CATS_KEY);
        if (!data) {
            localStorage.setItem(CATS_KEY, JSON.stringify(DEFAULT_CATEGORIES));
            return DEFAULT_CATEGORIES;
        }
        return JSON.parse(data);
    },

    async saveCategory(cat: AuditCategory): Promise<void> {
        if (isSupabaseEnabled()) {
            const isNew = !cat.id;
            const id = cat.id || crypto.randomUUID();

            const payload = {
                id,
                name: cat.name,
                description: cat.description
            };

            let error;
            if (isNew) {
                const result = await supabase.from('auditoria_categorias').insert([payload]);
                error = result.error;
            } else {
                const result = await supabase.from('auditoria_categorias').update(payload).eq('id', id);
                error = result.error;
            }

            if (error) {
                console.error("Supabase Error saving category:", error);
                throw error;
            }
            return;
        }

        const cats = await this.listCategories();
        const existingIndex = cats.findIndex(c => c.id === cat.id);
        if (existingIndex >= 0) {
            cats[existingIndex] = cat;
        } else {
            cats.push({ ...cat, id: cat.id || crypto.randomUUID() });
        }
        localStorage.setItem(CATS_KEY, JSON.stringify(cats));
    },

    async deleteCategory(id: string): Promise<void> {
        if (isSupabaseEnabled()) {
            const { error } = await supabase.from('auditoria_categorias').delete().eq('id', id);
            if (error) throw error;
            return;
        }
        const cats = await this.listCategories();
        const filtered = cats.filter(c => c.id !== id);
        localStorage.setItem(CATS_KEY, JSON.stringify(filtered));
    },

    // --- DOCUMENTS ---
    async list(): Promise<AuditDocument[]> {
        if (isSupabaseEnabled()) {
            try {
                console.log("DEBUG: Fetching audit_docs...");
                const { data, error } = await supabase
                    .from('auditoria_documentos')
                    .select('*');

                if (error) throw error;

                if (data && data.length > 0) {
                    detectedDbColumns = Object.keys(data[0]);
                    console.log("DEBUG: Columns found:", detectedDbColumns);
                }

                const docs = (data || []).map((d: any) => {
                    try {
                        return {
                            id: d.id,
                            name: d.name || 'Sem Nome',
                            fileName: d.fileName || d.filename || d.file_name || d.name || 'unknown',
                            fileSize: d.fileSize || d.filesize || d.file_size || 0,
                            fileType: d.fileType || d.filetype || d.file_type || 'application/octet-stream',
                            uploadDate: d.uploadDate || d.uploaddate || d.upload_date || d.created_at || new Date().toISOString(),
                            category: d.category || 'Geral',
                            analystName: d.analystName || d.analystname || d.analyst_name || 'Desconhecido',
                            status: d.status || 'verified',
                            labId: d.labId || d.labid || d.lab_id,
                            data: d.data,
                            isTask: d.isTask || d.istask || d.is_task || false,
                            deadline: d.deadline,
                            assignedTo: d.assignedTo || d.assignedto || d.assigned_to,
                            observation: d.observation
                        };
                    } catch (err) {
                        console.error("Mapping error for doc:", d, err);
                        return null;
                    }
                }).filter((d: any) => d !== null) as AuditDocument[];

                // Post-process: Generate Signed URLs for Storage Paths
                const pathsToSign: string[] = [];
                const docIndices: number[] = [];

                docs.forEach((doc, index) => {
                    if (doc.data && !doc.data.startsWith('data:') && !doc.data.startsWith('http')) {
                        pathsToSign.push(doc.data);
                        docIndices.push(index);
                    }
                });

                if (pathsToSign.length > 0) {
                    try {
                        const { data: signedData, error: _signError } = await supabase.storage
                            .from('audit-docs')
                            .createSignedUrls(pathsToSign, 3600); // Valid for 1 hour

                        if (signedData) {
                            signedData.forEach((item, i) => {
                                if (item.signedUrl) {
                                    docs[docIndices[i]].data = item.signedUrl;
                                }
                            });
                        }
                    } catch (signErr) {
                        console.warn("Failed to sign URLs, proceeding with raw paths:", signErr);
                    }
                }

                return docs.sort((a, b) => new Date(b.uploadDate).getTime() - new Date(a.uploadDate).getTime());

            } catch (authError) {
                console.warn("Supabase (Audit Docs) unavailable, falling back to local storage:", authError);
                // Fallback proceed to local storage code below
            }
        }
        const data = localStorage.getItem(DOCS_KEY);
        if (!data) return [];
        const parsed = JSON.parse(data);
        return parsed.map((d: AuditDocument) => {
            const { data, ...rest } = d;
            return rest;
        });
    },

    async getContent(id: string): Promise<string | null> {
        if (isSupabaseEnabled()) {
            const { data, error } = await supabase
                .from('auditoria_documentos')
                .select('*')
                .eq('id', id)
                .single();

            if (error || !data) return null;

            const rawData = data.data; // This might be base64, http url, or storage path

            if (rawData && !rawData.startsWith('data:') && !rawData.startsWith('http')) {
                // It's a storage path, get signed URL
                const { data: signed } = await supabase.storage
                    .from('audit-docs')
                    .createSignedUrl(rawData, 3600);
                return signed?.signedUrl || null;
            }

            return rawData || null;
        }
        const raw = localStorage.getItem(DOCS_KEY);
        if (!raw) return null;
        const parsed = JSON.parse(raw);
        const doc = parsed.find((d: AuditDocument) => d.id === id);
        return doc ? doc.data : null;
    },

    async listByLab(labId: string): Promise<AuditDocument[]> {
        const allDocs = await this.list();
        return allDocs.filter(d => d.labId === labId);
    },

    async upload(doc: Omit<AuditDocument, 'id' | 'uploadDate' | 'status'>, file?: File): Promise<AuditDocument> {
        if (isSupabaseEnabled()) {
            let finalData = doc.data;

            // 1. Upload to Supabase Storage if file is provided
            if (file) {
                try {
                    console.log("DEBUG: Starting Storage Upload...", file.name);
                    const cleanName = file.name.replace(/[^a-zA-Z0-9.-]/g, '_');
                    const uniquePath = `${Date.now()}_${cleanName}`;

                    const { error: uploadError } = await supabase.storage
                        .from('audit-docs')
                        .upload(uniquePath, file, {
                            cacheControl: '3600',
                            upsert: false
                        });

                    if (uploadError) {
                        console.error("Storage Upload Failed:", uploadError);
                        throw uploadError;
                    }

                    // 2. Store RELATIVE PATH (for secure access)
                    finalData = uniquePath;
                    console.log("DEBUG: File stored at path:", finalData);
                } catch (err) {
                    console.error("Critical Storage Error:", err);
                    throw err;
                }
            }

            // Define possible schemas to retry automatically
            const strategies: Array<{ name: string, map: Record<string, string> }> = [
                {
                    name: 'lowercase',
                    map: {
                        name: 'name', fileName: 'filename', fileSize: 'filesize', fileType: 'filetype',
                        category: 'category', analystName: 'analystname', labId: 'labid',
                        status: 'status', data: 'data', uploadDate: 'uploaddate',
                        isTask: 'istask', deadline: 'deadline', assignedTo: 'assignedto', observation: 'observation'
                    }
                },
                {
                    name: 'snake_case',
                    map: {
                        name: 'name', fileName: 'file_name', fileSize: 'file_size', fileType: 'file_type',
                        category: 'category', analystName: 'analyst_name', labId: 'lab_id',
                        status: 'status', data: 'data', uploadDate: 'created_at',
                        isTask: 'is_task', deadline: 'deadline', assignedTo: 'assigned_to', observation: 'observation'
                    }
                },
                {
                    name: 'camelCase',
                    map: {
                        name: 'name', fileName: 'fileName', fileSize: 'fileSize', fileType: 'fileType',
                        category: 'category', analystName: 'analystName', labId: 'labId',
                        status: 'status', data: 'data', uploadDate: 'uploadDate',
                        isTask: 'isTask', deadline: 'deadline', assignedTo: 'assignedTo', observation: 'observation'
                    }
                }
            ];

            let lastError;

            for (const strategy of strategies) {
                console.log(`DEBUG: Trying DB insert strategy: ${strategy.name}`);
                try {
                    const payload: any = {};
                    payload[strategy.map.name] = doc.name;
                    payload[strategy.map.fileName] = doc.fileName;
                    payload[strategy.map.fileSize] = doc.fileSize;
                    payload[strategy.map.fileType] = doc.fileType;
                    payload[strategy.map.category] = doc.category;
                    payload[strategy.map.analystName] = doc.analystName;
                    payload[strategy.map.labId] = doc.labId; // Allow null/undefined
                    payload[strategy.map.status] = 'verified';
                    payload[strategy.map.data] = finalData;
                    payload[strategy.map.uploadDate] = new Date().toISOString();

                    if (doc.isTask !== undefined) payload[strategy.map.isTask] = doc.isTask;
                    if (doc.deadline) payload[strategy.map.deadline] = doc.deadline;
                    if (doc.assignedTo) payload[strategy.map.assignedTo] = doc.assignedTo;
                    if (doc.observation) payload[strategy.map.observation] = doc.observation;

                    Object.keys(payload).forEach(key => payload[key] === undefined && delete payload[key]);

                    const { data, error } = await supabase
                        .from('auditoria_documentos')
                        .insert([payload])
                        .select()
                        .single();

                    if (error) {
                        if (error.code === 'PGRST204' || error.code === '42703' || error.message?.includes('column')) {
                            console.warn(`Strategy ${strategy.name} failed with column error. Retrying...`);
                            lastError = error;
                            continue;
                        }
                        throw error;
                    }

                    console.log(`DEBUG: Strategy ${strategy.name} SUCCEEDED!`);

                    const d = data;
                    return {
                        id: d.id,
                        name: d.name,
                        fileName: d.fileName || d.filename || d.file_name,
                        fileSize: d.fileSize || d.filesize || d.file_size,
                        fileType: d.fileType || d.filetype || d.file_type,
                        uploadDate: d.uploadDate || d.uploaddate || d.upload_date || d.created_at,
                        category: d.category,
                        analystName: d.analystName || d.analystname || d.analyst_name,
                        status: d.status,
                        labId: d.labId || d.labid || d.lab_id,
                        data: d.data,
                        isTask: d.isTask || d.istask || d.is_task,
                        deadline: d.deadline,
                        assignedTo: d.assignedTo || d.assignedto || d.assigned_to,
                        observation: d.observation
                    };

                } catch (err: any) {
                    lastError = err;
                    if (err.code === 'PGRST204' || err.code === '42703' || err.message?.includes('column')) {
                        continue;
                    }
                    throw err;
                }
            }
            throw lastError;
        }

        const raw = localStorage.getItem(DOCS_KEY);
        const allDocs = raw ? JSON.parse(raw) : [];

        const newDoc: AuditDocument = {
            ...doc,
            id: crypto.randomUUID(),
            uploadDate: new Date().toISOString(),
            status: 'verified'
        };

        allDocs.push(newDoc);
        localStorage.setItem(DOCS_KEY, JSON.stringify(allDocs));
        return newDoc;
    },

    async delete(id: string): Promise<void> {
        if (isSupabaseEnabled()) {
            const { error } = await supabase.from('auditoria_documentos').delete().eq('id', id);
            if (error) throw error;
            return;
        }
        const raw = localStorage.getItem(DOCS_KEY);
        if (!raw) return;
        const docs = JSON.parse(raw);
        const filtered = docs.filter((d: AuditDocument) => d.id !== id);
        localStorage.setItem(DOCS_KEY, JSON.stringify(filtered));
    }
};

import { supabase } from "@/lib/supabase";

export interface Machine {
    id: string;
    machineId: string; // "ID da M├íquina" e.g. "HVI 01"
    serialNumber: string; // "N├║mero de S├®rie"
    model: 'USTER' | 'PREMIER';
    labId: string; // V├¡nculo com Laborat├│rio
    created_at?: string;
}

const STORAGE_KEY = 'fibertech_machines';

const isSupabaseEnabled = () => !!import.meta.env.VITE_SUPABASE_URL && !!import.meta.env.VITE_SUPABASE_ANON_KEY;

const getStoredMachines = (): Machine[] => {
    try {
        const data = localStorage.getItem(STORAGE_KEY);
        if (!data) return [];
        return JSON.parse(data);
    } catch {
        return [];
    }
};

const saveStoredMachines = (machines: Machine[]) => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(machines));
};

export const MachineService = {
    async list(): Promise<Machine[]> {
        if (isSupabaseEnabled()) {
            const { data, error } = await supabase.from('maquinas').select('*');
            if (error) throw error;

            if (data && data.length > 0) {
                return data.map((m: any) => ({
                    id: m.id,
                    machineId: m.identificacao,
                    serialNumber: m.numero_serie,
                    model: m.modelo,
                    labId: m.lab_id,
                    created_at: m.created_at
                }));
            }

            // CRITICAL SAFETY NET: If Supabase empty, fall back to avoid hiding data
            const localData = getStoredMachines();
            if (localData.length > 0) {
                console.warn("Supabase (Machines) empty. Using LOCAL STORAGE fallback.");
                return localData;
            }

            return []; // Nothing anywhere
        }
        return getStoredMachines();
    },

    async listByLab(labId: string): Promise<Machine[]> {
        if (isSupabaseEnabled()) {
            const { data, error } = await supabase
                .from('maquinas')
                .select('*')
                .eq('lab_id', labId);

            if (error) throw error;

            return data.map((m: any) => ({
                id: m.id,
                machineId: m.identificacao,
                serialNumber: m.numero_serie,
                model: m.modelo,
                labId: m.lab_id,
                created_at: m.created_at
            }));
        }
        return getStoredMachines().filter(m => m.labId === labId);
    },

    async create(data: Omit<Machine, 'id' | 'created_at'>): Promise<Machine> {
        if (isSupabaseEnabled()) {
            const dbData = {
                identificacao: data.machineId,
                numero_serie: data.serialNumber,
                modelo: data.model,
                lab_id: data.labId
            };

            const { data: newMachine, error } = await supabase
                .from('maquinas')
                .insert([dbData])
                .select()
                .single();

            if (error) throw error;

            return {
                id: newMachine.id,
                machineId: newMachine.identificacao,
                serialNumber: newMachine.numero_serie,
                model: newMachine.modelo,
                labId: newMachine.lab_id,
                created_at: newMachine.created_at
            };
        }

        const machines = getStoredMachines();
        const newMachine: Machine = {
            ...data,
            id: crypto.randomUUID(),
            created_at: new Date().toISOString()
        };
        machines.push(newMachine);
        saveStoredMachines(machines);
        return newMachine;
    },

    async update(id: string, data: Partial<Machine>): Promise<Machine> {
        if (isSupabaseEnabled()) {
            const dbUpdates: any = {};
            if (data.machineId) dbUpdates.identificacao = data.machineId;
            if (data.serialNumber) dbUpdates.numero_serie = data.serialNumber;
            if (data.model) dbUpdates.modelo = data.model;
            if (data.labId) dbUpdates.lab_id = data.labId;

            const { data: updated, error } = await supabase
                .from('maquinas')
                .update(dbUpdates)
                .eq('id', id)
                .select()
                .single();

            if (error) throw error;

            return {
                id: updated.id,
                machineId: updated.identificacao,
                serialNumber: updated.numero_serie,
                model: updated.modelo,
                labId: updated.lab_id,
                created_at: updated.created_at
            };
        }

        const machines = getStoredMachines();
        const index = machines.findIndex(m => m.id === id);
        if (index === -1) throw new Error("Machine not found");

        machines[index] = { ...machines[index], ...data };
        saveStoredMachines(machines);
        return machines[index];
    },

    async delete(id: string): Promise<void> {
        if (isSupabaseEnabled()) {
            const { error } = await supabase.from('maquinas').delete().eq('id', id);
            if (error) throw error;
            return;
        }

        const machines = getStoredMachines();
        const filtered = machines.filter(m => m.id !== id);
        saveStoredMachines(filtered);
    },

    subscribe(callback: () => void): () => void {
        if (!isSupabaseEnabled()) return () => { };

        const channel = supabase
            .channel('maquinas-changes')
            .on(
                'postgres_changes',
                { event: '*', schema: 'public', table: 'maquinas' },
                () => callback()
            )
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    }
};

