        campo: string;
        valor_anterior: any;
        valor_novo: any;
        tipo_modificacao: 'criacao' | 'edicao' | 'cor_alterada';
    }>;
}

const STORAGE_KEY = 'fibertech_samples';

const isSupabaseEnabled = () => !!import.meta.env.VITE_SUPABASE_URL && !!import.meta.env.VITE_SUPABASE_ANON_KEY;

const getStoredSamples = (): Sample[] => {
    try {
        const data = localStorage.getItem(STORAGE_KEY);
        if (!data) return [];
        const parsed = JSON.parse(data);
        return Array.isArray(parsed) ? parsed : [];
    } catch (error) {
        console.error("Error reading samples from storage", error);
        return [];
    }
};

const saveStoredSamples = (samples: Sample[]) => {
    try {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(samples));
    } catch (error) {
        console.error("Error saving samples to storage", error);
        throw error;
    }
};

export const SampleService = {
    async list(): Promise<Sample[]> {
        if (isSupabaseEnabled()) {
            const { data, error } = await supabase.from('amostras').select('*');
            if (error) throw error;
            if (data && data.length > 0) return data;

            // CRITICAL SAFETY NET
            const local = getStoredSamples();
            if (local.length > 0) {
                console.warn("Supabase (Samples) empty. Using Local Storage Fallback.");
                return local;
            }
            return [];
        }
        return getStoredSamples();
    },

    async listByLote(loteId: string): Promise<Sample[]> {
        if (isSupabaseEnabled()) {
            const { data, error } = await supabase.from('amostras').select('*').eq('lote_id', loteId).order('amostra_id');
            if (error) throw error;
            return data || [];
        }
        return getStoredSamples()
            .filter(s => s.lote_id === loteId)
            .sort((a, b) => a.amostra_id.localeCompare(b.amostra_id));
    },

    async create(data: Omit<Sample, 'id'>): Promise<Sample> {
        if (isSupabaseEnabled()) {
            const { data: newSample, error } = await supabase.from('amostras').insert([data]).select().single();
            if (error) throw error;
            return newSample;
        }

        const samples = getStoredSamples();
        const newSample: Sample = {
            ...data,
            id: Math.random().toString(36).substr(2, 9),
        };
        samples.push(newSample);
        saveStoredSamples(samples);
        return newSample;
    },

    async bulkCreate(dataList: Omit<Sample, 'id'>[]): Promise<Sample[]> {
        if (isSupabaseEnabled()) {
            const { data, error } = await supabase.from('amostras').insert(dataList).select();
            if (error) throw error;
            return data;
        }

        const samples = getStoredSamples();
        const newSamples = dataList.map(data => ({
            ...data,
            id: Math.random().toString(36).substr(2, 9),
        }));
        samples.push(...newSamples);
        saveStoredSamples(samples);
        return newSamples;
    },

    async update(id: string, data: Partial<Sample>): Promise<Sample> {
        if (isSupabaseEnabled()) {
            const { data: updated, error } = await supabase.from('amostras').update(data).eq('id', id).select().single();
            if (error) throw error;
            return updated;
        }

        const samples = getStoredSamples();
        const index = samples.findIndex(s => s.id === id);
        if (index === -1) throw new Error("Sample not found");

        samples[index] = { ...samples[index], ...data };
        saveStoredSamples(samples);
        return samples[index];
    },

    async bulkUpdate(updates: Record<string, Partial<Sample>>): Promise<void> {
        if (isSupabaseEnabled()) {
            // Supabase doesn't have a direct "bulk update different rows with different data" in one call easily like this
            // But we can use an RPC or multiple calls. For simplicity here, we'll do promise.all
            const promises = Object.entries(updates).map(([id, data]) =>
                supabase.from('amostras').update(data).eq('id', id)
            );
            await Promise.all(promises);
            return;
        }

        const samples = getStoredSamples();
        let changed = false;
        Object.entries(updates).forEach(([id, data]) => {
            const index = samples.findIndex(s => s.id === id);
            if (index !== -1) {
                samples[index] = { ...samples[index], ...data };
                changed = true;
            }
        });
        if (changed) saveStoredSamples(samples);
    },

    async delete(id: string): Promise<void> {
        if (isSupabaseEnabled()) {
            const { error } = await supabase.from('amostras').delete().eq('id', id);
            if (error) throw error;
            return;
        }

        const samples = getStoredSamples();
        const filtered = samples.filter(s => s.id !== id);
        saveStoredSamples(filtered);
    },

    subscribe(callback: () => void): () => void {
        if (!isSupabaseEnabled()) return () => { };

        const channel = supabase
            .channel(`amostras-changes-${Math.random().toString(36).substr(2, 9)}`)
            .on(
                'postgres_changes',
                { event: '*', schema: 'public', table: 'amostras' },
                () => callback()
            )
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    }
};

import * as XLSX from 'xlsx';

export interface ProducaoParsed {
    lab_id: string;
    identificador_unico: string;
    data_producao: string;
    turno: string;
    produto: string;
    peso: number;
    metadata: any;
}

const parseDate = (cell: any): string | null => {
    if (!cell) return null;
    if (typeof cell === 'number' && cell > 40000) {
        const date = XLSX.SSF.parse_date_code(cell);
        return `${date.y}-${String(date.m).padStart(2, '0')}-${String(date.d).padStart(2, '0')}`;
    }
    if (typeof cell === 'string') {
        const match = cell.match(/(\d{1,2})\/(\d{1,2})\/(\d{4})/);
        if (match) return `${match[3]}-${match[2].padStart(2, '0')}-${match[1].padStart(2, '0')}`;
    }
    return null;
};

export const parseProducaoFileInChunks = async (
    file: File,
    labId: string,
    onBatch: (batch: ProducaoParsed[]) => Promise<void>,
    batchSize: number = 2000
): Promise<number> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();

        reader.onload = async (e) => {
            try {
                const data = e.target?.result;
                const workbook = XLSX.read(data, { type: 'binary', dense: true });
                const sheetName = workbook.SheetNames[0];
                const worksheet = workbook.Sheets[sheetName];

                const rows: any[][] = XLSX.utils.sheet_to_json(worksheet, { header: 1, defval: "" });

                // 1. Detect Header Row for Machine Mapping
                let machineMap: Record<number, number> = {};
                let headerRowIndex = -1;

                for (let i = 0; i < Math.min(rows.length, 50); i++) {
                    const row = rows[i];
                    let foundNumbers = 0;
                    const tempMap: Record<number, number> = {};

                    row.forEach((cell, colIdx) => {
                        const val = parseInt(String(cell));
                        if (!isNaN(val) && val > 0 && val < 1000) {
                            tempMap[colIdx] = val;
                            foundNumbers++;
                        }
                    });

                    if (foundNumbers > 5) {
                        machineMap = tempMap;
                        headerRowIndex = i;
                        break;
                    }
                }

                if (headerRowIndex === -1) {
                    throw new Error("N├úo foi poss├¡vel detectar o cabe├ºalho das m├íquinas (1, 2, 3...) nas primeiras 50 linhas.");
                }

                console.log(`Detected machines at row ${headerRowIndex}:`, machineMap);

                let currentBlockDate: string | null = null;
                let currentTurnoLabel: string = "";
                let currentBatch: ProducaoParsed[] = [];
                let totalProcessed = 0;
                let rowsWithData = 0;

                for (let i = 0; i < rows.length; i++) {
                    if (i === headerRowIndex) continue;

                    const row = rows[i];
                    if (!row || row.length === 0) {
                        // Reset turno on empty row to avoid importing trailing summary/total rows
                        currentTurnoLabel = "";
                        continue;
                    }

                    // Check for valid content in row (not just nulls/empty strings)
                    const hasContent = row.some(cell => cell !== null && cell !== "" && cell !== undefined);
                    if (!hasContent) {
                        currentTurnoLabel = "";
                        continue;
                    }

                    // 1. Check for date in columns 0 or 1
                    const potentialDate = parseDate(row[0]) || parseDate(row[1]);
                    if (potentialDate) {
                        currentBlockDate = potentialDate;
                        // Important: if this is JUST a date row (no turno or data yet), 
                        // we might reset turno or wait for the next row to tell us.
                    }

                    // 2. Check for turno label in columns 0 or 1
                    const firstCell = String(row[0] || "").toUpperCase().trim();
                    const secondCell = String(row[1] || "").toUpperCase().trim();

                    if (firstCell.includes("TURNO")) currentTurnoLabel = firstCell;
                    else if (secondCell.includes("TURNO")) currentTurnoLabel = secondCell;

                    // 3. If we have date + turno, process data columns
                    if (currentBlockDate && currentTurnoLabel) {
                        let foundInRow = 0;

                        // Iterate through ALL columns that might have data
                        // We use the machineMap as reference indices
                        const machineIndices = Object.keys(machineMap).map(Number);

                        // We also check columns immediately to the LEFT of machine labels (offset handling)
                        const colsToCheck = new Set<number>();
                        machineIndices.forEach(idx => {
                            colsToCheck.add(idx);
                            if (idx > 0) colsToCheck.add(idx - 1);
                        });

                        const sortedCols = Array.from(colsToCheck).sort((a, b) => a - b);

                        for (const colIdx of sortedCols) {
                            const cell = row[colIdx];
                            if (cell === null || cell === "" || cell === undefined) continue;

                            let val = NaN;
                            if (typeof cell === 'number') val = cell;
                            else if (typeof cell === 'string' && cell.trim() !== "") {
                                const clean = cell.replace(/\./g, "").replace(",", ".");
                                // Verify it's not a date string mistakenly being parsed as value
                                if (!clean.includes("/") && !isNaN(parseFloat(clean))) {
                                    val = parseFloat(clean);
                                }
                            }

                            if (isNaN(val) || val < 0) continue;

                            // Find which machine this column belongs to
                            // Rule: Exact match first, then offset +1
                            let machineNumber: number | undefined = machineMap[colIdx];
                            if (machineNumber === undefined && machineMap[colIdx + 1] !== undefined) {
                                machineNumber = machineMap[colIdx + 1];
                            }

                            if (machineNumber !== undefined) {
                                currentBatch.push({
                                    lab_id: labId,
                                    identificador_unico: `${currentBlockDate}-${currentTurnoLabel.replace(/[^A-Z0-9]/g, "")}-MQ${machineNumber}`,
                                    data_producao: currentBlockDate,
                                    turno: currentTurnoLabel.replace(":", "").trim(),
                                    produto: `Linha/Mq ${machineNumber}`,
                                    peso: val,
                                    metadata: { source: 'excel_upload_streaming_robust' }
                                });
                                foundInRow++;
                            }
                        }

                        if (foundInRow > 0) {
                            rowsWithData++;
                        }

                        if (currentBatch.length >= batchSize) {
                            await onBatch(currentBatch);
                            totalProcessed += currentBatch.length;
                            currentBatch = [];
                        }
                    }
                }

                console.log(`Finished parsing. Total rows with data: ${rowsWithData}, Total records: ${totalProcessed + currentBatch.length}`);

                if (currentBatch.length > 0) {
                    await onBatch(currentBatch);
                    totalProcessed += currentBatch.length;
                }

                resolve(totalProcessed);
            } catch (error) {
                reject(error);
            }
        };

        reader.onerror = reject;
        reader.readAsBinaryString(file);
    });
};

import * as XLSX from 'xlsx';

export interface StatusOSRawData {
    Laborat├│rio: string;
    Contrato: string;
    Tomador: string;
    Cliente: string;
    Fazenda: string;
    Variedade: string;
    Usina: string;
    "O.S.": number | string;
    Romaneio: string | number;
    Inicial: string | number;
    Final: string | number;
    Amostras: number;
    Protocolo: number | string;
    "Nota Fiscal": string | null;
    Fatura: number | string | null;
    Status: string;
    Registrado: number; // Excel Serial Date
    Recep├º├úo: number; // Excel Serial Date
    Acondicionado: number; // Excel Serial Date
    Finalizado: number; // Excel Serial Date
    Revisor: string;
    Horas: number;
    "Peso  Mala": number;
    "Peso M├®dio Amostra": number;
}

export interface StatusOSParsed {
    os_numero: string;
    romaneio: string;
    cliente: string;
    fazenda: string;
    usina: string;
    variedade: string;

    data_registro: Date | null;
    data_recepcao: Date | null;
    data_acondicionamento: Date | null;
    data_finalizacao: Date | null;

    revisor: string;
    status: string;

    total_amostras: number;
    peso_mala: number;
    peso_medio: number;
    horas: number;

    nota_fiscal: string;
    fatura: string;
}

// Helper to convert Excel Serial Date to JS Date
function excelDateToJSDate(serial: number): Date | null {
    if (!serial || isNaN(serial)) return null;
    // Excel base date is Dec 30 1899.
    // However, there is a leap year bug in Excel (1900 is treated as leap year).
    // Usually: (serial - 25569) * 86400 * 1000
    // Adjusting for timezone might be needed, but usually we want UTC or Local.
    // Let's use a standard conversion.
    const utc_days = Math.floor(serial - 25569);
    const utc_value = utc_days * 86400;
    const date_info = new Date(utc_value * 1000);

    const fractional_day = serial - Math.floor(serial) + 0.0000001;
    const total_seconds = Math.floor(86400 * fractional_day);
    const seconds = total_seconds % 60;
    const minutes = Math.floor(total_seconds / 60) % 60;
    const hours = Math.floor(total_seconds / (60 * 60));

    return new Date(date_info.getFullYear(), date_info.getMonth(), date_info.getDate(), hours, minutes, seconds);
}

// New streaming/chunked parser
export const parseStatusOSFileInChunks = async (
    file: File,
    onBatch: (batch: StatusOSParsed[]) => Promise<void>,
    batchSize: number = 2000
): Promise<number> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();

        reader.onload = async (e) => {
            try {
                const data = e.target?.result;
                // Use dense mode for better memory usage
                const workbook = XLSX.read(data, { type: 'binary', dense: true, cellDates: true });
                const sheetName = workbook.SheetNames[0];
                const worksheet = workbook.Sheets[sheetName];

                // Detectamos o range real para garantir que pegamos tudo
                XLSX.utils.decode_range(worksheet['!ref'] || 'A1');

                // Usamos stream_to_json ou similar se dispon├¡vel, mas aqui otimizamos o sheet_to_json
                const rawData = XLSX.utils.sheet_to_json<StatusOSRawData>(worksheet, {
                    range: 6, // Come├ºa na linha 7 (0-indexed + header)
                    raw: false,
                    defval: ""
                });

                let currentBatch: StatusOSParsed[] = [];
                let totalProcessed = 0;

                for (const row of rawData) {
                    const getVal = (possibleKeys: string[]) => {
                        const rowKeys = Object.keys(row);
                        for (const pk of possibleKeys) {
                            const match = rowKeys.find(k => k.trim().toLowerCase() === pk.trim().toLowerCase());
                            if (match && row[match as keyof StatusOSRawData] !== undefined) return row[match as keyof StatusOSRawData];
                        }
                        return undefined;
                    };

                    const parseExcelDate = (val: any): Date | null => {
                        if (!val) return null;
                        if (val instanceof Date) return val;
                        if (typeof val === 'number') return excelDateToJSDate(val);
                        if (typeof val === 'string') {
                            const d = new Date(val);
                            if (!isNaN(d.getTime())) return d;
                            // Tenta formato DD/MM/YYYY
                            const parts = val.split(/[/-]/);
                            if (parts.length === 3) {
                                if (parts[2].length === 4) return new Date(Number(parts[2]), Number(parts[1]) - 1, Number(parts[0]));
                                if (parts[0].length === 4) return new Date(Number(parts[0]), Number(parts[1]) - 1, Number(parts[2]));
                            }
                        }
                        return null;
                    };

                    const parseNum = (val: any): number => {
                        if (typeof val === 'number') return val;
                        if (!val) return 0;
                        const str = String(val).replace(/\./g, '').replace(',', '.').trim();
                        const n = parseFloat(str);
                        return isNaN(n) ? 0 : n;
                    };

                    const tomadorVal = String(getVal(["Tomador", "Contratante", "tomador"]) || "").trim();
                    const clienteVal = String(getVal(["Cliente", "Benefici├írio", "cliente"]) || "").trim();
                    let finalCliente = clienteVal;
                    if (tomadorVal && clienteVal && tomadorVal !== clienteVal) {
                        finalCliente = `${tomadorVal}|||${clienteVal}`;
                    } else if (tomadorVal && !clienteVal) {
                        finalCliente = tomadorVal;
                    }

                    const parsed: StatusOSParsed = {
                        os_numero: String(getVal(["O.S.", "OS", "Ordem de Servi├ºo", "os"]) || ""),
                        romaneio: String(getVal(["Romaneio", "Rom", "romaneio"]) || ""),
                        cliente: finalCliente,
                        fazenda: String(getVal(["Fazenda", "Faz", "fazenda"]) || ""),
                        usina: String(getVal(["Usina", "unidade", "usina"]) || ""),
                        variedade: String(getVal(["Variedade", "Var", "variedade"]) || ""),

                        data_registro: parseExcelDate(getVal(["Registrado", "Data Registro", "Registro", "registrado", "Dt. Registro", "Dt Registro"])),
                        data_recepcao: parseExcelDate(getVal(["Recep├º├úo", "Data Recep├º├úo", "Recepcao", "recepcao", "Dt. Recep├º├úo", "Dt Recep├º├úo", "Dt. Recepc├úo", "Dt Recepc├úo"])),
                        data_acondicionamento: parseExcelDate(getVal(["Acondicionado", "Data Acondicionamento", "acondicionado", "Dt. Acondicionado"])),
                        data_finalizacao: parseExcelDate(getVal(["Finalizado", "Data Finaliza├º├úo", "Finaliza├º├úo", "finalizado", "Dt. Finaliza├º├úo", "Dt Finaliza├º├úo"])),

                        revisor: String(getVal(["Revisor", "Analista", "revisor"]) || ""),
                        status: String(getVal(["Status", "Situa├º├úo", "status"]) || ""),

                        total_amostras: parseNum(getVal(["Amostras", "Qtde", "Quantidade", "Total Amostras", "amostras"])),
                        peso_mala: parseNum(getVal(["Peso Mala", "Peso  Mala", "peso_mala"])),
                        peso_medio: parseNum(getVal(["Peso M├®dio Amostra", "Peso M├®dio", "Peso Medio", "peso_medio"])),
                        horas: parseNum(getVal(["Horas", "Dura├º├úo", "horas"])),

                        nota_fiscal: String(getVal(["Nota Fiscal", "NF", "nota_fiscal"]) || ""),
                        fatura: String(getVal(["Fatura", "Fat", "fatura"]) || ""),
                    };

                    if (parsed.os_numero || parsed.cliente || parsed.romaneio) {
                        currentBatch.push(parsed);
                    }

                    if (currentBatch.length >= batchSize) {
                        await onBatch(currentBatch);
                        totalProcessed += currentBatch.length;
                        currentBatch = [];
                    }
                }

                // Final batch
                if (currentBatch.length > 0) {
                    await onBatch(currentBatch);
                    totalProcessed += currentBatch.length;
                }

                resolve(totalProcessed);
            } catch (error) {
                reject(error);
            }
        };

        reader.onerror = (error) => reject(error);
        reader.readAsBinaryString(file);
    });
};

export const parseStatusOSFile = async (file: File): Promise<StatusOSParsed[]> => {
    // Legacy support or wrapper
    const allData: StatusOSParsed[] = [];
    await parseStatusOSFileInChunks(file, async (batch) => {
        allData.push(...batch);
    });
    return allData;
};

