// Interfaces
import { MachineService } from "@/entities/Machine";
import type { Machine } from "@/entities/Machine";

function SystemConfigTab() {
    const { user, currentLab } = useAuth();
    const { addToast } = useToast();
    const [machines, setMachines] = useState<Machine[]>([]);
    const [labs, setLabs] = useState<Lab[]>([]);

    // Form State
    const [editingId, setEditingId] = useState<string | null>(null);
    const [formMachineId, setFormMachineId] = useState("");
    const [formSerialNumber, setFormSerialNumber] = useState("");
    const [formModel, setFormModel] = useState<'USTER' | 'PREMIER'>("USTER");
    const [formLabId, setFormLabId] = useState("");

    useEffect(() => {
        const targetLabId = (currentLab?.id || (user?.acesso === 'admin_lab' ? user.lab_id : "")) || "";
        setFormLabId(targetLabId);
        loadData();
        // Subscribe to real-time changes
        const unsubscribe = MachineService.subscribe(() => {
            loadData();
        });
        return () => unsubscribe();
    }, [user, currentLab]);

    const loadData = async () => {
        // Load Labs for name resolution
        try {
            const labsData = await LabService.list();
            setLabs(labsData);
        } catch (e) {
            console.error("Failed to load labs", e);
        }

        // Load Machines
        try {
            const isGlobalAdmin = user?.acesso === 'admin_global';
            const targetLabId = currentLab?.id || (user?.acesso === 'admin_lab' ? user.lab_id : null);
            let data: Machine[] = [];

            if (targetLabId && !isGlobalAdmin) {
                // Fetch only for the specific lab
                data = await MachineService.listByLab(targetLabId);
            } else {
                // Fetch all if global admin or no specific lab context
                data = await MachineService.list();
            }

            setMachines(data);
        } catch (error) {
            console.error("Failed to load machines:", error);
            addToast({ title: "Erro ao carregar m├íquinas", type: "error" });
        }
    };

    const handleSaveMachine = async () => {
        if (!formMachineId.trim()) {
            addToast({ title: "ID da M├íquina obrigat├│rio", type: "error" });
            return;
        }
        if (!formSerialNumber.trim()) {
            addToast({ title: "N├║mero de S├®rie obrigat├│rio", type: "error" });
            return;
        }

        if (!formLabId) {
            addToast({ title: "Erro: Nenhum laborat├│rio selecionado", type: "error" });
            return;
        }

        try {
            const payload = {
                machineId: formMachineId.toUpperCase(),
                serialNumber: formSerialNumber.toUpperCase(),
                model: formModel,
                labId: formLabId
            };

            if (editingId) {
                await MachineService.update(editingId, payload);
                addToast({ title: "M├íquina Atualizada", type: "success" });
            } else {
                await MachineService.create(payload as any);
                addToast({ title: "M├íquina Adicionada", type: "success" });
            }

            // Reload data
            loadData();
            resetForm();

        } catch (error) {
            console.error("Error saving machine", error);
            addToast({ title: "Erro ao salvar m├íquina", type: "error" });
        }
    };

    const handleEditClick = (machine: Machine) => {
        setEditingId(machine.id);
        setFormMachineId(machine.machineId);
        setFormSerialNumber(machine.serialNumber);
        setFormModel(machine.model);
        setFormLabId(machine.labId);
    };

    const handleRemoveMachine = async (id: string) => {
        if (confirm("Remover esta m├íquina?")) {
            try {
                await MachineService.delete(id);
                addToast({ title: "M├íquina Removida", type: "info" });
                loadData();
                if (editingId === id) resetForm();
            } catch (error) {
                console.error("Error deleting machine", error);
                addToast({ title: "Erro ao remover m├íquina", type: "error" });
            }
        }
    };

    const resetForm = () => {
        setEditingId(null);
        setFormMachineId("");
        setFormSerialNumber("");
        setFormModel("USTER");
    };

    // Helper to get lab name
    const getLabName = (id: string) => {
        return labs.find(l => l.id === id)?.nome || "Lab Desconhecido";
    };

    return (
        <div className="grid gap-8 lg:grid-cols-12">
            {/* Coluna Principal: M├íquinas */}
            <div className="lg:col-span-12 border border-neutral-200 bg-white p-10 space-y-8 shadow-sm">
                <div className="flex items-center justify-between border-b border-black pb-4">
                    <h3 className="text-xl font-serif">M├íquinas Registradas (HVI)</h3>
                    <Server className="h-5 w-5" />
                </div>

                {/* Lista de M├íquinas */}
                <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {machines.map(machine => (
                        <div key={machine.id} className={cn(
                            "group relative flex flex-col justify-between p-6 bg-neutral-50 border transition-all",
                            editingId === machine.id ? "border-black ring-1 ring-black bg-white" : "border-neutral-200 hover:border-black"
                        )}>
                            <div className="space-y-4 mb-4">
                                <div className="flex items-center justify-between">
                                    <div className="h-10 w-10 bg-white border border-neutral-200 flex items-center justify-center font-bold text-sm font-serif">
                                        {(machine.machineId || "??").substring(0, 2)}
                                    </div>
                                    <span className={cn(
                                        "text-[9px] font-bold uppercase px-2 py-0.5 rounded-full inline-block",
                                        machine.model === 'USTER' ? "bg-emerald-100 text-emerald-700" : "bg-blue-100 text-blue-700"
                                    )}>
                                        {machine.model || "N/A"}
                                    </span>
                                </div>

                                <div className="pt-2 border-t border-dashed border-neutral-200">
                                    <span className="text-[9px] font-mono text-neutral-400 uppercase block mb-1">Laborat├│rio Vinculado</span>
                                    <div className="flex items-center gap-2">
                                        <Database className="h-3 w-3 text-neutral-400" />
                                        <span className="text-xs font-bold text-black uppercase truncate max-w-[150px]">
                                            {getLabName(machine.labId)}
                                        </span>
                                    </div>
                                </div>

                                <div>
                                    <span className="text-[10px] font-mono text-neutral-400 uppercase">ID da M├íquina</span>
                                    <h4 className="text-sm font-bold uppercase tracking-widest text-black">{machine.machineId}</h4>
                                </div>
                                <div>
                                    <span className="text-[10px] font-mono text-neutral-400 uppercase">N├║mero de S├®rie</span>
                                    <p className="text-xs font-mono text-neutral-600">{machine.serialNumber}</p>
                                </div>
                            </div>

                            <div className="flex items-center gap-2 pt-4 border-t border-neutral-100 opacity-40 group-hover:opacity-100 transition-opacity">
                                <Button
                                    variant="outline"
                                    size="sm"
                                    onClick={() => handleEditClick(machine)}
                                    className="flex-1 h-8 text-[9px] uppercase tracking-widest hover:bg-black hover:text-white"
                                >
                                    <Edit className="h-3 w-3 mr-2" /> Editar
                                </Button>
                                <Button
                                    variant="ghost"
                                    size="icon"
                                    onClick={() => handleRemoveMachine(machine.id)}
                                    className="h-8 w-8 text-neutral-400 hover:text-red-600"
                                >
                                    <Trash2 className="h-3 w-3" />
                                </Button>
                            </div>
                        </div>
                    ))}

                    {machines.length === 0 && (
                        <div className="col-span-full text-center p-12 border-2 border-dashed border-neutral-200 text-neutral-400 text-xs font-mono uppercase">
                            Nenhuma m├íquina HVI cadastrada.
                        </div>
                    )}
                </div>

                {/* Formul├írio de Adi├º├úo/Edi├º├úo */}
                <div className={cn(
                    "pt-8 border-t border-dashed border-neutral-200 space-y-6 transition-all",
                    editingId ? "bg-neutral-50 -mx-10 px-10 py-10 border-b border-black" : ""
                )}>
                    <div className="flex items-center justify-between">
                        <h4 className="text-xs font-bold uppercase tracking-widest text-neutral-500">
                            {editingId ? "Editando M├íquina" : "Adicionar Nova M├íquina"}
                        </h4>
                        {editingId && (
                            <button onClick={resetForm} className="text-[10px] font-bold uppercase text-red-500 hover:underline">
                                Cancelar Edi├º├úo
                            </button>
                        )}
                    </div>

                    <div className="grid md:grid-cols-12 gap-4 items-end">
                        {/* Campo ID */}
                        <div className="md:col-span-2 space-y-1">
                            <label className="text-[9px] font-bold uppercase text-neutral-400">ID da M├íquina</label>
                            <input
                                type="text"
                                placeholder="EX: HVI 02"
                                value={formMachineId}
                                onChange={e => setFormMachineId(e.target.value)}
                                className="w-full h-12 px-4 border border-neutral-200 text-xs font-mono uppercase bg-white focus:outline-none focus:border-black transition-colors"
                            />
                        </div>

                        {/* Campo Serial */}
                        <div className="md:col-span-3 space-y-1">
                            <label className="text-[9px] font-bold uppercase text-neutral-400">N├║mero de S├®rie</label>
                            <input
                                type="text"
                                placeholder="EX: 123456789"
                                value={formSerialNumber}
                                onChange={e => setFormSerialNumber(e.target.value)}
                                className="w-full h-12 px-4 border border-neutral-200 text-xs font-mono uppercase bg-white focus:outline-none focus:border-black transition-colors"
                            />
                        </div>                        {/* Campo Lab (Only for Global Admin) */}
                        <div className="md:col-span-3 space-y-1">
                            <label className="text-[9px] font-bold uppercase text-neutral-400">Laborat├│rio</label>
                            <select
                                value={formLabId}
                                onChange={e => setFormLabId(e.target.value)}
                                disabled={user?.acesso !== 'admin_global' && !!(currentLab?.id || user?.lab_id)}
                                className="w-full h-12 px-4 border border-neutral-200 text-xs font-mono uppercase bg-white focus:outline-none focus:border-black transition-colors disabled:opacity-50"
                                title="Selecione o laborat├│rio"
                                aria-label="Selecione o laborat├│rio"
                            >
                                <option value="">SELECIONE O LAB</option>
                                {labs.map(l => (
                                    <option key={l.id} value={l.id}>{l.nome} ({l.codigo})</option>
                                ))}
                            </select>
                        </div>
                        {/* Campo Modelo */}
                        <div className="md:col-span-2 space-y-1">
                            <label className="text-[9px] font-bold uppercase text-neutral-400">Modelo HVI</label>
                            <div className="flex h-12 border border-neutral-200 bg-white">
                                <button
                                    onClick={() => setFormModel("USTER")}
                                    className={cn(
                                        "flex-1 text-[9px] font-bold uppercase tracking-widest transition-colors border-r border-neutral-200",
                                        formModel === "USTER" ? "bg-black text-white" : "text-neutral-400 hover:text-black"
                                    )}
                                >
                                    USTER
                                </button>
                                <button
                                    onClick={() => setFormModel("PREMIER")}
                                    className={cn(
                                        "flex-1 text-[9px] font-bold uppercase tracking-widest transition-colors",
                                        formModel === "PREMIER" ? "bg-black text-white" : "text-neutral-400 hover:text-black"
                                    )}
                                >
                                    PREMIER
                                </button>
                            </div>
                        </div>

                        {/* Bot├úo de A├º├úo */}
                        <div className="md:col-span-2">
                            <Button
                                onClick={handleSaveMachine}
                                className={cn(
                                    "w-full h-12 rounded-none font-bold uppercase text-[10px] tracking-widest",
                                    editingId ? "bg-blue-600 hover:bg-blue-700 text-white" : "bg-black hover:bg-neutral-800 text-white"
                                )}
                            >
                                {editingId ? "Atualizar" : "Adicionar"}
                            </Button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    )
}

import { useState, useEffect } from "react";
import { useSearchParams, useNavigate } from "react-router-dom";
import {
    ArrowLeft,
    Plus,
    Download,
    Filter,
    Wand2,
    Activity
} from "lucide-react";
import { Button } from "@/components/ui/button";
import type { Sample } from "@/entities/Sample";
import type { Lote } from "@/entities/Lote";
import { SampleService } from "@/entities/Sample";
import { LoteService } from "@/entities/Lote";
import AnalysisTable from "@/components/analysis/AnalysisTable";
import StatisticsPanel from "@/components/analysis/StatisticsPanel";
import MovingAverageChart from "@/components/analysis/MovingAverageChart";
import PatternAnalysisModal from "@/components/analysis/PatternAnalysisModal";
import { useToast } from "@/contexts/ToastContext";
import { useAuth } from "@/contexts/AuthContext";
import HVIStatisticalReportModal from "@/components/analysis/HVIStatisticalReportModal";

export default function Analysis() {
    const [searchParams] = useSearchParams();
    const navigate = useNavigate();
    const { addToast } = useToast();
    const loteId = searchParams.get("loteId");

    const [lote, setLote] = useState<Lote | null>(null);
    const [samples, setSamples] = useState<Sample[]>([]);
    const [isProcessing, setIsProcessing] = useState(false);
    const [filterColor, setFilterColor] = useState<string | null>(null);

    const handleExportCSV = () => {
        if (!samples.length || !lote) return;

        const headers = ["Amostra", "Mala", "Etiqueta", "HVI", "MIC", "LEN", "UNF", "STR", "RD", "B", "Cor"];
        const rows = samples.map(s => [
            s.amostra_id,
            s.mala || "",
            s.etiqueta || "",
            s.hvi || "",
            s.mic?.toString().replace(".", ",") || "",
            s.len?.toString().replace(".", ",") || "",
            s.unf?.toString().replace(".", ",") || "",
            s.str?.toString().replace(".", ",") || "",
            s.rd?.toString().replace(".", ",") || "",
            s.b?.toString().replace(".", ",") || "",
            s.cor || ""
        ]);

        const csvContent = [
            headers.join(";"),
            ...rows.map(r => r.join(";"))
        ].join("\n");

        const blob = new Blob(["\ufeff" + csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.setAttribute("href", url);
        link.setAttribute("download", `Analise_${lote.nome}_${new Date().toLocaleDateString()}.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);

        addToast({ title: "Report Generated", description: "CSV file downloaded successfully.", type: "success" });
    };

    const { user } = useAuth();

    useEffect(() => {
        if (loteId) {
            loadData();

            // Subscribe to real-time changes
            const unsubSamples = SampleService.subscribe(() => {
                loadData();
            });
            const unsubLotes = LoteService.subscribe(() => {
                loadData();
            });

            return () => {
                unsubSamples();
                unsubLotes();
            };
        }
    }, [loteId, user]);

    const loadData = async () => {
        if (!loteId) return;
        const l = await LoteService.get(loteId);

        if (l) {
            if (user?.acesso !== 'admin_global' && user?.lab_id && l.lab_id && l.lab_id !== user.lab_id) {
                addToast({ title: "Access Denied", description: "You cannot access batches from other laboratories.", type: "error" });
                navigate("/");
                return;
            }
            setLote(l);
        }

        const s = await SampleService.listByLote(loteId);
        setSamples(s);
    };

    const handleUpdateSample = async (id: string, field: string, value: any) => {
        setIsProcessing(true);
        try {
            await SampleService.update(id, { [field]: value });
            await loadData();
            addToast({ title: "Value Updated", type: "success" });
        } catch (error) {
            addToast({ title: "Update Failed", type: "error" });
        } finally {
            setIsProcessing(false);
        }
    };

    const handleColorChange = async (id: string, color: string) => {
        setIsProcessing(true);
        try {
            await SampleService.update(id, { cor: color });
            await loadData();
            addToast({ title: "Classified", type: "success" });
        } catch (error) {
            addToast({ title: "Error", type: "error" });
        } finally {
            setIsProcessing(false);
        }
    };

    const handleDeleteSample = async (id: string) => {
        if (!confirm("This action is irreversible. Delete sample?")) return;
        setIsProcessing(true);
        try {
            await SampleService.delete(id);
            await loadData();
            addToast({ title: "Sample Removed", type: "success" });
        } catch (error) {
            addToast({ title: "Remove Failed", type: "error" });
        } finally {
            setIsProcessing(false);
        }
    };

    const [isPatternModalOpen, setIsPatternModalOpen] = useState(false);
    const [isStatsModalOpen, setIsStatsModalOpen] = useState(false);

    const handleBulkColorUpdate = async (updates: Record<string, string>) => {
        setIsProcessing(true);
        try {
            const bulkPayload: Record<string, Partial<Sample>> = {};
            Object.entries(updates).forEach(([id, color]) => {
                bulkPayload[id] = { cor: color };
            });

            await SampleService.bulkUpdate(bulkPayload);
            await loadData();
            addToast({ title: "Patterns Applied", description: "Samples classified successfully.", type: "success" });
        } catch (error) {
            addToast({ title: "Classification Failed", type: "error" });
        } finally {
            setIsProcessing(false);
        }
    };

    if (!loteId) return <div className="p-10 text-center font-mono uppercase tracking-widest text-[10px]">NO_BATCH_ID</div>;
    if (!lote) return <div className="p-10 text-center animate-pulse font-mono uppercase tracking-widest text-[10px]">LOADING_METRICS...</div>;

    const filteredSamples = filterColor
        ? samples.filter(s => s.cor === filterColor)
        : samples;

    return (
        <div className="space-y-12 animate-fade-in relative pb-24 text-black">
            {/* Header */}
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-8 border-b border-black pb-8">
                <div className="space-y-4">
                    <div className="flex items-center gap-6">
                        <Button
                            variant="ghost"
                            size="icon"
                            onClick={() => navigate(-1)}
                            className="rounded-none hover:bg-neutral-100 text-black h-10 w-10 border border-neutral-200"
                        >
                            <ArrowLeft className="h-4 w-4" />
                        </Button>
                        <div className="space-y-1">
                            <div className="flex items-center gap-3">
                                <h1 className="text-3xl font-serif text-black leading-none">
                                    Global Analysis <span className="text-[10px] text-slate-400 align-top">v1.1</span>
                                </h1>
                                <span className={`text-[9px] font-bold uppercase tracking-widest border border-black px-2 py-0.5 ${lote.status === 'aberto' ? 'bg-black text-white' : 'bg-transparent text-black'}`}>
                                    {lote.status === 'aberto' ? 'Active' : 'Archived'}
                                </span>
                            </div>
                            <p className="font-mono text-neutral-500 text-xs uppercase tracking-widest">
                                BATCH: {lote.nome}
                            </p>
                        </div>
                    </div>
                </div>

                <div className="flex items-center gap-4">
                    <Button
                        onClick={() => setIsPatternModalOpen(true)}
                        className="rounded-none h-12 px-6 bg-white border border-black text-black hover:bg-black hover:text-white font-bold text-[10px] uppercase tracking-widest transition-colors flex items-center gap-2"
                    >
                        <Wand2 className="h-4 w-4" />
                        Auto-Classify
                    </Button>
                    <Button
                        onClick={() => setIsStatsModalOpen(true)}
                        className="rounded-none h-12 px-6 bg-white border border-black text-black hover:bg-black hover:text-white font-bold text-[10px] uppercase tracking-widest transition-colors flex items-center gap-2"
                    >
                        <Activity className="h-4 w-4" />
                        AI Patterns
                    </Button>
                    <Button
                        onClick={handleExportCSV}
                        className="rounded-none h-12 px-6 bg-white border border-black text-black hover:bg-black hover:text-white font-bold text-[10px] uppercase tracking-widest transition-colors"
                    >
                        <Download className="mr-2 h-3 w-3" /> Export CSV
                    </Button>
                    <Button
                        onClick={() => navigate(`/registro?loteId=${loteId}`)}
                        className="rounded-none h-12 px-6 bg-black text-white hover:bg-neutral-800 font-bold text-[10px] uppercase tracking-widest transition-colors"
                    >
                        <Plus className="mr-2 h-3 w-3" /> Add Sample
                    </Button>
                </div>
            </div>

            <div className="space-y-12">
                {/* Metrics Header */}
                <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-6 border border-neutral-200 p-6 bg-neutral-50">
                    <div className="flex items-center gap-2">
                        <Filter className="h-4 w-4 text-black" />
                        <span className="text-[10px] uppercase tracking-widest font-bold">Grade Filter</span>
                    </div>

                    <div className="flex flex-wrap items-center gap-2">
                        {(['#10b981', '#f59e0b', '#ef4444', '#3b82f6'] as const).map(c => (
                            <button
                                key={c}
                                onClick={() => setFilterColor(filterColor === c ? null : c)}
                                className={`w-8 h-8 transition-all border border-neutral-300 ${filterColor === c ? 'ring-2 ring-black ring-offset-2' : 'hover:opacity-80'}`}
                                style={{ backgroundColor: c }}
                            />
                        ))}
                        {filterColor && (
                            <Button variant="ghost" size="sm" onClick={() => setFilterColor(null)} className="h-8 px-4 ml-2 rounded-none text-[9px] font-bold text-black border border-black hover:bg-black hover:text-white uppercase">
                                Clear
                            </Button>
                        )}
                        <div className="h-8 w-[1px] bg-neutral-300 mx-4 hidden md:block" />
                        <span className="text-xs font-mono font-bold">
                            {filteredSamples.length} RECORDS
                        </span>
                    </div>
                </div>

                {/* Table Container */}
                <div className="overflow-hidden border border-black">
                    <div className="overflow-x-auto">
                        <AnalysisTable
                            samples={filteredSamples}
                            onUpdateSample={handleUpdateSample}
                            onColorChange={handleColorChange}
                            onDeleteSample={handleDeleteSample}
                            isProcessing={isProcessing}
                            highlightedSampleId={null}
                        />
                    </div>
                </div>
            </div>

            {/* Statistics */}
            <div className="space-y-8 pt-12 border-t border-neutral-200">
                <h2 className="font-serif text-2xl text-black">Performance Metrics</h2>
                <StatisticsPanel samples={samples} selectedColor={filterColor} />

                <div className="pt-12">
                    <MovingAverageChart
                        samples={samples}
                    />
                </div>
            </div>

            <PatternAnalysisModal
                isOpen={isPatternModalOpen}
                onClose={() => setIsPatternModalOpen(false)}
                samples={samples}
                onApplyColors={handleBulkColorUpdate}
            />

            <HVIStatisticalReportModal
                isOpen={isStatsModalOpen}
                onClose={() => setIsStatsModalOpen(false)}
                samples={samples}
            />
        </div>
    );
}

import { useState, useEffect } from "react";
import {
    Plus,
    X,
    Search,
    LayoutGrid,
    List,
    CheckCircle2,
    Trash2,
    Calendar,
    ClipboardCheck,
    CheckCircle,
    ChevronRight,
    SearchCheck,
    Briefcase
} from "lucide-react";
import { useAuth } from "@/contexts/AuthContext";
import { Navigate } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { useToast } from "@/contexts/ToastContext";
import { AuditService, type AuditDocument } from "@/entities/Audit";
import { LabService } from "@/entities/Lab";
import { AnalistaService, type Analista } from "@/entities/Analista";
import { cn } from "@/lib/utils";

/**
 * Checklist Page - Modern Implementation
 */
export default function Checklist() {
    const { user, currentLab, selectLab } = useAuth();
    const { addToast } = useToast();

    // Access control
    if (user && !['admin_global', 'admin_lab', 'quality_admin'].includes(user.acesso)) {
        return <Navigate to="/" replace />;
    }

    // State
    const [items, setItems] = useState<AuditDocument[]>([]);
    const [labs, setLabs] = useState<any[]>([]);
    const [analysts, setAnalysts] = useState<Analista[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
    const [searchTerm, setSearchTerm] = useState("");
    const [filterStatus, setFilterStatus] = useState<'all' | 'pending' | 'completed'>('all');

    // Sidebar State
    const [isSidebarOpen, setIsSidebarOpen] = useState(false);

    // Form State
    const [formData, setFormData] = useState({
        name: "",
        assignedTo: "",
        deadline: "",
        observation: ""
    });

    useEffect(() => {
        loadData();
    }, [user, currentLab]);

    const loadData = async () => {
        setIsLoading(true);
        try {
            const labsData = await LabService.list().catch(() => []);
            setLabs(labsData);

            const targetLabId = currentLab?.id || user?.lab_id;
            const [docs, anals] = await Promise.all([
                targetLabId ? AuditService.listByLab(targetLabId) : AuditService.list(),
                AnalistaService.list()
            ]);

            setItems(docs);
            setAnalysts(anals);
        } catch (error) {
            addToast({ title: "Erro na sincroniza├º├úo", type: "error" });
        } finally {
            setIsLoading(false);
        }
    };

    const handleCreateItem = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.name) {
            addToast({ title: "O t├¡tulo ├® obrigat├│rio", type: "error" });
            return;
        }

        try {
            const targetLabId = currentLab?.id || user?.lab_id;
            await AuditService.upload({
                name: formData.name,
                fileName: formData.name + '.task',
                fileSize: 0,
                fileType: 'task/custom',
                category: 'Checklist Operacional',
                analystName: user?.nome || 'Analista',
                labId: targetLabId || undefined,
                isTask: true,
                deadline: formData.deadline,
                assignedTo: formData.assignedTo || undefined,
                observation: formData.observation
            });

            addToast({ title: 'Atividade Registrada!', type: 'success' });
            setFormData({ name: "", assignedTo: "", deadline: "", observation: "" });
            setIsSidebarOpen(false);
            loadData();
        } catch (error: any) {
            addToast({ title: 'Erro ao registrar', description: error.message, type: 'error' });
        }
    };

    const handleToggleStatus = async (item: AuditDocument) => {
        try {
            const { supabase } = await import('@/lib/supabase');
            const nextStatus = item.status === 'completed' ? 'verified' : 'completed';

            const { error } = await supabase
                .from('auditoria_documentos')
                .update({ status: nextStatus })
                .eq('id', item.id);

            if (error) throw error;

            loadData();
            addToast({
                title: nextStatus === 'completed' ? 'Atividade Conclu├¡da' : 'Atividade Reaberta',
                type: 'success'
            });
        } catch (e) {
            addToast({ title: 'Erro ao atualizar status', type: 'error' });
        }
    };

    const handleDeleteItem = async (id: string) => {
        if (confirm("Confirmar exclus├úo deste item?")) {
            await AuditService.delete(id);
            addToast({ title: "Item removido", type: "info" });
            loadData();
        }
    };

    const filteredItems = items.filter(item => {
        const matchesSearch = item.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
            (item.observation?.toLowerCase().includes(searchTerm.toLowerCase()));

        if (filterStatus === 'all') return matchesSearch;
        return matchesSearch && (filterStatus === 'completed' ? item.status === 'completed' : item.status !== 'completed');
    });

    // const pendingCount = items.filter(i => i.status !== 'completed').length;
    // const completedCount = items.filter(i => i.status === 'completed').length;

    // Unit Selection for Global Admins
    if (user?.acesso === 'admin_global' && !currentLab) {
        return (
            <div className="min-h-[85vh] flex flex-col items-center justify-center p-8 bg-white">
                <div className="max-w-4xl w-full space-y-16 animate-in fade-in slide-in-from-bottom-8 duration-700">
                    <div className="text-center space-y-4">
                        <div className="inline-flex items-center justify-center h-16 w-16 bg-neutral-900 rounded-3xl shadow-2xl mb-4">
                            <ClipboardCheck className="h-8 w-8 text-white" />
                        </div>
                        <h1 className="text-6xl font-serif text-black tracking-tighter">
                            Checklist <span className="font-light italic text-neutral-300">Estrat├®gico</span>
                        </h1>
                        <p className="text-lg text-neutral-500 font-light max-w-lg mx-auto leading-relaxed">
                            Selecione uma unidade de opera├º├úo para gerenciar as atividades de conformidade e auditorias.
                        </p>
                    </div>

                    <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {labs.map((lab) => (
                            <button
                                key={lab.id}
                                onClick={() => selectLab(lab.id)}
                                className="group relative p-8 bg-neutral-50/50 border border-neutral-100 rounded-[2rem] transition-all duration-500 hover:bg-white hover:border-black hover:shadow-2xl text-left"
                            >
                                <h3 className="text-2xl font-serif text-black mb-1 group-hover:translate-x-1 transition-transform">{lab.nome}</h3>
                                <p className="text-[10px] font-mono text-neutral-400 uppercase tracking-widest mb-10">{lab.cidade || 'Unidade Geral'}</p>

                                <div className="flex items-center justify-between mt-auto">
                                    <div className="flex items-center gap-2">
                                        <div className="h-2 w-2 rounded-full bg-black animate-pulse" />
                                        <span className="text-[10px] font-bold uppercase tracking-widest text-neutral-600">Ativo</span>
                                    </div>
                                    <ChevronRight className="h-5 w-5 text-neutral-200 group-hover:text-black group-hover:translate-x-1 transition-all" />
                                </div>
                            </button>
                        ))}
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-[1400px] mx-auto space-y-12 animate-in fade-in duration-500 pb-32 pt-8 px-4">
            {/* Minimal Header */}
            <div className="flex flex-col lg:flex-row lg:items-end justify-between gap-12 border-b border-black/5 pb-16">
                <div className="space-y-6">
                    <div className="flex items-center gap-3 text-neutral-400">
                        <ClipboardCheck className="h-6 w-6 text-black" />
                        <div className="h-4 w-[1px] bg-neutral-200" />
                        <span className="text-[10px] font-black uppercase tracking-[0.4em]">Operations Control</span>
                    </div>
                    <div className="space-y-2">
                        <h1 className="text-7xl font-serif text-black tracking-tighter leading-none">
                            Checklist <span className="font-light text-neutral-300 italic">Global</span>
                        </h1>
                        <p className="text-xl text-neutral-500 font-light max-w-2xl leading-relaxed">
                            Gest├úo de conformidade integrada para o <span className="text-black font-medium">{currentLab?.nome}</span>.
                        </p>
                    </div>
                </div>

                <div className="flex flex-wrap items-center gap-4">
                    <div className="flex items-center bg-neutral-50 px-2 py-1.5 rounded-2xl border border-neutral-100">
                        <button
                            onClick={() => setFilterStatus('all')}
                            className={cn("px-6 py-2.5 text-[10px] font-bold uppercase tracking-widest transition-all rounded-xl", filterStatus === 'all' ? "bg-white text-black shadow-lg" : "text-neutral-400 hover:text-black")}
                        >
                            Ver Tudo
                        </button>
                        <button
                            onClick={() => setFilterStatus('pending')}
                            className={cn("px-6 py-2.5 text-[10px] font-bold uppercase tracking-widest transition-all rounded-xl", filterStatus === 'pending' ? "bg-white text-black shadow-lg" : "text-neutral-400 hover:text-black")}
                        >
                            Pendentes
                        </button>
                        <button
                            onClick={() => setFilterStatus('completed')}
                            className={cn("px-6 py-2.5 text-[10px] font-bold uppercase tracking-widest transition-all rounded-xl", filterStatus === 'completed' ? "bg-white text-black shadow-lg" : "text-neutral-400 hover:text-black")}
                        >
                            Conclu├¡dos
                        </button>
                    </div>
                    <Button
                        onClick={() => setIsSidebarOpen(true)}
                        className="h-16 px-10 bg-black text-white rounded-2xl font-bold text-[10px] uppercase tracking-[0.3em] hover:bg-neutral-800 transition-all shadow-2xl hover:shadow-black/20"
                    >
                        <Plus className="mr-3 h-5 w-5" /> Registrar Atividade
                    </Button>
                </div>
            </div>

            {/* Quick Stats Toolbar */}
            <div className="flex flex-col md:flex-row items-center gap-6">
                <div className="flex-1 w-full group relative">
                    <Search className="absolute left-6 top-1/2 -translate-y-1/2 h-4 w-4 text-neutral-300 group-focus-within:text-black transition-colors" />
                    <Input
                        placeholder="Filtrar atividades por t├¡tulo ou respons├ível..."
                        value={searchTerm}
                        onChange={e => setSearchTerm(e.target.value)}
                        className="pl-14 h-16 border-none bg-neutral-50 rounded-[1.5rem] focus-visible:ring-1 focus-visible:ring-black placeholder:text-neutral-400 font-medium text-lg"
                    />
                </div>

                <div className="flex p-1.5 bg-neutral-50 rounded-2xl border border-neutral-100">
                    <button
                        onClick={() => setViewMode('grid')}
                        className={cn("p-4 rounded-xl transition-all", viewMode === 'grid' ? "bg-white text-black shadow-md" : "text-neutral-300 hover:text-black")}
                        title="Visualiza├º├úo em Grade"
                    >
                        <LayoutGrid className="h-5 w-5" />
                    </button>
                    <button
                        onClick={() => setViewMode('list')}
                        className={cn("p-4 rounded-xl transition-all", viewMode === 'list' ? "bg-white text-black shadow-md" : "text-neutral-300 hover:text-black")}
                        title="Visualiza├º├úo em Lista"
                    >
                        <List className="h-5 w-5" />
                    </button>
                </div>
            </div>

            {/* Main Content */}
            {isLoading ? (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                    {[1, 2, 3, 4, 5, 6].map(i => (
                        <div key={i} className="h-64 bg-neutral-50 rounded-[2.5rem] animate-pulse" />
                    ))}
                </div>
            ) : filteredItems.length === 0 ? (
                <div className="py-40 flex flex-col items-center justify-center text-center space-y-8 bg-neutral-50/50 rounded-[4rem] border border-dashed border-neutral-200">
                    <div className="h-24 w-24 bg-white rounded-full flex items-center justify-center shadow-2xl">
                        <SearchCheck className="h-10 w-10 text-neutral-200" />
                    </div>
                    <div className="space-y-3">
                        <h4 className="text-3xl font-serif text-black tracking-tight">Vazio por enquanto</h4>
                        <p className="text-neutral-400 max-w-sm mx-auto font-light leading-relaxed">Nenhuma atividade registrada nos crit├®rios selecionados. Comece criando um novo item.</p>
                    </div>
                    <Button onClick={() => setIsSidebarOpen(true)} variant="outline" className="h-14 px-8 border-black font-bold text-[10px] uppercase tracking-widest hover:bg-black hover:text-white transition-all rounded-2xl">
                        Criar Primeiro Item
                    </Button>
                </div>
            ) : (
                <div className={cn(
                    "grid gap-8 transition-all duration-700",
                    viewMode === 'grid' ? "grid-cols-1 md:grid-cols-2 lg:grid-cols-3" : "grid-cols-1"
                )}>
                    {filteredItems.map(item => (
                        <ChecklistItemCard
                            key={item.id}
                            item={item}
                            viewMode={viewMode}
                            onToggle={() => handleToggleStatus(item)}
                            onDelete={() => handleDeleteItem(item.id)}
                        />
                    ))}
                </div>
            )}

            {/* Add Sidebar Drawer */}
            {isSidebarOpen && (
                <div className="fixed inset-0 z-[100] animate-in fade-in duration-300">
                    <div className="absolute inset-0 bg-black/60 backdrop-blur-md" onClick={() => setIsSidebarOpen(false)} />
                    <div className="absolute right-0 top-0 bottom-0 w-full max-w-md bg-white shadow-[0_0_100px_rgba(0,0,0,0.5)] animate-in slide-in-from-right duration-500 p-12 overflow-y-auto flex flex-col">
                        <div className="flex items-center justify-between mb-16">
                            <div className="space-y-1">
                                <h3 className="text-4xl font-serif tracking-tight">Nova Atividade</h3>
                                <p className="text-[10px] font-black uppercase tracking-[0.3em] text-neutral-300">Registro de Conformidade</p>
                            </div>
                            <button onClick={() => setIsSidebarOpen(false)} className="p-3 hover:bg-neutral-100 rounded-2xl transition-colors" title="Fechar">
                                <X className="h-6 w-6" />
                            </button>
                        </div>

                        <form onSubmit={handleCreateItem} className="space-y-10 flex-1">
                            <div className="space-y-4">
                                <label className="text-[10px] font-black uppercase tracking-widest text-neutral-400 block ml-1">O que ser├í feito?</label>
                                <Input
                                    value={formData.name}
                                    onChange={e => setFormData({ ...formData, name: e.target.value })}
                                    placeholder="Ex: Auditoria de Amostragem"
                                    className="h-16 border-none bg-neutral-50 rounded-2xl px-6 font-bold text-lg focus-visible:ring-1 focus-visible:ring-black"
                                />
                            </div>

                            <div className="space-y-4">
                                <label className="text-[10px] font-black uppercase tracking-widest text-neutral-400 block ml-1">Para quem?</label>
                                <select
                                    value={formData.assignedTo}
                                    onChange={e => setFormData({ ...formData, assignedTo: e.target.value })}
                                    className="w-full h-16 bg-neutral-50 border-none rounded-2xl px-6 text-sm font-bold focus:ring-1 focus:ring-black outline-none appearance-none"
                                    title="Selecione o respons├ível"
                                >
                                    <option value="">Equipe Geral</option>
                                    {analysts.map(a => <option key={a.id} value={a.nome}>{a.nome}</option>)}
                                </select>
                            </div>

                            <div className="space-y-4">
                                <label className="text-[10px] font-black uppercase tracking-widest text-neutral-400 block ml-1">Data Limite</label>
                                <Input
                                    type="date"
                                    value={formData.deadline}
                                    onChange={e => setFormData({ ...formData, deadline: e.target.value })}
                                    className="h-16 border-none bg-neutral-50 rounded-2xl px-6"
                                />
                            </div>

                            <div className="space-y-4 flex-1">
                                <label className="text-[10px] font-black uppercase tracking-widest text-neutral-400 block ml-1">Instru├º├Áes</label>
                                <textarea
                                    className="w-full min-h-[160px] bg-neutral-50 border-none rounded-3xl p-6 text-base font-medium focus:ring-1 focus:ring-black outline-none resize-none"
                                    placeholder="Detalhe o procedimento..."
                                    value={formData.observation}
                                    onChange={e => setFormData({ ...formData, observation: e.target.value })}
                                />
                            </div>

                            <Button
                                type="submit"
                                className="w-full h-20 bg-black text-white rounded-[2rem] font-black text-[12px] uppercase tracking-[0.4em] shadow-2xl hover:bg-neutral-900 transition-all mt-6"
                            >
                                Registrar Agora
                            </Button>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

function ChecklistItemCard({ item, viewMode, onToggle, onDelete }: {
    item: AuditDocument,
    viewMode: 'grid' | 'list',
    onToggle: () => void,
    onDelete: () => void
}) {
    const isCompleted = item.status === 'completed';

    if (viewMode === 'list') {
        return (
            <div className={cn(
                "group flex items-center gap-8 p-6 bg-white border border-neutral-100 rounded-[2.5rem] transition-all hover:shadow-2xl hover:-translate-y-1",
                isCompleted ? "opacity-60 grayscale-[0.5]" : ""
            )}>
                <button
                    onClick={onToggle}
                    className={cn(
                        "h-14 w-14 rounded-2xl flex items-center justify-center transition-all",
                        isCompleted ? "bg-emerald-500 text-white shadow-lg shadow-emerald-500/20" : "bg-neutral-50 text-neutral-200 hover:bg-black hover:text-white"
                    )}
                >
                    {isCompleted ? <CheckCircle2 className="h-7 w-7" /> : <Plus className="h-6 w-6" />}
                </button>
                <div className="flex-1">
                    <h4 className={cn("text-xl font-serif text-black", isCompleted && "line-through text-neutral-400")}>{item.name}</h4>
                    <div className="flex items-center gap-8 mt-2">
                        <span className="text-[10px] font-bold uppercase tracking-widest text-neutral-400 flex items-center gap-2">
                            <Briefcase className="h-3.5 w-3.5" /> {item.assignedTo || "Coletiva"}
                        </span>
                        {item.deadline && (
                            <span className="text-[10px] font-bold uppercase tracking-widest text-neutral-400 flex items-center gap-2">
                                <Calendar className="h-3.5 w-3.5" /> {new Date(item.deadline).toLocaleDateString()}
                            </span>
                        )}
                    </div>
                </div>
                <div className="flex items-center gap-4">
                    <button onClick={onDelete} className="p-3 text-neutral-200 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100">
                        <Trash2 className="h-5 w-5" />
                    </button>
                    <ChevronRight className="h-5 w-5 text-neutral-200" />
                </div>
            </div>
        );
    }

    return (
        <div className={cn(
            "group relative p-12 bg-white border border-neutral-100 flex flex-col justify-between min-h-[380px] rounded-[3.5rem] transition-all duration-700 hover:shadow-[0_60px_100px_-40px_rgba(0,0,0,0.12)] hover:-translate-y-3 hover:border-black/10 text-black",
            isCompleted ? "border-emerald-100/50" : ""
        )}>
            {/* Status Badge Top Left */}
            <div className="absolute top-12 left-12 flex items-center gap-3">
                <div className={cn("h-2.5 w-2.5 rounded-full", isCompleted ? "bg-emerald-500 shadow-[0_0_12px_rgba(16,185,129,0.5)]" : "bg-neutral-200")} />
                <span className={cn("text-[10px] font-black uppercase tracking-[0.2em]", isCompleted ? "text-emerald-500" : "text-neutral-300")}>
                    {isCompleted ? "Documentado" : "Em Aberto"}
                </span>
            </div>

            {/* Check Button Top Right */}
            <div className="absolute top-10 right-10">
                <button
                    onClick={onToggle}
                    className={cn(
                        "h-16 w-16 rounded-[1.5rem] flex items-center justify-center transition-all duration-500",
                        isCompleted
                            ? "bg-emerald-500 text-white shadow-xl shadow-emerald-500/30 scale-105"
                            : "bg-neutral-50 text-neutral-200 hover:bg-black hover:text-white hover:rotate-90"
                    )}
                >
                    {isCompleted ? <CheckCircle className="h-8 w-8" /> : <Plus className="h-7 w-7" />}
                </button>
            </div>

            <div className="space-y-8 mt-12 flex-1">
                <div className="space-y-4">
                    <h4 className={cn(
                        "text-4xl font-serif tracking-tight leading-[1.15]",
                        isCompleted ? "text-neutral-300 line-through" : "text-black group-hover:underline decoration-1 underline-offset-8"
                    )}>
                        {item.name}
                    </h4>
                    {item.observation && (
                        <p className={cn("text-base font-medium leading-relaxed max-w-[90%] opacity-0 group-hover:opacity-100 translate-y-4 group-hover:translate-y-0 transition-all duration-500", isCompleted ? "text-neutral-200" : "text-neutral-500")}>
                            {item.observation}
                        </p>
