                        <h2 className="text-2xl font-black uppercase tracking-tight text-neutral-900 mb-2">ATEN├ç├âO</h2>
                        <p className="text-sm font-medium text-neutral-500 mb-8">
                            Tem certeza que deseja apagar os registros deste laborat├│rio? Essa a├º├úo limpar├í o hist├│rico imediatamente.
                        </p>
                        <div className="flex gap-4 w-full">
                            <Button
                                variant="outline"
                                className="flex-1 rounded-xl uppercase font-black text-[10px] tracking-widest h-12"
                                onClick={() => setIsClearConfirmOpen(false)}
                            >
                                Cancelar
                            </Button>
                            <Button
                                variant="destructive"
                                className="flex-1 rounded-xl uppercase font-black text-[10px] tracking-widest h-12 bg-red-600 hover:bg-red-700"
                                onClick={handleClearAllData}
                            >
                                Apagar Tudo
                            </Button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

