    nome: string;
    amostras: number;
}

interface TurnoData {
    operadores: Operador[];
    total: number;
}

interface DiaData {
    data: string;          // "DD/MM"
    dataFull: string;      // "YYYY-MM-DD"
    diaSemana: string;
    turnos: Record<string, TurnoData>;
    totalDia: number;
}

interface ReportState {
