const classifySample = (row: HVIDataRow): string => {
    const { mic, len, str } = row;

    // Crit├®rios Premium (Verde)
    const isMicOk = mic >= 3.8 && mic <= 4.5;
    const isLenOk = len >= 1.12;
    const isStrOk = str >= 29;

    if (isMicOk && isLenOk && isStrOk) return "#10b981"; // Green (Premium)

    // Crit├®rios Regular (Amarelo)
    const isMicRegular = (mic >= 3.5 && mic < 3.8) || (mic > 4.5 && mic <= 4.9);
    const isLenRegular = len >= 1.08;
    const isStrRegular = str >= 27;

    if (isMicRegular || (isLenRegular && isStrRegular)) return "#f59e0b"; // Yellow (Regular)

    // Fora dos padr├Áes (Vermelho)
    return "#ef4444";
};

type PendingConfirmation = {
    file: File;
    previewUrl: string;
    data: ExtractionResult;
};

export default function Registro() {
    const [searchParams] = useSearchParams();
    const navigate = useNavigate();
    const { addToast } = useToast();
    const loteId = searchParams.get("loteId");

    const [lote, setLote] = useState<Lote | null>(null);
    const [samples, setSamples] = useState<Sample[]>([]);

    // States for the review flow
    // States for the review flow
    const [isProcessing, setIsProcessing] = useState(false); // Processamento bloqueante (foreground)
    const [isBackgroundProcessing, setIsBackgroundProcessing] = useState(false); // Processamento em background
    const [ocrProgress, setOcrProgress] = useState(0);
    const [processingStatus, setProcessingStatus] = useState("");

    const [uploadQueue, setUploadQueue] = useState<File[]>([]); // Arquivos aguardando
    const [processedQueue, setProcessedQueue] = useState<PendingConfirmation[]>([]); // Arquivos prontos para revis├úo

    // Item sendo revisado atualmente
    const [pendingReview, setPendingReview] = useState<PendingConfirmation | null>(null);

    // Efeito para processar filas em background enquanto o usu├írio trabalha
    useEffect(() => {
        const processNextInBackground = async () => {
            if (uploadQueue.length === 0 || isBackgroundProcessing || isProcessing) return;

            // S├│ processa em background se ainda tivermos trabalho pela frente
            // e n├úo tivermos acumulado muitos processados (para economizar mem├│ria)
            if (processedQueue.length > 5) return;

            setIsBackgroundProcessing(true);
            const nextFile = uploadQueue[0];

            try {
                // Remove da fila de upload imediatamente para evitar duplicidade
                setUploadQueue(prev => prev.slice(1));

                const data = await OCRExtractionService.extractFromImage(nextFile, () => { }); // Progresso ignorado no background
                const previewUrl = URL.createObjectURL(nextFile);

                setProcessedQueue(prev => [...prev, { file: nextFile, previewUrl, data }]);
            } catch (error) {
                console.error("Erro no processamento background", error);
                // Se der erro, descartamos silenciosamente
            } finally {
                setIsBackgroundProcessing(false);
            }
        };

        const timer = setTimeout(processNextInBackground, 500); // Debounce
        return () => clearTimeout(timer);
    }, [uploadQueue, isBackgroundProcessing, isProcessing, processedQueue.length]);


    // Fun├º├úo que assume um item para revis├úo (seja da fila processada ou processando na hora)
    const loadNextForReview = async (item?: PendingConfirmation) => {
        let reviewItem = item;

        // Se n├úo passou item, tenta pegar da fila de processados
        if (!reviewItem && processedQueue.length > 0) {
            reviewItem = processedQueue[0];
            setProcessedQueue(prev => prev.slice(1));
        }

        // Se ainda n├úo tem item, mas tem na fila de upload (caso background n├úo tenha terminado)
        // Processamos com prioridade (foreground)
        if (!reviewItem && uploadQueue.length > 0) {
            const nextFile = uploadQueue[0];
            setUploadQueue(prev => prev.slice(1));

            setIsProcessing(true);
            setOcrProgress(0);
            setProcessingStatus("Processando pr├│xima imagem...");

            try {
                const data = await OCRExtractionService.extractFromImage(nextFile, (p) => setOcrProgress(p));
                const previewUrl = URL.createObjectURL(nextFile);
                reviewItem = { file: nextFile, previewUrl, data };
            } catch (error) {
                console.error(error);
                addToast({ title: "Erro no OCR", description: "Falha ao processar imagem.", type: "error" });
                setIsProcessing(false);
                setProcessingStatus("");
                return; // Aborta
            } finally {
                setIsProcessing(false);
                setProcessingStatus("");
            }
        }

        if (reviewItem) {
            // Setup do review
            setPendingReview(reviewItem);
            setEditingMala(reviewItem.data.mala || '');
            setEditingEtiqueta(reviewItem.data.etiqueta || '');

            setEditingRows(reviewItem.data.rows.length > 0 ? [...reviewItem.data.rows] : [{
                numero: '1', hvi: '1', data_analise: new Date().toLocaleDateString('pt-BR'), hora_analise: new Date().toLocaleTimeString('pt-BR'),
                mic: 0, len: 0, unf: 0, str: 0, rd: 0, b: 0
            }]);
            setCurrentRowIndex(0);
            setSelectedRows(new Set(reviewItem.data.rows.length > 0 ? reviewItem.data.rows.map((_, i) => i) : [0]));

            addToast({
                title: "Imagem Carregada",
                description: reviewItem.data.rows.length > 0 ? `${reviewItem.data.rows.length} registros.` : "Sem dados autom├íticos.",
                type: "success"
            });
        }
    };

    const handleUpload = async (files: File[]) => {
        if (!loteId || files.length === 0) return;

        // Se n├úo tiver nada sendo revisado, o primeiro arquivo vai direto para review (caminho r├ípido)
        // O resto vai para a fila de upload para ser pego pelo background
        if (!pendingReview && processedQueue.length === 0 && uploadQueue.length === 0) {
            const [first, ...rest] = files;
            setUploadQueue(rest); // Fila para background

            // Processa o primeiro imediatamente
            setIsProcessing(true);
            setOcrProgress(0);
            try {
                const data = await OCRExtractionService.extractFromImage(first, p => setOcrProgress(p));
                const previewUrl = URL.createObjectURL(first);
                loadNextForReview({ file: first, previewUrl, data });
            } catch (e) {
                console.error(e);
            } finally {
                setIsProcessing(false);
            }
        } else {
            // Se j├í tem coisa rolando, joga tudo na fila
            setUploadQueue(prev => [...prev, ...files]);
            addToast({ title: "Adicionado ├á Fila", description: `${files.length} imagens adicionadas.`, type: "info" });
        }
    };

    // Nova estrutura para edi├º├úo de m├║ltiplas linhas
    const [editingMala, setEditingMala] = useState('');
    const [editingEtiqueta, setEditingEtiqueta] = useState('');
    const [editingRows, setEditingRows] = useState<HVIDataRow[]>([]);
    const [currentRowIndex, setCurrentRowIndex] = useState(0);
    const [selectedRows, setSelectedRows] = useState<Set<number>>(new Set());

    // Modal Confirmation State
    const [modalAction, setModalAction] = useState<{ type: 'delete', id?: string } | null>(null);

    // Core Hooks
    const { user } = useAuth();

    // Presence Logic
    const [coWorkers, setCoWorkers] = useState<any[]>([]);
    useEffect(() => {
        const checkPresence = async () => {
            const all = await AnalistaService.list();
            const now = new Date().getTime();
            const others = all.filter(a =>
                a.id !== user?.id &&
                a.current_lote_id === loteId &&
                a.last_active && (now - new Date(a.last_active).getTime() < 15000)
            );
            setCoWorkers(others);
        };
        const interval = setInterval(checkPresence, 3000);
        checkPresence();
        return () => clearInterval(interval);
    }, [loteId, user?.id]);

    useEffect(() => {
        if (loteId) {
            loadData();

            // Subscribe to real-time changes for samples
            const unsubSamples = SampleService.subscribe(() => {
                loadData();
            });
            const unsubLotes = LoteService.subscribe(() => {
                loadData();
            });

            return () => {
                unsubSamples();
                unsubLotes();
            };
        }
    }, [loteId, user]);



    const loadData = async () => {
        if (!loteId) return;
        const l = await LoteService.get(loteId);

        if (l) {
            // Security Check
            if (user?.acesso !== 'admin_global' && user?.lab_id && l.lab_id && l.lab_id !== user.lab_id) {
                addToast({ title: "Access Denied", description: "You cannot manage samples for other laboratories.", type: "error" });
                navigate("/");
                return;
            }
            setLote(l);
        }

        const s = await SampleService.listByLote(loteId);
        setSamples(s);
    };

    const handleDeleteSample = async (sampleId: string) => {
        try {
            await SampleService.delete(sampleId);
            addToast({ title: "Registro Removido", type: "info" });
            setModalAction(null);
            loadData();
        } catch (error) {
            addToast({ title: "Erro ao Remover", type: "error" });
        }
    };

    const handleExportHVI = async (sample: Sample) => {
        const result = await HVIFileGeneratorService.generateFileForSample(sample);
        addToast({
            title: result.success ? "Arquivo HVI Gerado" : "Erro",
            description: result.message,
            type: result.success ? "success" : "error"
        });
    };



    const updateCurrentRow = (field: keyof HVIDataRow, value: string | number) => {
        setEditingRows(rows => {
            const updated = [...rows];
            updated[currentRowIndex] = { ...updated[currentRowIndex], [field]: value };
            return updated;
        });
    };

    const handleSaveSelectedSamples = async () => {
        if (!loteId || !pendingReview || selectedRows.size === 0) return;

        try {
            let savedCount = 0;
            const rowsToSave = editingRows.filter((_, index) => selectedRows.has(index));

            for (const row of rowsToSave) {
                if (samples.length + savedCount >= 28) {
                    addToast({ title: "Limite Atingido", description: "M├íximo de 28 amostras por lote.", type: "warning" });
                    break;
                }

                const nextId = (samples.length + savedCount + 1).toString().padStart(2, '0');
                await SampleService.create({
                    lote_id: loteId,
                    amostra_id: nextId,
                    hvi: row.hvi, // N├║mero da m├íquina HVI
                    mala: editingMala,
                    etiqueta: editingEtiqueta,
                    data_analise: row.data_analise,
                    hora_analise: row.hora_analise,
                    mic: row.mic,
                    len: row.len,
                    unf: row.unf,
                    str: row.str,
                    rd: row.rd,
                    b: row.b,
                    cor: classifySample(row), // Auto-classifica├º├úo precisa
                    historico_modificacoes: []
                });
                savedCount++;
            }

            addToast({ title: "Amostras Salvas", description: `${savedCount} registro(s) adicionado(s).`, type: "success" });
            URL.revokeObjectURL(pendingReview.previewUrl);
            setPendingReview(null);
            setEditingRows([]);
            setEditingMala('');
            setEditingEtiqueta('');
            setSelectedRows(new Set());
            await loadData();

            // Carrega pr├│ximo
            loadNextForReview();
        } catch (error) {
            addToast({ title: "Erro ao Salvar", type: "error" });
        }
    };

    const handleAbortReview = () => {
        if (pendingReview) {
            URL.revokeObjectURL(pendingReview.previewUrl);
        }
        setPendingReview(null);
        setEditingRows([]);
        setEditingMala('');
        setEditingEtiqueta('');
        setSelectedRows(new Set());

        // Carrega pr├│ximo
        loadNextForReview();
    };

    if (!loteId) return <div className="p-4 text-center font-black text-slate-300 uppercase tracking-widest text-[8px]">ID_LOTE_MISSING</div>;
    if (!lote) return <div className="p-4 text-center animate-pulse text-slate-400 font-bold uppercase tracking-widest text-[8px]">Carregando...</div>;

    // --- SIDE-BY-SIDE CONFIRMATION VIEW ---
    if (pendingReview && editingRows.length > 0) {
        const currentRow = editingRows[currentRowIndex];
        // Safety check to prevent crashes if index is out of bounds
        if (!currentRow) {
            console.error("Critical Error: Current row index out of bounds", currentRowIndex, editingRows.length);
            // Attempt recovery
            if (editingRows.length > 0) {
                setCurrentRowIndex(0);
                return null;
            } else {
                setPendingReview(null);
                return null;
            }
        }

        return createPortal(

            <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in">
                <div className="w-full max-w-6xl h-full lg:h-[85vh] max-h-screen bg-white flex flex-col lg:flex-row shadow-2xl border border-black overflow-hidden relative">

                    {/* Header Controls */}
                    <div className="absolute top-0 left-0 right-0 h-16 bg-white border-b border-black flex items-center justify-between px-8 z-20">
                        <div className="flex items-center gap-6">
                            <Button variant="ghost" size="icon" onClick={handleAbortReview} className="hover:bg-neutral-100 rounded-none h-10 w-10 border border-neutral-200">
                                <ArrowLeft className="h-4 w-4" />
                            </Button>
                            <div>
                                <h3 className="text-sm font-bold uppercase tracking-widest text-black">Verification Console</h3>
                                <p className="text-[10px] font-mono text-neutral-400 uppercase">Reviewing Digitized Data</p>
                            </div>
                        </div>
                        <div className="flex items-center gap-4">
                            <div className="flex items-center gap-3 px-4 border-r border-neutral-200">
                                <div className="text-right">
                                    <p className="text-[9px] font-bold uppercase tracking-widest text-neutral-400">Current Sample</p>
                                    <p className="text-xs font-mono font-bold">{currentRowIndex + 1} <span className="text-neutral-300">/</span> {editingRows.length}</p>
                                </div>
                            </div>
                            <Button onClick={handleSaveSelectedSamples} className="h-10 rounded-none bg-black text-white hover:bg-neutral-800 text-[10px] uppercase tracking-widest px-8 font-bold shadow-lg transition-all hover:scale-105">
                                Confirm & Save to Database
                            </Button>
                        </div>
                    </div>

                    {/* Left: Image Viewer Area */}
                    <div className="w-full lg:w-1/2 h-[40vh] lg:h-auto bg-neutral-100 border-b lg:border-b-0 lg:border-r border-black pt-16 flex flex-col relative group shrink-0">
                        <div className="absolute top-20 left-6 z-10 flex gap-2">
                            <div className="bg-black text-white text-[9px] uppercase tracking-widest px-3 py-1 font-bold shadow-sm">
                                Original Source
                            </div>
                        </div>

                        <div className="flex-1 overflow-auto p-6 lg:p-12 flex items-center justify-center">
                            <img
                                src={pendingReview.previewUrl}
                                alt="Source"
                                className="max-w-full max-h-full object-contain shadow-2xl border-4 border-white transition-transform duration-300 group-hover:scale-[1.02]"
                            />
                        </div>

                        {/* Filmstrip Navigation */}
                        {editingRows.length > 1 && (
                            <div className="h-16 lg:h-24 bg-white border-t border-black p-0 flex divide-x divide-black overflow-x-auto items-center shrink-0">
                                {editingRows.map((row, idx) => (
                                    <button
                                        key={idx}
                                        onClick={() => setCurrentRowIndex(idx)}
                                        className={cn(
                                            "h-full min-w-[60px] lg:min-w-[80px] flex flex-col items-center justify-center transition-all px-2 relative group-hover/strip:opacity-50 hover:!opacity-100",
                                            currentRowIndex === idx
                                                ? "bg-black text-white"
                                                : "bg-white text-black hover:bg-neutral-50"
                                        )}
                                    >
                                        <span className="text-[8px] lg:text-[10px] font-bold uppercase mb-1">Sample</span>
                                        <span className="font-mono text-lg lg:text-xl font-bold">#{row.numero}</span>
                                        {currentRowIndex === idx && (
                                            <div className="absolute bottom-2 w-1 h-1 bg-white rounded-full" />
                                        )}
                                    </button>
                                ))}
                            </div>
                        )}
                    </div>

                    {/* Right: Data Editor Form */}
                    <div className="w-full lg:w-1/2 bg-white lg:pt-16 overflow-y-auto flex-1 h-auto">
                        <div className="p-10 space-y-10">

                            {/* Section: Identifiers */}
                            <div className="space-y-6 animate-slide-up" style={{ animationDelay: '100ms' }}>
                                <div className="flex items-center gap-3 border-b-2 border-black pb-3">
                                    <div className="h-2 w-2 bg-blue-600 rounded-full animate-pulse" />
                                    <h3 className="text-sm font-bold uppercase tracking-[0.2em]">Identification</h3>
                                </div>

                                <div className="grid grid-cols-2 gap-6">
                                    <div className="space-y-2">
                                        <label className="text-[9px] font-bold text-neutral-400 uppercase tracking-widest">Bag ID</label>
                                        <Input
                                            value={editingMala}
                                            onChange={(e) => setEditingMala(e.target.value)}
                                            className="h-12 border-b-2 border-l-0 border-r-0 border-t-0 border-neutral-200 rounded-none font-mono text-lg bg-transparent px-0 focus:border-black focus:ring-0 placeholder:text-neutral-200"
                                            placeholder="UNIDENTIFIED"
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <label className="text-[9px] font-bold text-neutral-400 uppercase tracking-widest">Tag Reference</label>
                                        <Input
                                            value={editingEtiqueta}
                                            onChange={(e) => setEditingEtiqueta(e.target.value)}
                                            className="h-12 border-b-2 border-l-0 border-r-0 border-t-0 border-neutral-200 rounded-none font-mono text-lg bg-transparent px-0 focus:border-black focus:ring-0 placeholder:text-neutral-200"
                                            placeholder="NO TAG"
                                        />
                                    </div>
                                </div>
                            </div>

                            {/* Section: Metrics */}
                            <div className="space-y-6 animate-slide-up" style={{ animationDelay: '200ms' }}>
                                <div className="flex items-center gap-3 border-b border-neutral-200 pb-3">
                                    <Activity className="h-4 w-4 text-neutral-400" />
                                    <h3 className="text-xs font-bold uppercase tracking-[0.2em] text-neutral-500">Fiber Metrics</h3>
                                </div>
                                <div className="grid grid-cols-2 gap-x-8 gap-y-6">
                                    {[
                                        { label: "Micronaire", short: "MIC", key: "mic" as keyof HVIDataRow, decimals: 2 },
                                        { label: "Length", short: "LEN", key: "len" as keyof HVIDataRow, decimals: 2 },
                                        { label: "Uniformity", short: "UNF", key: "unf" as keyof HVIDataRow, decimals: 1 },
                                        { label: "Strength", short: "STR", key: "str" as keyof HVIDataRow, decimals: 1 },
                                        { label: "Reflectance", short: "RD", key: "rd" as keyof HVIDataRow, decimals: 1 },
                                        { label: "Yellowness", short: "+b", key: "b" as keyof HVIDataRow, decimals: 1 }
                                    ].map((field) => (
                                        <div key={field.key} className="flex items-center justify-between group">
                                            <div className="space-y-0.5">
                                                <label className="text-[9px] font-bold text-neutral-400 uppercase tracking-widest block group-hover:text-black transition-colors">{field.short}</label>
                                                <span className="text-[8px] font-mono text-neutral-300 uppercase">{field.label}</span>
                                            </div>
                                            <Input
                                                key={`${currentRowIndex}-${field.key}`}
                                                defaultValue={formatDecimalBR(currentRow[field.key] as number || 0, field.decimals)}
                                                onBlur={(e) => {
                                                    const inputValue = e.target.value.replace(',', '.');
                                                    const numValue = parseFloat(inputValue);
                                                    updateCurrentRow(field.key, isNaN(numValue) ? 0 : numValue);
                                                }}
                                                className="w-24 h-10 bg-neutral-50 border-transparent focus:bg-white focus:border-black rounded-none font-mono text-xl text-right focus:ring-0 transition-all font-bold"
                                            />
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>,
            document.body
        );
    }


    // --- MAIN VIEW ---
    return (
        <div className="w-full h-screen flex flex-col bg-white text-black overflow-hidden animate-fade-in">
            {/* Header */}
            <div className="h-20 border-b border-black flex items-center justify-between px-8 shrink-0">
                <div className="flex items-center gap-6">
                    <Button
                        variant="ghost"
                        size="icon"
                        onClick={() => navigate(-1)}
                        className="rounded-none hover:bg-neutral-100 text-black h-10 w-10 border border-neutral-200"
                    >
                        <ArrowLeft className="h-4 w-4" />
                    </Button>
                    <div className="space-y-1">
                        <div className="flex items-center gap-3">
                            <h1 className="text-2xl font-serif text-black leading-none">
                                Sample Registration
                            </h1>
                            {coWorkers.length > 0 && (
                                <div className="flex items-center gap-2 bg-yellow-100 px-2 py-1 rounded-full border border-yellow-200 animate-pulse">
                                    <span className="text-[9px] font-bold uppercase text-yellow-700">{coWorkers.length} other(s) editing</span>
                                    <div className="flex -space-x-1">
                                        {coWorkers.map(cw => (
                                            <div key={cw.id} className="w-5 h-5 rounded-full bg-neutral-200 border border-white overflow-hidden" title={cw.nome || 'Unknown'}>
                                                {cw.foto ? (
                                                    <img src={cw.foto} className="w-full h-full object-cover" alt={cw.nome} />
                                                ) : (
                                                    <div className="w-full h-full flex items-center justify-center text-[8px] font-bold">
                                                        {(cw.nome && cw.nome[0] ? cw.nome[0] : "?").toUpperCase()}
                                                    </div>
                                                )}
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>
                        <p className="text-[10px] text-neutral-500 uppercase tracking-[0.2em] font-mono">
                            BATCH: {lote.nome}
                        </p>
                    </div>
                </div>

                <Button
                    onClick={() => navigate(`/analysis?loteId=${loteId}`)}
                    className="h-12 px-8 bg-black text-white hover:bg-neutral-800 rounded-none text-[10px] uppercase tracking-[0.2em] font-bold transition-all"
                >
                    Analysis View
                    <ArrowRight className="ml-2 h-3 w-3" />
                </Button>
            </div>

            <div className="flex-1 flex flex-col overflow-hidden relative">
                {/* Upload Section - Top */}
                <div className="w-full h-[280px] border-b border-black flex flex-col bg-neutral-50 shrink-0 transition-all duration-300">
                    <div className="p-3 border-b border-black flex items-center justify-between bg-white shrink-0">
                        <h3 className="text-xs font-bold uppercase tracking-widest text-black flex items-center gap-2">
                            Digitization Station
                        </h3>
                        <span className="text-xs font-mono font-bold">{samples.length} / 28</span>
                    </div>

                    <div className="p-4 overflow-y-auto flex-1 [&::-webkit-scrollbar]:hidden [-ms-overflow-style:none] [scrollbar-width:none]">
                        {isProcessing ? (
                            <div className="h-full flex flex-col items-center justify-center gap-6 text-center">
                                <div className="w-16 h-16 border-4 border-neutral-200 border-t-black rounded-full animate-spin" />
                                <div className="space-y-2">
                                    <p className="text-xs font-bold uppercase tracking-widest text-black">
                                        Processing Image
                                    </p>
                                    <p className="text-[10px] font-mono text-neutral-400 uppercase">
                                        {processingStatus || "EXTRACTING DATA..."} {ocrProgress > 0 && `ÔÇó ${ocrProgress}%`}
                                    </p>
                                </div>
                            </div>
                        ) : (
                            <div className="space-y-3 max-w-4xl mx-auto w-full">
                                <HVIUpload
                                    onUpload={handleUpload}
                                    isProcessing={isProcessing}
                                    maxFiles={28}
                                />
                                <div className="bg-white border border-neutral-200 p-3 space-y-2 flex items-center justify-between gap-4">
                                    <div className="flex items-center gap-4">
                                        <h4 className="text-[9px] font-bold uppercase tracking-widest text-neutral-400 shrink-0">Instruction</h4>
                                        <p className="text-[10px] text-neutral-600 font-mono leading-none">Upload HVI printouts. System auto-detects parameters.</p>
                                    </div>
                                    <span className="text-[9px] font-bold uppercase tracking-widest text-neutral-300">AUTO-OCR v2.0</span>
                                </div>
                            </div>
                        )}
                    </div>
                </div>

                {/* Table Section */}
                <div className="flex-1 flex flex-col bg-white overflow-hidden">
                    <div className="p-4 border-b border-neutral-200 flex items-center justify-between bg-white shrink-0">
                        <h3 className="text-xs font-bold uppercase tracking-widest text-neutral-500">Registry Buffer</h3>
                        <div className="text-[10px] uppercase font-mono text-neutral-400">
                            Live Database Connection
                        </div>
                    </div>

                    <div className="flex-1 overflow-auto p-4">
                        {samples.length === 0 ? (
                            <div className="h-full flex flex-col items-center justify-center space-y-4 opacity-20">
                                <Database className="h-12 w-12 text-black" />
                                <span className="text-xs font-bold uppercase tracking-[0.25em]">No Records Found</span>
                            </div>
                        ) : (
                            <div className="w-full overflow-x-auto">
                                <table className="w-full text-left border-collapse min-w-[1000px]">
                                    <thead className="bg-white sticky top-0 z-10 border-b border-black">
                                        <tr className="text-[9px] font-bold text-black uppercase tracking-widest">
                                            <th className="px-6 py-4 w-[60px] text-center font-mono">#ID</th>
                                            <th className="px-4 py-4">Bag ID</th>
                                            <th className="px-4 py-4">Tag</th>
                                            <th className="px-4 py-4">Timestamp</th>
                                            <th className="px-2 py-4 text-right font-mono">MIC</th>
                                            <th className="px-2 py-4 text-right font-mono">LEN</th>
                                            <th className="px-2 py-4 text-right font-mono">UNF</th>
                                            <th className="px-2 py-4 text-right font-mono">STR</th>
                                            <th className="px-2 py-4 text-right font-mono">RD</th>
                                            <th className="px-2 py-4 text-right font-mono">+B</th>
                                            <th className="px-6 py-4 text-right w-[120px]">Actions</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-neutral-100">
                                        {samples.slice().reverse().map((s) => (
                                            <tr key={s.id} className="group hover:bg-neutral-50 transition-colors">
                                                <td className="px-6 py-4 font-mono text-xs text-neutral-400 text-center">#{s.amostra_id}</td>
                                                <td className="px-4 py-4 font-mono text-xs font-bold text-black">{s.mala || "-"}</td>
                                                <td className="px-4 py-4 font-mono text-xs text-neutral-500">{s.etiqueta || "-"}</td>
                                                <td className="px-4 py-4 text-[10px] font-mono text-neutral-400">
                                                    {s.data_analise} <span className="opacity-50">{s.hora_analise}</span>
                                                </td>
                                                <td className="px-2 py-4 text-right font-mono text-xs tabular-nums">{formatDecimalBR(s.mic ?? 0, 2)}</td>
                                                <td className="px-2 py-4 text-right font-mono text-xs tabular-nums text-neutral-500">{formatDecimalBR(s.len ?? 0, 2)}</td>
                                                <td className="px-2 py-4 text-right font-mono text-xs tabular-nums text-neutral-500">{formatDecimalBR(s.unf ?? 0, 1)}</td>
                                                <td className="px-2 py-4 text-right font-mono text-xs tabular-nums text-neutral-500">{formatDecimalBR(s.str ?? 0, 1)}</td>
                                                <td className="px-2 py-4 text-right font-mono text-xs tabular-nums text-neutral-500">{formatDecimalBR(s.rd ?? 0, 1)}</td>
                                                <td className="px-2 py-4 text-right font-mono text-xs tabular-nums text-neutral-500">{formatDecimalBR(s.b ?? 0, 1)}</td>
                                                <td className="px-6 py-4 text-right">
                                                    <div className="flex items-center justify-end gap-2">
                                                        <Button
                                                            variant="ghost"
                                                            size="icon"
                                                            className="h-8 w-8 text-neutral-300 hover:text-white hover:bg-blue-600 rounded-none transition-all"
                                                            onClick={() => handleExportHVI(s)}
                                                            title="Gerar arquivo HVI"
                                                        >
                                                            <FileDown className="h-4 w-4" />
                                                        </Button>
                                                        <Button
                                                            variant="ghost"
                                                            size="icon"
                                                            className="h-8 w-8 text-neutral-300 hover:text-white hover:bg-black rounded-none transition-all"
                                                            onClick={() => setModalAction({ type: 'delete', id: s.id })}
                                                        >
                                                            <Trash2 className="h-4 w-4" />
                                                        </Button>
                                                    </div>
                                                </td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* Deletion Modal */}
            <Modal
                isOpen={modalAction?.type === 'delete'}
                onClose={() => setModalAction(null)}
                title="Confirm Deletion"
            >
                <div className="space-y-8 py-2 text-center">
                    <p className="text-xs text-neutral-500 font-bold uppercase tracking-widest leading-relaxed">
                        Permanently remove sample <span className="text-black font-black border-b border-black">#{samples.find(s => s.id === modalAction?.id)?.amostra_id}</span>?
                    </p>
                    <div className="grid grid-cols-1 gap-3 pt-2">
                        <Button
                            onClick={() => modalAction?.id && handleDeleteSample(modalAction.id)}
                            className="h-12 rounded-none bg-black text-white font-black uppercase text-[10px] tracking-widest hover:bg-neutral-800"
                        >
                            Confirm Delete
                        </Button>
                        <Button variant="ghost" onClick={() => setModalAction(null)} className="h-10 font-bold uppercase text-[9px] text-neutral-400 hover:text-black">Cancel</Button>
                    </div>
                </div>
            </Modal>
        </div>
    );
}

/**
 * Audit Log Service
 * Tracks all critical user actions for compliance and security
 */

export type AuditAction =
    | 'CREATE_LOTE'
    | 'UPDATE_LOTE'
    | 'DELETE_LOTE'
    | 'CREATE_SAMPLE'
    | 'UPDATE_SAMPLE'
    | 'DELETE_SAMPLE'
    | 'CREATE_USER'
    | 'UPDATE_USER'
    | 'DELETE_USER'
    | 'UPLOAD_DOCUMENT'
    | 'DELETE_DOCUMENT'
    | 'CREATE_LAB'
    | 'UPDATE_LAB'
    | 'DELETE_LAB'
    | 'LOGIN'
    | 'LOGOUT'
    | 'GENERATE_REPORT'
    | 'EXPORT_DATA'
    | 'IMPORT_DATA';

export interface AuditLogEntry {
    id: string;
    timestamp: string;
    userId: string;
    userName: string;
    action: AuditAction;
    entityType: string;
    entityId?: string;
    labId?: string;
    labName?: string;
    details: string;
    metadata?: Record<string, any>;
}

export class AuditLogService {
    private static STORAGE_KEY = 'audit-logs';
    private static MAX_LOGS = 10000; // Keep last 10k entries

    /**
     * Log an action
     */
    static log(
        userId: string,
        userName: string,
        action: AuditAction,
        entityType: string,
        details: string,
        options?: {
            entityId?: string;
            labId?: string;
            labName?: string;
            metadata?: Record<string, any>;
        }
    ): void {
        const entry: AuditLogEntry = {
            id: crypto.randomUUID(),
            timestamp: new Date().toISOString(),
            userId,
            userName,
            action,
            entityType,
            entityId: options?.entityId,
            labId: options?.labId,
            labName: options?.labName,
            details,
            metadata: options?.metadata
        };

        const logs = this.getAll();
        logs.unshift(entry); // Add to beginning

        // Keep only recent logs
        if (logs.length > this.MAX_LOGS) {
            logs.splice(this.MAX_LOGS);
        }

        localStorage.setItem(this.STORAGE_KEY, JSON.stringify(logs));
    }

    /**
     * Get all logs
     */
    static getAll(): AuditLogEntry[] {
        const data = localStorage.getItem(this.STORAGE_KEY);
        return data ? JSON.parse(data) : [];
    }

    /**
     * Get logs by user
     */
    static getByUser(userId: string): AuditLogEntry[] {
        return this.getAll().filter(log => log.userId === userId);
    }

    /**
     * Get logs by lab
     */
    static getByLab(labId: string): AuditLogEntry[] {
        return this.getAll().filter(log => log.labId === labId);
    }

    /**
     * Get logs by date range
     */
    static getByDateRange(startDate: Date, endDate: Date): AuditLogEntry[] {
        return this.getAll().filter(log => {
            const logDate = new Date(log.timestamp);
            return logDate >= startDate && logDate <= endDate;
        });
    }

    /**
     * Get logs by action type
     */
    static getByAction(action: AuditAction): AuditLogEntry[] {
        return this.getAll().filter(log => log.action === action);
    }

    /**
     * Export logs to CSV
     */
    static exportToCSV(): void {
        const logs = this.getAll();
        const headers = ['Timestamp', 'User', 'Action', 'Entity Type', 'Entity ID', 'Lab', 'Details'];
        const rows = logs.map(log => [
            log.timestamp,
            log.userName,
            log.action,
            log.entityType,
            log.entityId || '',
            log.labName || '',
            log.details
        ]);

        const csv = [
            headers.join(','),
            ...rows.map(row => row.map(cell => `"${cell}"`).join(','))
        ].join('\n');

        const blob = new Blob([csv], { type: 'text/csv' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `audit-log-${new Date().toISOString().split('T')[0]}.csv`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    }

    /**
     * Clear old logs (older than specified days)
     */
    static clearOldLogs(daysToKeep: number): number {
        const cutoffDate = new Date();
        cutoffDate.setDate(cutoffDate.getDate() - daysToKeep);

        const logs = this.getAll();
        const filtered = logs.filter(log => new Date(log.timestamp) >= cutoffDate);
        const removed = logs.length - filtered.length;

        localStorage.setItem(this.STORAGE_KEY, JSON.stringify(filtered));
        return removed;
    }
}

/**
 * Backup Service
 * Handles data export, import, and automatic backup scheduling
 */

import { LoteService } from '@/entities/Lote';
import { SampleService } from '@/entities/Sample';
import { AnalistaService } from '@/entities/Analista';
import { LabService } from '@/entities/Lab';
import { AuditService } from '@/entities/Audit';

export interface BackupData {
    version: string;
    timestamp: string;
    data: {
        lotes: any[];
        samples: any[];
        analistas: any[];
        labs: any[];
        auditDocuments: any[];
        auditCategories: any[];
    };
}

export class BackupService {
    private static VERSION = '1.0.0';

    /**
     * Export all system data to JSON
     */
    static async exportAll(): Promise<BackupData> {
        const [lotes, samples, analistas, labs, auditDocs, auditCats] = await Promise.all([
            LoteService.list(),
            SampleService.list(),
            AnalistaService.list(),
            LabService.list(),
            AuditService.list(),
            AuditService.listCategories()
        ]);

        return {
            version: this.VERSION,
            timestamp: new Date().toISOString(),
            data: {
                lotes,
                samples,
                analistas,
                labs,
                auditDocuments: auditDocs,
                auditCategories: auditCats
            }
        };
    }

    /**
     * Download backup as JSON file
     */
    static async downloadBackup(): Promise<void> {
        const backup = await this.exportAll();
        const blob = new Blob([JSON.stringify(backup, null, 2)], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');

        const timestamp = new Date().toISOString().split('T')[0];
        a.href = url;
        a.download = `origo-backup-${timestamp}.json`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    }

    /**
     * Import backup data
     */
    static async importBackup(file: File): Promise<{ success: boolean; message: string }> {
        try {
            const text = await file.text();
            const backup: BackupData = JSON.parse(text);

            // Validate backup format
            if (!backup.version || !backup.data) {
                return { success: false, message: 'Formato de backup inv├ílido' };
            }

            // Confirm with user
            const itemCount =
                backup.data.lotes.length +
                backup.data.samples.length +
                backup.data.analistas.length +
                backup.data.labs.length +
                backup.data.auditDocuments.length;

            if (!confirm(`Importar backup de ${backup.timestamp}?\n\n` +
                `Este backup cont├®m ${itemCount} itens.\n` +
                `ATEN├ç├âO: Dados atuais ser├úo preservados, mas pode haver duplicatas.`)) {
                return { success: false, message: 'Importa├º├úo cancelada pelo usu├írio' };
            }

            // Import data (this will merge with existing data)
            // In a real scenario, you'd want more sophisticated merge logic
            const { data } = backup;

            // Store backup data to localStorage directly for now
            // In production, you'd want proper merge/conflict resolution
            if (data.labs.length > 0) {
                const existing = await LabService.list();
                const merged = [...existing, ...data.labs.filter(l => !existing.find(e => e.id === l.id))];
                localStorage.setItem('labs', JSON.stringify(merged));
            }

            if (data.analistas.length > 0) {
                const existing = await AnalistaService.list();
                const merged = [...existing, ...data.analistas.filter(a => !existing.find(e => e.id === a.id))];
                localStorage.setItem('analistas', JSON.stringify(merged));
            }

            return {
                success: true,
                message: `Backup importado com sucesso!\n${itemCount} itens processados.`
            };

        } catch (error) {
            console.error('Import error:', error);
            return {
                success: false,
                message: 'Erro ao importar backup: ' + (error instanceof Error ? error.message : 'Erro desconhecido')
            };
        }
    }

    /**
     * Schedule automatic backups
     */
    static scheduleAutoBackup(intervalHours: number = 24): void {
        const intervalMs = intervalHours * 60 * 60 * 1000;

        setInterval(async () => {
            const backup = await this.exportAll();
            localStorage.setItem('last-auto-backup', JSON.stringify(backup));
            localStorage.setItem('last-backup-date', new Date().toISOString());
        }, intervalMs);
    }

    /**
     * Get last backup date
     */
    static getLastBackupDate(): string | null {
        return localStorage.getItem('last-backup-date');
    }
}

import { type Sample } from "@/entities/Sample";

export interface PatternGroup {
    id: string;
    label?: string;
    micAvg: number;
    lenAvg: number;
    unfAvg: number;
    strAvg: number;
    rdAvg: number;
    bAvg: number;
    count: number;
    sampleIds: string[];
    color: string | null;
    patternFeatures?: string[];
}

export class DeepSeekService {
    /**
     * Gera uma an├ílise descritiva t├®cnica baseada na hierarquia de par├ómetros.
     */
    public static async analyzeSamples(samples: Sample[]): Promise<string> {
        if (!samples || samples.length === 0) return "Sem sinal de dados para processamento.";

        const groups = this.classifySamplesSmart(samples);
        const dominant = this.findDominantFactor(samples);

        let report = `[ SISTEMA DE INTELIG├èNCIA FIBERSCAN - RELAT├ôRIO T├ëCNICO ]\n`;
        report += `===========================================================\n\n`;
        report += `EXAME HIER├üRQUICO DE ${samples.length} OBSERVA├ç├òES\n\n`;

        if (groups.length > 0) {
            // Infer selected parameter from pattern features? Or just describe groups.
            report += `DIAGN├ôSTICO: O grupo foi segmentado prioritariamente por padr├Áes de similaridade estat├¡stica.\n\n`;

            groups.forEach((g, idx) => {
                const pct = ((g.count / samples.length) * 100).toFixed(1);
                report += `${idx + 1}. ${g.label?.toUpperCase()} (${pct}% do Lote)\n`;
                report += `   - CARACTER├ìSTICA: ${g.patternFeatures?.join(" + ") || "Padr├úo de Refer├¬ncia"}\n`;
                report += `   - M├ëTRICAS: MIC ${g.micAvg.toFixed(2)} | LEN ${g.lenAvg.toFixed(2)} | STR ${g.strAvg.toFixed(1)}\n\n`;
            });
        }

        report += `AN├üLISE DE VOLATILIDADE:\n`;
        report += `O par├ómetro "${dominant.name}" apresenta a maior press├úo de variabilidade (CV: ${dominant.cv.toFixed(2)}%).\n`;

        report += `\nCONCLUS├âO T├ëCNICA:\n`;
        if (groups.length > 1) {
            report += `Lote com heterogeneidade identificada. A classifica├º├úo seguiu a ordem de sensibilidade t├®cnica (MIC > LEN > UI > STR). Foram isolados ${groups.length} n├║cleos de comportamento distinto.`;
        } else {
            report += `Lote com alt├¡ssima estabilidade. N├úo foram detectados desvios significativos em nenhum dos par├ómetros na ordem de prioridade.`;
        }

        return report;
    }

    /**
     * Agrupa as amostras seguindo a hierarquia solicitada:
     * 1. MIC (se houver padr├úo conciso)
     * 2. LEN (UHML)
     * 3. UNF (UI)
     * 4. STR
     * 5. RD
     * 6. +B
     */
    public static classifySamplesSmart(samples: Sample[]): PatternGroup[] {
        if (!samples || samples.length === 0) return [];

        // 1. Parse de dados
        const data = samples.map(s => ({
            id: s.id,
            mic: parseFloat(s.mic?.toString().replace(',', '.') || '0'),
            len: parseFloat(s.len?.toString().replace(',', '.') || '0'),
            unf: parseFloat(s.unf?.toString().replace(',', '.') || '0'),
            str: parseFloat(s.str?.toString().replace(',', '.') || '0'),
            rd: parseFloat(s.rd?.toString().replace(',', '.') || '0'),
            b: parseFloat(s.b?.toString().replace(',', '.') || '0'),
        }));

        const hierarchy = [
            { key: 'mic', label: 'MICRONAIRE', cvThreshold: 1.2 },
            { key: 'len', label: 'COMPRIMENTO (LEN)', cvThreshold: 1.0 },
            { key: 'unf', label: 'UNIFORMIDADE (UNF)', cvThreshold: 0.8 },
            { key: 'str', label: 'RESIST├èNCIA (STR)', cvThreshold: 1.5 },
            { key: 'rd', label: 'REFLET├éNCIA (RD)', cvThreshold: 1.2 },
            { key: 'b', label: 'AMARELECIMENTO (+B)', cvThreshold: 2.5 },
        ];

        let selected = hierarchy[0];
        let finalMean = 0;
        let finalStd = 0;

        // 2. Encontrar o primeiro par├ómetro com "padr├úo conciso" (CV acima do threshold)
        for (const p of hierarchy) {
            const vals = data.map(d => (d as any)[p.key]);
            const mean = vals.reduce((a, b) => a + b, 0) / vals.length;
            const variance = vals.reduce((acc, v) => acc + Math.pow(v - mean, 2), 0) / vals.length;
            const std = Math.sqrt(variance);
            const cv = (std / (mean || 1)) * 100;

            if (cv >= p.cvThreshold || p === hierarchy[hierarchy.length - 1]) {
                selected = p;
                finalMean = mean;
                finalStd = std;
                break;
            }
        }

        // 3. Agrupamento em 4 n├¡veis baseado no par├ómetro escolhido
        const groups: PatternGroup[] = [];
        const colors = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444']; // Azul, Verde, Amarelo, Vermelho

        const assignments: { [key: string]: number } = {};
        data.forEach(s => {
            const val = (s as any)[selected.key];
            // Dividir em 4 zonas baseadas no desvio padr├úo
            if (val >= finalMean + 0.5 * finalStd) assignments[s.id] = 0; // Top
            else if (val >= finalMean) assignments[s.id] = 1;             // Mid-High
            else if (val >= finalMean - 0.5 * finalStd) assignments[s.id] = 2; // Mid-Low
            else assignments[s.id] = 3;                                  // Bottom
        });

        // 4. Consolida├º├úo
        [0, 1, 2, 3].forEach(idx => {
            const clusterData = data.filter(d => assignments[d.id] === idx);
            if (clusterData.length === 0) return;

            const avg = (k: keyof typeof clusterData[0]) =>
                clusterData.reduce((a, b) => a + (b[k] as number), 0) / clusterData.length;

            // Gerar labels baseados no par├ómetro escolhido
            let featureName = "";
            if (idx === 0) featureName = `${selected.label} Superior`;
            else if (idx === 1) featureName = `${selected.label} Acima da M├®dia`;
            else if (idx === 2) featureName = `${selected.label} Abaixo da M├®dia`;
            else featureName = `${selected.label} Inferior`;

            groups.push({
                id: `G${idx + 1}`,
                label: `GRUPO ${idx + 1}`,
                micAvg: avg('mic'),
                lenAvg: avg('len'),
                unfAvg: avg('unf'),
                strAvg: avg('str'),
                rdAvg: avg('rd'),
                bAvg: avg('b'),
                count: clusterData.length,
                sampleIds: clusterData.map(d => d.id),
                color: colors[idx],
                patternFeatures: [featureName, `Foco: ${selected.key.toUpperCase()}`]
            });
        });

        return groups;
    }

    private static findDominantFactor(samples: Sample[]) {
        const params = ['mic', 'len', 'str', 'rd'];
        const cvs = params.map(p => {
            const vals = samples.map(s => parseFloat((s as any)[p]?.toString().replace(',', '.') || '0'));
            const mean = vals.reduce((a, b) => a + b, 0) / vals.length;
            const variance = vals.reduce((acc, v) => acc + Math.pow(v - mean, 2), 0) / vals.length;
            const std = Math.sqrt(variance);
            return { name: p.toUpperCase(), cv: (std / (mean || 1)) * 100 };
        });
        return cvs.sort((a, b) => b.cv - a.cv)[0];
    }
}

import { type Sample } from "@/entities/Sample";

export interface HVIAnalysisConfig {
    targetParams: string[];
    useOutliersInModel: boolean;
    machineGrouping: boolean;
    colorGrouping: boolean;
}

export interface ParameterStats {
    mean: number;
    stdDev: number;
    cv: number;
    min: number;
    max: number;
    q1: number;
    q3: number;
    iqr: number;
}

export interface OutlierInfo {
    sampleId: string;
    value: number;
    zScore: number;
    severity: 'NORMAL' | 'ALERTA' | 'CRITICO';
}

export interface PredictionResult {
    predictedNextValue: number;
    confidenceInterval: [number, number];
    probabilityWithinRange: number;
    mae: number;
    rmse: number;
    status: 'OK' | 'ALERTA' | 'CRITICO';
}

export interface ParameterAnalysis {
    param: string;
    displayName: string;
    stats: ParameterStats;
    outliers: OutlierInfo[];
    prediction: PredictionResult;
    distribution: { label: string, value: number, percent: number }[];
    trend: number[]; // Added for Trend Analysis chart
    discriminantScore: number;
    isDominant: boolean;
}

export interface CorrelationMatrix {
    [key: string]: { [key: string]: number };
}

export interface HVIAnalysisReport {
    timestamp: string;
    initialCount: number;
    cleanedCount: number;
    outlierCount: number;
    machine: string;
    groupType: 'MACHINE' | 'COLOR' | 'CONSOLIDATED';
    parameterAnalyses: ParameterAnalysis[];
    correlationMatrix: CorrelationMatrix;
    consolidated: {
        weightedMean: number;
        globalInterval: [number, number];
        globalProbability: number;
        status: 'OK' | 'ALERTA' | 'CRITICO';
    };
    validation: {
        maeGlobal: number;
        rmseGlobal: number;
        withinICPercentage: number;
        falseAlertRate: number;
        isValid: boolean;
    };
    logs: string[];
}

export class HVIAnalysisService {
    private static PARAMS = ['mic', 'len', 'unf', 'str', 'rd', 'b'];
    private static PARAM_NAMES: Record<string, string> = {
        mic: 'MIC',
        len: 'LEN(UHML)',
        unf: 'UNF',
        str: 'STR',
        rd: 'RD',
        b: '+B'
    };

    /**
     * Core Analysis Entry point. Returns all groups (Consolidated, Machine, and Color).
     */
    public static async analyze(samples: Sample[]): Promise<HVIAnalysisReport[]> {
        const results: HVIAnalysisReport[] = [];
        if (!samples || samples.length === 0) return [];

        // 1. GERAL (Consolidado)
        try {
            const report = this.processGroup('RELAT├ôRIO GERAL (CONSOLIDADO)', samples, {});
            report.groupType = 'CONSOLIDATED';
            results.push(report);
        } catch (e) {
            console.warn("Erro no consolidado", e);
        }

        // 2. POR M├üQUINA
        const machineGroups: { [key: string]: Sample[] } = {};
        samples.forEach(s => {
            const m = s.hvi || 'HVI_N├âO_IDENTIFICADA';
            if (!machineGroups[m]) machineGroups[m] = [];
            machineGroups[m].push(s);
        });

        // Process each machine if there are specifically multiple machines or it's identified
        if (Object.keys(machineGroups).length > 0) {
            for (const [m, s] of Object.entries(machineGroups)) {
                try {
                    const report = this.processGroup(`M├üQUINA: ${m}`, s, {});
                    report.groupType = 'MACHINE';
                    results.push(report);
                } catch (e) { }
            }
        }

        // 3. POR COR (Qualidade)
        const colorGroups: { [key: string]: Sample[] } = {};
        samples.forEach(s => {
            const c = s.cor || 'SEM_CLASSIFICA├ç├âO';
            if (!colorGroups[c]) colorGroups[c] = [];
            colorGroups[c].push(s);
        });

        if (Object.keys(colorGroups).length > 0) {
            for (const [c, s] of Object.entries(colorGroups)) {
                try {
                    const report = this.processGroup(`QUALIDADE: ${c}`, s, {});
                    report.groupType = 'COLOR';
                    results.push(report);
                } catch (e) { }
            }
        }

        return results;
    }

    private static processGroup(groupName: string, samples: Sample[], _config: Partial<HVIAnalysisConfig>): HVIAnalysisReport {
        const logs: string[] = [];
        const initialCount = samples.length;

        // Clean and validate data (handling comma notation)
        const validSamples = samples.filter(s => this.isValid(s));
        const n = validSamples.length;
        logs.push(`Iniciando an├ílise para ${groupName}. Amostras v├ílidas: ${n}/${initialCount}`);

        if (n < 1) {
            throw new Error(`Dados insuficientes (n=${n}). M├¡nimo de 1 amostra necess├íria.`);
        }

        const analysesMap: Record<string, ParameterAnalysis> = {};
        const matrixData: number[][] = [];

        this.PARAMS.forEach(param => {
            // Filter samples that have THIS specific parameter
            const paramValues = validSamples
                .map(s => {
                    const val = (s as any)[param];
                    if (val === undefined || val === null || val === '') return null;
                    const num = parseFloat(val.toString().replace(',', '.'));
                    return isNaN(num) ? null : num;
                })
                .filter((v): v is number => v !== null);

            if (paramValues.length === 0) return; // Skip if no data for this param

            const stats = this.calculateStats(paramValues);
            const outliers = this.detectOutliers(validSamples, param, stats);
            const prediction = this.calculatePrediction(paramValues, stats);

            // Calculate Histogram / Distribution
            const distribution = this.calculateDistribution(paramValues);

            // Trend data (Sequence of values)
            const trend = paramValues;

            analysesMap[param] = {
                param,
                displayName: this.PARAM_NAMES[param],
                stats,
                outliers,
                prediction,
                distribution,
                trend,
                discriminantScore: 0,
                isDominant: false
            };
        });

        // Normalize matrix for PCA
        validSamples.forEach(s => {
            const row: number[] = this.PARAMS.map(p => {
                const val = parseFloat(((s as any)[p] || 0).toString().replace(',', '.'));
                const stats = analysesMap[p].stats;
                return (val - stats.mean) / (stats.stdDev || 1);
            });
            matrixData.push(row);
        });

        // PCA Calculation for Dominant Parameter
        const loadings = this.calculateFirstComponentLoadings(matrixData);
        const scores: number[] = [];
        this.PARAMS.forEach((param, i) => {
            const analysis = analysesMap[param];
            const loading = Math.abs(loadings[i]);
            // Higher score if it has high loading and stable CV
            analysis.discriminantScore = loading / (analysis.stats.cv / 100 || 0.001);
            scores.push(analysis.discriminantScore);
        });

        const meanScore = scores.reduce((a, b) => a + b, 0) / scores.length;
        const cvs = this.PARAMS.map(p => analysesMap[p].stats.cv).sort((a, b) => a - b);
        const p50CV = cvs[Math.floor(cvs.length / 2)];

        let dominantParam: string | null = null;
        this.PARAMS.forEach(param => {
            const analysis = analysesMap[param];
            if (analysis.discriminantScore >= 1.25 * meanScore && analysis.stats.cv <= p50CV) {
                analysis.isDominant = true;
                dominantParam = param;
                logs.push(`Par├ómetro Cr├¡tico/Dominante: ${analysis.displayName}`);
            }
        });

        // Calculate Weights
        const weights: Record<string, number> = {};
        if (dominantParam) {
            this.PARAMS.forEach(p => weights[p] = p === dominantParam ? 0.40 : (0.60 / (this.PARAMS.length - 1)));
        } else {
            this.PARAMS.forEach(p => weights[p] = 1 / this.PARAMS.length);
        }

        let weightedMeanSum = 0;
        let globalProbSum = 0;
        this.PARAMS.forEach(p => {
            weightedMeanSum += analysesMap[p].stats.mean * weights[p];
            globalProbSum += analysesMap[p].prediction.probabilityWithinRange * weights[p];
        });

        const validation = this.validateModel(validSamples, analysesMap, weights);

        return {
            timestamp: new Date().toISOString(),
            initialCount,
            cleanedCount: n,
            outlierCount: validSamples.filter(s => this.PARAMS.some(p => {
                const val = parseFloat(((s as any)[p] || 0).toString().replace(',', '.'));
                return Math.abs((val - analysesMap[p].stats.mean) / (analysesMap[p].stats.stdDev || 1)) > 2;
            })).length,
            machine: groupName,
            groupType: 'CONSOLIDATED',
            parameterAnalyses: Object.values(analysesMap),
            correlationMatrix: this.calculateCorrelationMatrix(validSamples),
            consolidated: {
                weightedMean: weightedMeanSum,
                globalInterval: [weightedMeanSum * 0.95, weightedMeanSum * 1.05],
                globalProbability: globalProbSum,
                status: globalProbSum >= 90 ? 'OK' : globalProbSum >= 70 ? 'ALERTA' : 'CRITICO'
            },
            validation,
            logs
        };
    }

    private static isValid(s: Sample): boolean {
        // A sample is valid if it has AT LEAST one numeric parameter
        return this.PARAMS.some(p => {
            const val = (s as any)[p];
            if (val === undefined || val === null || val === '') return false;
            return !isNaN(parseFloat(val.toString().replace(',', '.')));
        });
    }

    private static calculateStats(values: number[]): ParameterStats {
        const n = values.length;
        const mean = values.reduce((a, b) => a + b, 0) / n;
        const variance = values.map(v => Math.pow(v - mean, 2)).reduce((a, b) => a + b, 0) / (n - 1 || 1);
        const stdDev = Math.sqrt(variance);
        const sorted = [...values].sort((a, b) => a - b);
        return {
            mean, stdDev, cv: mean === 0 ? 0 : (stdDev / mean) * 100,
            min: sorted[0], max: sorted[n - 1],
            q1: sorted[Math.floor(n * 0.25)], q3: sorted[Math.floor(n * 0.75)],
            iqr: (sorted[Math.floor(n * 0.75)] || 0) - (sorted[Math.floor(n * 0.25)] || 0)
        };
    }

    private static detectOutliers(samples: Sample[], param: string, stats: ParameterStats): OutlierInfo[] {
        return samples.map(s => {
            const val = parseFloat(((s as any)[param] || 0).toString().replace(',', '.'));
            const z = stats.stdDev === 0 ? 0 : (val - stats.mean) / stats.stdDev;
            return { sampleId: s.id, value: val, zScore: z, severity: Math.abs(z) > 3 ? 'CRITICO' : Math.abs(z) > 2 ? 'ALERTA' : 'NORMAL' };
        });
    }

    private static calculatePrediction(values: number[], stats: ParameterStats): PredictionResult {
        const n = values.length;
        const margin = 1.96 * stats.stdDev;
        const ci: [number, number] = [stats.mean - margin, stats.mean + margin];
        const prob = (this.normalCDF(ci[1], stats.mean, stats.stdDev) - this.normalCDF(ci[0], stats.mean, stats.stdDev)) * 100;

        let mae = 0, rmseSq = 0;
        for (let i = 1; i < n; i++) {
            const err = Math.abs(values[i] - (values.slice(0, i).reduce((a, b) => a + b, 0) / i));
            mae += err; rmseSq += err * err;
        }

        return {
            predictedNextValue: stats.mean,
            confidenceInterval: ci,
            probabilityWithinRange: prob,
            mae: mae / (n - 1 || 1),
            rmse: Math.sqrt(rmseSq / (n - 1 || 1)),
            status: prob >= 90 ? 'OK' : prob >= 70 ? 'ALERTA' : 'CRITICO'
        };
    }

    private static normalCDF(x: number, mean: number, stdDev: number): number {
        if (stdDev <= 0) return x >= mean ? 1 : 0;
        const z = (x - mean) / stdDev;
        const t = 1 / (1 + 0.2316419 * Math.abs(z));
        const d = 0.3989423 * Math.exp(-z * z / 2);
        const p = d * t * (0.3193815 + t * (-0.3565638 + t * (1.7814779 + t * (-1.821256 + t * 1.330274))));
        return z >= 0 ? 1 - p : p;
    }

    private static calculateFirstComponentLoadings(matrix: number[][]): number[] {
        const m = matrix[0].length;
        const cov: number[][] = Array.from({ length: m }, () => Array(m).fill(0));
        for (let i = 0; i < m; i++) for (let j = 0; j < m; j++) {
            let sum = 0; for (let k = 0; k < matrix.length; k++) sum += matrix[k][i] * matrix[k][j];
            cov[i][j] = sum / (matrix.length - 1 || 1);
        }
        let b = Array(m).fill(0).map(() => Math.random());
        for (let iter = 0; iter < 10; iter++) {
            const nb = Array(m).fill(0);
            for (let i = 0; i < m; i++) for (let j = 0; j < m; j++) nb[i] += cov[i][j] * b[j];
            const norm = Math.sqrt(nb.reduce((a, c) => a + c * c, 0)) || 1;
            b = nb.map(v => v / norm);
        }
        return b;
    }

    private static validateModel(samples: Sample[], analyses: Record<string, ParameterAnalysis>, weights: Record<string, number>) {
        let mae = 0, rmseSq = 0, within = 0, total = 0;
        this.PARAMS.forEach(p => {
            mae += analyses[p].prediction.mae * weights[p];
            rmseSq += Math.pow(analyses[p].prediction.rmse, 2) * weights[p];
            samples.forEach(s => {
                const v = parseFloat(((s as any)[p] || 0).toString().replace(',', '.'));
                if (v >= analyses[p].prediction.confidenceInterval[0] && v <= analyses[p].prediction.confidenceInterval[1]) within++;
                total++;
            });
        });
        const rmse = Math.sqrt(rmseSq);
        const avgSD = this.PARAMS.reduce((a, b) => a + analyses[b].stats.stdDev, 0) / this.PARAMS.length;
        return { maeGlobal: mae, rmseGlobal: rmse, withinICPercentage: (within / (total || 1)) * 100, falseAlertRate: 0, isValid: rmse <= (avgSD || 1) };
    }

    private static calculateCorrelationMatrix(samples: Sample[]): CorrelationMatrix {
        const matrix: CorrelationMatrix = {};
        this.PARAMS.forEach(p1 => {
            matrix[p1] = {};
            this.PARAMS.forEach(p2 => {
                const x = samples.map(s => parseFloat(((s as any)[p1] || 0).toString().replace(',', '.')));
                const y = samples.map(s => parseFloat(((s as any)[p2] || 0).toString().replace(',', '.')));
                matrix[p1][p2] = this.pearson(x, y);
            });
        });
        return matrix;
    }

    private static pearson(x: number[], y: number[]): number {
        const n = x.length;
        const mx = x.reduce((a, b) => a + b, 0) / n, my = y.reduce((a, b) => a + b, 0) / n;
        let num = 0, dx2 = 0, dy2 = 0;
        for (let i = 0; i < n; i++) {
            const dx = x[i] - mx, dy = y[i] - my;
            num += dx * dy; dx2 += dx * dx; dy2 += dy * dy;
        }
        return Math.sqrt(dx2 * dy2) === 0 ? 0 : num / Math.sqrt(dx2 * dy2);
    }

    private static calculateDistribution(values: number[], buckets = 10): { label: string, value: number, percent: number }[] {
        if (!values.length) return [];
        const min = Math.min(...values);
        const max = Math.max(...values);
        const range = max - min || 1;
        const step = range / buckets;

        const counts = new Array(buckets).fill(0);
        values.forEach(v => {
            const idx = Math.min(Math.floor((v - min) / step), buckets - 1);
            counts[idx]++;
        });

        return counts.map((count, i) => ({
            label: (min + i * step).toFixed(2),
            value: count,
            percent: (count / values.length) * 100
        }));
    }
}

/**
 * HVI File Generator Service
 * Generates HVI format files (Uster/Premier) for individual samples
 * Based on color average and machine model - Using Interlaboratorial format
 */

import type { Sample } from '@/entities/Sample';
import { MachineService, type Machine } from '@/entities/Machine';

export interface HVIPreviewData {
    content: string;
    filename: string;
    machineModel: 'USTER' | 'PREMIER';
    generatedValues: {
        mic: number;
        len: number;
        unf: number;
        str: number;
        rd: number;
        b: number;
    };
}

export class HVIFileGeneratorService {

    /**
     * Get machine by HVI number
     */
    /**
     * Get machine by HVI number
     */
    private static async getMachineByHVI(hviNumber: string): Promise<Machine | null> {
        try {
            const machines = await MachineService.list();

            // Try exact match
            const exactMatch = machines.find(m => m.machineId === hviNumber);
            if (exactMatch) return exactMatch;

            // Try loose match (ignoring spaces, case)
            const looseMatch = machines.find(m =>
                m.machineId.trim().toUpperCase() === hviNumber.trim().toUpperCase()
            );
            return looseMatch || null;
        } catch (error) {
            console.error('Error loading machines:', error);
            return null;
        }
    }

    /**
     * Get target values for generation (prioritizes Sample values, then Color Average)
     */
    private static getSampleTargetValues(sample: Sample, allSamples: Sample[] = []): { mic: number; len: number; unf: number; str: number; rd: number; b: number } {
        // Return Color Average strictly (Interlaboratorial rule: use average for the color)
        return this.getColorAverage(sample.cor, allSamples);

        // Fallback to Color Average (Original Logic)
        return this.getColorAverage(sample.cor, allSamples);
    }

    /**
     * Get average values based on sample color (Fallback)
     */
    private static getColorAverage(color?: string, allSamples: Sample[] = []): { mic: number; len: number; unf: number; str: number; rd: number; b: number } {
        const defaultValues = { mic: 4.50, len: 29.0, unf: 80.0, str: 29.0, rd: 80.0, b: 11.0 };

        if (!color) return defaultValues;

        try {
            // First, calculate averages from samples
            const colorSamples = allSamples.filter(s => s.cor === color);

            let calculatedAverages = { ...defaultValues };

            if (colorSamples.length > 0) {
                if (colorSamples.length > 0) {
                    // Calculate averages from real data
                    const calculateAvg = (field: keyof Sample) => {
                        const values = colorSamples
                            .map(s => {
                                const val = s[field];
                                if (typeof val === 'number') return val;
                                if (typeof val === 'string') return parseFloat(val.replace(',', '.'));
                                return NaN;
                            })
                            .filter(v => typeof v === 'number' && !isNaN(v)) as number[];

                        if (values.length === 0) return defaultValues[field as keyof typeof defaultValues];

                        const sum = values.reduce((acc, val) => acc + val, 0);
                        const avg = sum / values.length;
                        return avg;
                    };

                    calculatedAverages = {
                        mic: calculateAvg('mic'),
                        len: calculateAvg('len'),
                        unf: calculateAvg('unf'),
                        str: calculateAvg('str'),
                        rd: calculateAvg('rd'),
                        b: calculateAvg('b')
                    };
                }
            }

            // Now check for custom (manually edited) averages and merge
            const customAveragesStr = localStorage.getItem('custom_color_averages');
            if (customAveragesStr) {
                try {
                    const customAverages = JSON.parse(customAveragesStr);
                    if (customAverages[color]) {
                        const custom = customAverages[color];

                        // Merge: use custom if exists, otherwise use calculated
                        const result = {
                            mic: custom.mic ?? calculatedAverages.mic,
                            len: custom.len ?? calculatedAverages.len,
                            unf: custom.unf ?? calculatedAverages.unf,
                            str: custom.str ?? calculatedAverages.str,
                            rd: custom.rd ?? calculatedAverages.rd,
                            b: custom.b ?? calculatedAverages.b
                        };
                        return result;
                    }
                } catch (e) {
                    console.warn('Error parsing custom averages:', e);
                }
            }

            return calculatedAverages;
        } catch (error) {
            console.error('Error calculating color averages:', error);
            return defaultValues;
        }
    }

    /**
     * Generate random variation around a base value
     */
    private static randomVariation(base: number, variance: number, decimals: number): number {
        const variation = (Math.random() - 0.5) * 2 * variance;
        return parseFloat((base + variation).toFixed(decimals));
    }

    /**
     * Format date for filename
     */
    private static formatDateForFilename(): string {
        const now = new Date();
        const year = now.getFullYear();
        const month = String(now.getMonth() + 1).padStart(2, '0');
        const day = String(now.getDate()).padStart(2, '0');
        const hours = String(now.getHours()).padStart(2, '0');
        const minutes = String(now.getMinutes()).padStart(2, '0');
        return `${year}${month}${day}_${hours}${minutes}`;
    }

