            const cg = '"11-3"'; // Default from example
            const sfi = this.randomVariation(12.0, 1.0, 1); // Closer to example 11.9
            const grd = '"2"'; // Default from example
            const cnt = Math.round(this.randomVariation(20, 8, 0)); // Closer to example 18
            const area = this.randomVariation(0.30, 0.08, 2); // Closer to example 0.32
            const mat = this.randomVariation(0.85, 0.04, 2); // Closer to example 0.84

            // Store for stats
            numerics.uhml.push(uhml); numerics.ml.push(ml); numerics.ui.push(ui);
            numerics.elg.push(elg); numerics.str.push(str); numerics.mic.push(mic);
            numerics.rd.push(rd); numerics.b.push(plusB); numerics.sfi.push(sfi);
            numerics.cnt.push(cnt); numerics.area.push(area); numerics.mat.push(mat);

            rows.push([
                i + 1,
                `"${sample.etiqueta || 'SAMPLE'} "`,
                fmt(uhml, 2), fmt(ml, 2), fmt(ui, 1), fmt(elg, 1), fmt(str, 1), fmt(mic, 2),
                fmt(rd, 1), fmt(plusB, 1), cg, fmt(sfi, 1), grd, cnt, fmt(area, 2), fmt(mat, 2)
            ].join('\t'));
        }

        // Stats Calculation
        const keys = ['uhml', 'ml', 'ui', 'elg', 'str', 'mic', 'rd', 'b', 'sfi', 'cnt', 'area', 'mat'];
        const stats: Record<string, any> = {};

        keys.forEach(key => {
            const vals = numerics[key];
            const mean = calcMean(vals);
            const sd = calcSD(vals);
            stats[key] = {
                mean: mean,
                median: calcMedian(vals),
                sd: sd,
                cv: calcCV(mean, sd),
                min: calcMin(vals),
                max: calcMax(vals)
            };
        });

        // Formatting Helpers
        const fMean = (k: string, d: number) => fmt(stats[k].mean, d);
        const fMed = (k: string, d: number) => fmt(stats[k].median, d);
        const fSD = (k: string, d: number) => fmt(stats[k].sd, d); // SD usually same decimals or +1? User example: 0.24 (2 decimals) for UHML.
        const fCV = (k: string) => fmt(stats[k].cv, 2);
        const fMin = (k: string, d: number) => fmt(stats[k].min, d);
        const fMax = (k: string, d: number) => fmt(stats[k].max, d);

        // Stats Rows Construction
        const statsRows = [];
        statsRows.push(`" Statistics"`);

        // Avg Row: "Avg" "11-3" "2" ...
        statsRows.push([
            `"Avg"`, `"11-3"`, `"2"`,
            fMean('uhml', 2), fMean('ml', 2), fMean('ui', 1), fMean('elg', 1), fMean('str', 1), fMean('mic', 2),
            fMean('rd', 1), fMean('b', 1), fMean('sfi', 1), fMean('cnt', 0), fMean('area', 2), fMean('mat', 2)
        ].join('\t'));

        // Gap
        statsRows.push(``);
        statsRows.push(``);
        statsRows.push(``);
        statsRows.push(``);
        statsRows.push(``);
        statsRows.push(``);
        statsRows.push(``);
        statsRows.push(``); // User example has multiple empty lines

        // Other Stats: "Label"\t\t\t...
        const prefix = (label: string) => `"${label}"\t\t\t`;

        statsRows.push(prefix("Median") + [
            fMed('uhml', 2), fMed('ml', 2), fMed('ui', 1), fMed('elg', 1), fMed('str', 1), fMed('mic', 2),
            fMed('rd', 1), fMed('b', 1), fMed('sfi', 1), fMed('cnt', 0), fMed('area', 2), fMed('mat', 2)
        ].join('\t'));

        statsRows.push(prefix("SD") + [
            fSD('uhml', 2), fSD('ml', 2), fSD('ui', 1), fSD('elg', 1), fSD('str', 1), fSD('mic', 2),
            fSD('rd', 1), fSD('b', 1), fSD('sfi', 2), fSD('cnt', 2), fSD('area', 2), fSD('mat', 2) // SD decimals from user example (often 2)
        ].join('\t'));

        statsRows.push(prefix("CV%") + [
            fCV('uhml'), fCV('ml'), fCV('ui'), fCV('elg'), fCV('str'), fCV('mic'),
            fCV('rd'), fCV('b'), fCV('sfi'), fCV('cnt'), fCV('area'), fCV('mat')
        ].join('\t'));

        statsRows.push(prefix("Min") + [
            fMin('uhml', 2), fMin('ml', 2), fMin('ui', 1), fMin('elg', 1), fMin('str', 1), fMin('mic', 2),
            fMin('rd', 1), fMin('b', 1), fMin('sfi', 1), fMin('cnt', 0), fMin('area', 2), fMin('mat', 2)
        ].join('\t'));

        statsRows.push(prefix("Max") + [
            fMax('uhml', 2), fMax('ml', 2), fMax('ui', 1), fMax('elg', 1), fMax('str', 1), fMax('mic', 2),
            fMax('rd', 1), fMax('b', 1), fMax('sfi', 1), fMax('cnt', 0), fMax('area', 2), fMax('mat', 2)
        ].join('\t'));

        statsRows.push(``);
        statsRows.push(``);
        statsRows.push(``);

        return header.join('\n') + rows.join('\n') + '\n\n' + statsRows.join('\n');
    }

    /**
     * Generate preview data for a sample (does NOT download)
     */
    static async generatePreviewForSample(
        sample: Sample,
        allSamples: Sample[] = []
    ): Promise<{ success: boolean; message?: string; data?: HVIPreviewData }> {
        try {
            // Check if sample has HVI number
            if (!sample.hvi) {
                return {
                    success: false,
                    message: 'Amostra n├úo possui n├║mero HVI cadastrado'
                };
            }

            // Get machine info
            const machine = await this.getMachineByHVI(sample.hvi);
            if (!machine) {
                return {
                    success: false,
                    message: `M├íquina HVI ${sample.hvi} n├úo encontrada no cadastro`
                };
            }

            // Get the averages (Sample values or Color Average)
            const averages = this.getSampleTargetValues(sample, allSamples);

            // For preview modal: show EXACT average values (no variation)
            const generatedValues = {
                mic: averages.mic,
                len: averages.len,
                unf: averages.unf,
                str: averages.str,
                rd: averages.rd,
                b: averages.b
            };

            // For file content: generate 6 readings with variation
            let content: string;
            let extension: string;

            if (machine.model === 'USTER') {
                // Generate 6 Uster format lines
                const lines = Array(6).fill(null).map(() => this.generateUsterFormat(sample, allSamples));
                content = lines.join('\n');
                extension = 'txt';
            } else {
                // Generate Premier format with 6 readings
                content = this.generatePremierFormatMultiple(sample, 6, allSamples);
                extension = 'txt';
            }

            // Create filename
            const timestamp = this.formatDateForFilename();
            const sampleLabel = sample.etiqueta?.replace(/[^a-zA-Z0-9]/g, '_') || sample.amostra_id;
            const filename = `HVI_${machine.model}_${sampleLabel}_${timestamp}.${extension}`;

            return {
                success: true,
                data: {
                    content,
                    filename,
                    machineModel: machine.model,
                    generatedValues
                }
            };

        } catch (error) {
            console.error('Error generating HVI preview:', error);
            return {
                success: false,
                message: 'Erro ao gerar pr├®via HVI: ' + (error instanceof Error ? error.message : 'Erro desconhecido')
            };
        }
    }

    /**
     * Generate and download HVI file for a sample
     */
    static async generateFileForSample(sample: Sample): Promise<{ success: boolean; message: string }> {
        const result = await this.generatePreviewForSample(sample);

        if (!result.success || !result.data) {
            return {
                success: false,
                message: result.message || "Falha na gera├º├úo do arquivo"
            };
        }

        this.downloadHVIFile(result.data.content, result.data.filename);

        return {
            success: true,
            message: `Arquivo ${result.data.filename} gerado com sucesso.`
        };
    }

    /**
     * Download the HVI file content
     */
    static downloadHVIFile(content: string, filename: string): void {
        const blob = new Blob([content], { type: 'text/plain' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = filename;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    }
}

/**
 * Notification Service
 * Manages system notifications and alerts
 */

import { supabase } from "@/lib/supabase";

export type NotificationType = 'info' | 'warning' | 'error' | 'success';
export type NotificationPriority = 'low' | 'medium' | 'high' | 'critical';

export interface Notification {
    id: string;
    type: NotificationType;
    priority: NotificationPriority;
    title: string;
    message: string;
    timestamp: string;
    read: boolean;
    userId: string;
    labId?: string;
    actionUrl?: string;
    metadata?: Record<string, any>;
}

const isSupabaseEnabled = () => !!import.meta.env.VITE_SUPABASE_URL && !!import.meta.env.VITE_SUPABASE_ANON_KEY;

export class NotificationService {
    private static STORAGE_KEY = 'notifications';
    private static listeners: Set<(notifications: Notification[]) => void> = new Set();

    /**
     * Create a new notification
     */
    static async create(
        userId: string,
        type: NotificationType,
        priority: NotificationPriority,
        title: string,
        message: string,
        options?: {
            labId?: string;
            actionUrl?: string;
            metadata?: Record<string, any>;
        }
    ): Promise<Notification> {
        const notification: Notification = {
            id: crypto.randomUUID(),
            type,
            priority,
            title,
            message,
            timestamp: new Date().toISOString(),
            read: false,
            userId,
            labId: options?.labId,
            actionUrl: options?.actionUrl,
            metadata: options?.metadata
        };

        if (isSupabaseEnabled()) {
            // Clean payload
            const dbPayload = {
                id: notification.id,
                type: notification.type,
                priority: notification.priority,
                title: notification.title,
                message: notification.message,
                created_at: notification.timestamp,
                read: notification.read,
                user_id: notification.userId,
                lab_id: notification.labId,
                action_url: notification.actionUrl,
                metadata: notification.metadata
            };

            const { error } = await supabase.from('notificacoes').insert([dbPayload]);
            if (error) console.error("Error creating notification:", error);
            // We can optimistic update or just fetch
            this.notifyListeners(); // Will trigger fetch
            return notification;
        }

        const notifications = this.getAllSync();
        notifications.unshift(notification);

        this.saveSync(notifications);
        this.notifyListeners();

        return notification;
    }

    /**
     * Get all notifications (async)
     */
    static async getAll(): Promise<Notification[]> {
        if (isSupabaseEnabled()) {
            const { data, error } = await supabase
                .from('notificacoes')
                .select('*, userId:user_id, labId:lab_id, actionUrl:action_url, timestamp:created_at')
                .order('created_at', { ascending: false });

            if (error) {
                console.error("Error fetching notifications:", error);
                return [];
            }
            return data || [];
        }
        return this.getAllSync();
    }

    // Sync version for local storage compatibility
    private static getAllSync(): Notification[] {
        const data = localStorage.getItem(this.STORAGE_KEY);
        return data ? JSON.parse(data) : [];
    }

    /**
     * Get notifications for a user
     */
    static async getForUser(userId: string, unreadOnly = false): Promise<Notification[]> {
        if (isSupabaseEnabled()) {
            let query = supabase
                .from('notificacoes')
                .select('*, userId:user_id, labId:lab_id, actionUrl:action_url, timestamp:created_at')
                .eq('user_id', userId)
                .order('created_at', { ascending: false });

            if (unreadOnly) {
                query = query.eq('read', false);
            }

            const { data, error } = await query;
            if (error) return [];
            return data || [];
        }

        const all = this.getAllSync();
        let filtered = all.filter(n => n.userId === userId);

        if (unreadOnly) {
            filtered = filtered.filter(n => !n.read);
        }

        return filtered;
    }

    /**
     * Get unread count for user
     */
    static async getUnreadCount(userId: string): Promise<number> {
        const notifs = await this.getForUser(userId, true);
        return notifs.length;
    }

    /**
     * Mark notification as read
     */
    static async markAsRead(notificationId: string): Promise<void> {
        if (isSupabaseEnabled()) {
            await supabase.from('notificacoes').update({ read: true }).eq('id', notificationId);
            this.notifyListeners();
            return;
        }

        const notifications = this.getAllSync();
        const notification = notifications.find(n => n.id === notificationId);

        if (notification) {
            notification.read = true;
            this.saveSync(notifications);
            this.notifyListeners();
        }
    }

    /**
     * Mark all as read for user
     */
    static async markAllAsRead(userId: string): Promise<void> {
        if (isSupabaseEnabled()) {
            await supabase.from('notificacoes').update({ read: true }).eq('user_id', userId);
            this.notifyListeners();
            return;
        }

        const notifications = this.getAllSync();
        notifications.forEach(n => {
            if (n.userId === userId) {
                n.read = true;
            }
        });

        this.saveSync(notifications);
        this.notifyListeners();
    }

    /**
     * Delete notification
     */
    static async delete(notificationId: string): Promise<void> {
        if (isSupabaseEnabled()) {
            await supabase.from('notificacoes').delete().eq('id', notificationId);
            this.notifyListeners();
            return;
        }

        const notifications = this.getAllSync().filter(n => n.id !== notificationId);
        this.saveSync(notifications);
        this.notifyListeners();
    }

    /**
     * Subscribe to notification changes
     */
    static subscribe(callback: (notifications: Notification[]) => void): () => void {
        this.listeners.add(callback);

        // Initial fetch
        this.getAll().then(n => callback(n));

        let channel: any = null;

        if (isSupabaseEnabled()) {
            channel = supabase
                .channel('notifications-changes')
                .on(
                    'postgres_changes',
                    { event: '*', schema: 'public', table: 'notificacoes' },
                    async () => {
                        // Reload data when something changes
                        const notifications = await this.getAll();
                        callback(notifications);
                    }
                )
                .subscribe();
        }

        return () => {
            this.listeners.delete(callback);
            if (channel) supabase.removeChannel(channel);
        };
    }

    /**
     * Helper: Create quality document alert
     */
    static async createQualityAlert(userId: string, labId: string, labName: string, documentName: string): Promise<void> {
        await this.create(
            userId,
            'warning',
            'high',
            'Documento de Qualidade Pendente',
            `O documento "${documentName}" requer revis├úo no laborat├│rio ${labName}`,
            { labId, actionUrl: '/quality' }
        );
    }

    /**
     * Helper: Create compliance alert
     */
    static async createComplianceAlert(userId: string, labId: string, message: string): Promise<void> {
        await this.create(
            userId,
            'error',
            'critical',
            'N├úo Conformidade Detectada',
            message,
            { labId, actionUrl: '/quality' }
        );
    }

    /**
     * Helper: Create success notification
     */
    static async createSuccessNotification(userId: string, title: string, message: string): Promise<void> {
        await this.create(userId, 'success', 'low', title, message);
    }

    // Private methods
    private static saveSync(notifications: Notification[]): void {
        localStorage.setItem(this.STORAGE_KEY, JSON.stringify(notifications));
    }

    private static async notifyListeners(): Promise<void> {
        const notifications = await this.getAll();
        this.listeners.forEach(listener => listener(notifications));
    }
}

import { supabase } from '../lib/supabase';

export interface VerificacaoState {
    amostras: any[];
    analises: any[];
    date: string;
}

const isSupabaseEnabled = () => {
    const url = import.meta.env.VITE_SUPABASE_URL;
    const key = import.meta.env.VITE_SUPABASE_ANON_KEY;
    return !!url && url !== 'YOUR_SUPABASE_URL' && !!key && key !== 'YOUR_SUPABASE_ANON_KEY';
};

export const verificacaoService = {
    async save(labId: string, state: VerificacaoState): Promise<void> {
        // Envia para o Supabase se habilitado e labId for v├ílido (UUID)
        if (isSupabaseEnabled() && labId && labId !== 'all') {
            try {
                const { error } = await supabase
                    .from('verificacao_interna')
                    .upsert({
                        lab_id: labId,
                        date: state.date,
                        data_json: {
                            amostras: state.amostras,
                            analises: state.analises
                        },
                        updated_at: new Date().toISOString()
                    }, {
                        onConflict: 'lab_id,date'
                    });

                if (error) throw error;
            } catch (err) {
                console.error("Failed to save verification to Supabase:", err);
            }
        }

        // Always update local storage as well for immediate feedback and local persistence
        const storeKey = `fibertech_verificacao_${labId}`;
        localStorage.setItem(storeKey, JSON.stringify(state));
    },

    async get(labId: string, date: string): Promise<VerificacaoState | null> {
        if (isSupabaseEnabled() && labId && labId !== 'all') {
            try {
                const { data, error } = await supabase
                    .from('verificacao_interna')
                    .select('*')
                    .eq('lab_id', labId)
                    .eq('date', date)
                    .maybeSingle();

                if (error) throw error;

                if (data && data.data_json) {
                    const state = {
                        amostras: data.data_json.amostras || [],
                        analises: data.data_json.analises || [],
                        date: date
                    };

                    // Sincroniza o cache local com os dados frescos da nuvem
                    const storeKey = `fibertech_verificacao_${labId}`;
                    localStorage.setItem(storeKey, JSON.stringify(state));

                    return state;
                }
            } catch (err) {
                console.error("Failed to fetch verification from Supabase:", err);
            }
        }

        // Fallback Local se a nuvem falhar ou n├úo tiver dados
        const storeKey = `fibertech_verificacao_${labId}`;
        const stored = localStorage.getItem(storeKey);
        if (stored) {
            try {
                const parsed = JSON.parse(stored);
                if (parsed.date === date) return parsed;
            } catch (e) {
                console.warn("Error parsing local verification state:", e);
            }
        }

        return null;
    }
};
